  ('Association.SocialMediaType', 'en', 'Social Media Type', 'A list of types of websites or social media the association Uniform Resource Locator (URL) or ID is referring to (e.g., Website, Blog, Facebook, Twitter, LinkedIn, Instagram).', 'https://dd.reso.org/DD2.0/Association/SocialMediaType/', 'https://dd.reso.org/DD2.0/lookups/SocialMediaType/', '2.0', 'reso_official_csv'),
