  ('Caravan.CaravanOrganizerKey', 'en', 'Caravan Organizer Key', 'A system unique identifier for the entity hosting the tour. Specifically, in aggregation systems, the Key is the system unique identifier from the system that the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set.', 'https://dd.reso.org/DD2.0/Caravan/CaravanOrganizerKey/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.CaravanOrganizerMlsId', 'en', 'Caravan Organizer MLS ID', 'The local, well-known identifier for the entity hosting the tour. This value may not be unique, specifically in the case of aggregation systems, this value should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/Caravan/CaravanOrganizerMlsId/', NULL, '2.0', 'reso_official_csv'),
