  ('Caravan.OriginatingSystemId', 'en', 'Originating System ID', 'The RESO UOI''s OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the CaravanStop was inputted). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Caravan/OriginatingSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the CaravanStop was inputted). There may be cases where the source system (how you received the record) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/Caravan/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider. Most commonly the name of the MLS. The place where the CaravanStop was originally inputted. The legal name of the company.', 'https://dd.reso.org/DD2.0/Caravan/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.SourceSystemId', 'en', 'Source System ID', 'The RESO UOI''s OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Caravan/SourceSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Caravan/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Caravan.SourceSystemName', 'en', 'Source System Name', 'The name of the CaravanStop record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Caravan/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('CaravanStop.CaravanKey', 'en', 'Caravan Key', 'A system unique identifier. Specifically, a foreign key referencing the primary key of the Caravan Resource.', 'https://dd.reso.org/DD2.0/CaravanStop/CaravanKey/', NULL, '2.0', 'reso_official_csv'),
  ('CaravanStop.CaravanStopKey', 'en', 'Caravan Stop Key', 'A system unique identifier. Specifically, a foreign key referencing the primary key of the CaravanStop Resource.', 'https://dd.reso.org/DD2.0/CaravanStop/CaravanStopKey/', NULL, '2.0', 'reso_official_csv'),
