  ('CaravanStop.StopKey', 'en', 'Stop Key', 'The key of a caravan stop record. This is a foreign key to the CaravanStop Resource. Typical stops are represented by an open house or listing record''s key. A stop might also be another custom/local resource.', 'https://dd.reso.org/DD2.0/CaravanStop/StopKey/', NULL, '2.0', 'reso_official_csv'),
