  ('CaravanStop.StopShowingAgentMlsId', 'en', 'Stop Showing Agent MLS ID', 'The local, well-known identifier for the showing agent. This value may not be unique. Specifically, in the case of aggregation systems, this value should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/CaravanStop/StopShowingAgentMlsId/', NULL, '2.0', 'reso_official_csv'),
