  ('ContactListings.AgentNotesUnreadYN', 'en', 'Agent Notes Unread Yes/No', 'Indicates whether or not agent notes have gone unread. If yes, one or more of the agent notes are unread.', 'https://dd.reso.org/DD2.0/ContactListings/AgentNotesUnreadYN/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ClassName', 'en', 'Class Name', 'The name of the class where the listing record is located.', 'https://dd.reso.org/DD2.0/ContactListings/ClassName/', 'https://dd.reso.org/DD2.0/lookups/ClassName/', '2.0', 'reso_official_csv'),
  ('ContactListings.Contact', 'en', 'Contact', 'The contact for the ContactListings record.', 'https://dd.reso.org/DD2.0/ContactListings/Contact/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ContactKey', 'en', 'Contact Key', 'The foreign key relating to the Contacts Resource. A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see Source System Contact Key and Originating System Contact Key in the Contacts Resource.', 'https://dd.reso.org/DD2.0/ContactListings/ContactKey/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ContactListingPreference', 'en', 'Contact Listing Preference', 'The contact''s preference selection on the given listing (i.e., Favorite, Possibility or Discard).', 'https://dd.reso.org/DD2.0/ContactListings/ContactListingPreference/', 'https://dd.reso.org/DD2.0/lookups/ContactListingPreference/', '2.0', 'reso_official_csv'),
  ('ContactListings.ContactListingsKey', 'en', 'Contact Listings Key', 'A system unique identifier. Specifically, in aggregation systems, the key is the system unique identifier from the system that the record was just retrieved from. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set.', 'https://dd.reso.org/DD2.0/ContactListings/ContactListingsKey/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ContactLoginId', 'en', 'Contact Login ID', 'The foreign key referring to the Contacts Resource''s local, well-known identifier for the contact. This value may not be unique, specifically in the case of aggregation systems. This value should be the identifier from the original system and is used by the contact to log on to a client portal in that system.', 'https://dd.reso.org/DD2.0/ContactListings/ContactLoginId/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ContactNotesUnreadYN', 'en', 'Contact Notes Unread Yes/No', 'A flag indicating whether or not the contact''s notes are unread. This flag may be true/false, yes/no or another true, false or unknown indicator. As with all flags, the field may be null.', 'https://dd.reso.org/DD2.0/ContactListings/ContactNotesUnreadYN/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.DirectEmailYN', 'en', 'Direct Email Yes/No', 'A flag indicating whether or not this is a direct email. If true, the email was a direct email sent to the client by the member. If false, the email was an automated email.', 'https://dd.reso.org/DD2.0/ContactListings/DirectEmailYN/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.HistoryTransactional', 'en', 'History Transactional', 'The history of the ContactListings record.', 'https://dd.reso.org/DD2.0/ContactListings/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.LastAgentNoteTimestamp', 'en', 'Last Agent Note Timestamp', 'The date/time the member last added or updated a ListingNote.', 'https://dd.reso.org/DD2.0/ContactListings/LastAgentNoteTimestamp/', NULL, '2.0', 'reso_official_csv'),
