  ('ContactListings.Listing', 'en', 'Listing', 'The listing for the ContactListings record.', 'https://dd.reso.org/DD2.0/ContactListings/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ListingId', 'en', 'Listing ID', 'The well-known identifier for the listing. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/ContactListings/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('ContactListings.ListingKey', 'en', 'Listing Key', 'The foreign key related to the Property Resource''s unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/ContactListings/ListingKey/', NULL, '2.0', 'reso_official_csv'),
