  ('Contacts.OriginatingSystem', 'en', 'Originating System', 'The originating system of the contact''s record.', 'https://dd.reso.org/DD2.0/Contacts/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OriginatingSystemContactKey', 'en', 'Originating System Contact Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the contact was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/Contacts/OriginatingSystemContactKey/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OriginatingSystemID', 'en', 'Originating System ID', 'The OUID Resource''s OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the contact was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Contacts/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the contact is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/Contacts/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherAddress1', 'en', 'Other Address 1', 'The other street number, direction, name and suffix of the contact.', 'https://dd.reso.org/DD2.0/Contacts/OtherAddress1/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherAddress2', 'en', 'Other Address 2', 'The other unit/suite number of the contact.', 'https://dd.reso.org/DD2.0/Contacts/OtherAddress2/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherCarrierRoute', 'en', 'Other Carrier Route', 'The group of addresses to which the U.S. Postal Service (USPS) assigns the same code to aid in mail delivery. For the USPS, these codes are 9 digits: 5 numbers for the ZIP Code, one letter for the carrier route type and 3 numbers for the carrier route number.', 'https://dd.reso.org/DD2.0/Contacts/OtherCarrierRoute/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherCity', 'en', 'Other City', 'The other city of the contact.', 'https://dd.reso.org/DD2.0/Contacts/OtherCity/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherCountry', 'en', 'Other Country', 'The other country abbreviation in a postal address.', 'https://dd.reso.org/DD2.0/Contacts/OtherCountry/', 'https://dd.reso.org/DD2.0/lookups/Country/', '2.0', 'reso_official_csv'),
  ('Contacts.OtherCountyOrParish', 'en', 'Other County Or Parish', 'The other county or parish in which the contact is addressed.', 'https://dd.reso.org/DD2.0/Contacts/OtherCountyOrParish/', 'https://dd.reso.org/DD2.0/lookups/CountyOrParish/', '2.0', 'reso_official_csv'),
  ('Contacts.OtherPhoneType', 'en', 'Other Phone Type', 'A list of phone types (e.g., Home, Mobile, Second) that do not already exist in the given phone fields or if a second type of phone field is needed.', 'https://dd.reso.org/DD2.0/Contacts/OtherPhoneType/', 'https://dd.reso.org/DD2.0/lookups/OtherPhoneType/', '2.0', 'reso_official_csv'),
  ('Contacts.OtherPostalCode', 'en', 'Other Postal Code', 'The other postal code of the contact.', 'https://dd.reso.org/DD2.0/Contacts/OtherPostalCode/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherPostalCodePlus4', 'en', 'Other Postal Code Plus 4', 'The other four-digit extension of the U.S. Zip Code.', 'https://dd.reso.org/DD2.0/Contacts/OtherPostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OtherStateOrProvince', 'en', 'Other State Or Province', 'The other state or province in which the contact is addressed.', 'https://dd.reso.org/DD2.0/Contacts/OtherStateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('Contacts.OwnerMember', 'en', 'Owner Member', 'The member who owns the contact''s record.', 'https://dd.reso.org/DD2.0/Contacts/OwnerMember/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OwnerMemberID', 'en', 'Owner Member ID', 'The local, well-known identifier for the member in charge of the contact.', 'https://dd.reso.org/DD2.0/Contacts/OwnerMemberID/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.OwnerMemberKey', 'en', 'Owner Member Key', 'The unique identifier (key) of the member owning the contact. This is a foreign key relating to the Member resource''s MemberKey.', 'https://dd.reso.org/DD2.0/Contacts/OwnerMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.Pager', 'en', 'Pager', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Contacts/Pager/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.PhoneTTYTDD', 'en', 'Phone Tty/Tdd', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Contacts/PhoneTTYTDD/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.PreferredAddress', 'en', 'Preferred Address', 'A list of the address options (i.e., Home, Work and Other) used to determine the address preferred by the client.', 'https://dd.reso.org/DD2.0/Contacts/PreferredAddress/', 'https://dd.reso.org/DD2.0/lookups/PreferredAddress/', '2.0', 'reso_official_csv'),
  ('Contacts.PreferredPhone', 'en', 'Preferred Phone', 'A list of the phone options (e.g., Office, Mobile, Direct, Voicemail) used to determine the phone preferred by the client.', 'https://dd.reso.org/DD2.0/Contacts/PreferredPhone/', 'https://dd.reso.org/DD2.0/lookups/PreferredPhone/', '2.0', 'reso_official_csv'),
  ('Contacts.ReferredBy', 'en', 'Referred By', 'The name of the person who referred the contact.', 'https://dd.reso.org/DD2.0/Contacts/ReferredBy/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.ReverseProspectingEnabledYN', 'en', 'Reverse Prospecting Enabled Yes/No', 'Reverse prospecting, a system that allows listing agents to see the agent/member whose client has a search criteria that found the agent''s listing, has been enabled for the given client''s saved searches.', 'https://dd.reso.org/DD2.0/Contacts/ReverseProspectingEnabledYN/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.SocialMediaType', 'en', 'Social Media Type', 'A list of social media platforms (e.g., Facebook, LinkedIn, Instagram) associated with the ContactsSocialMedia field.', 'https://dd.reso.org/DD2.0/Contacts/SocialMediaType/', 'https://dd.reso.org/DD2.0/lookups/SocialMediaType/', '2.0', 'reso_official_csv'),
  ('Contacts.SourceSystem', 'en', 'Source System', 'The source system of the contact''s record.', 'https://dd.reso.org/DD2.0/Contacts/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.SourceSystemContactKey', 'en', 'Source System Contact Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Contacts/SourceSystemContactKey/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.SourceSystemID', 'en', 'Source System ID', 'The OUID Resource''s OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Contacts/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.SourceSystemName', 'en', 'Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Contacts/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.SpousePartnerName', 'en', 'Spouse Partner Name', 'The contact''s spouse or partner.', 'https://dd.reso.org/DD2.0/Contacts/SpousePartnerName/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.TollFreePhone', 'en', 'Toll Free Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Contacts/TollFreePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.VoiceMail', 'en', 'Voice Mail', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Contacts/VoiceMail/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.VoiceMailExt', 'en', 'Voice Mail Ext', 'The extension of the given phone number (if applicable).', 'https://dd.reso.org/DD2.0/Contacts/VoiceMailExt/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkAddress1', 'en', 'Work Address 1', 'The street number, direction, name and suffix of the contact''s work.', 'https://dd.reso.org/DD2.0/Contacts/WorkAddress1/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkAddress2', 'en', 'Work Address 2', 'The unit/suite number of the contact''s work.', 'https://dd.reso.org/DD2.0/Contacts/WorkAddress2/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkCarrierRoute', 'en', 'Work Carrier Route', 'The group of addresses to which the U.S. Postal Service (USPS) assigns the same code to aid in mail delivery. For the USPS, these codes are nine digits: five numbers for the ZIP Code, one letter for the carrier route type and three numbers for the carrier route number.', 'https://dd.reso.org/DD2.0/Contacts/WorkCarrierRoute/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkCity', 'en', 'Work City', 'The city of the contact''s work.', 'https://dd.reso.org/DD2.0/Contacts/WorkCity/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkCountry', 'en', 'Work Country', 'The country abbreviation in a postal address.', 'https://dd.reso.org/DD2.0/Contacts/WorkCountry/', 'https://dd.reso.org/DD2.0/lookups/Country/', '2.0', 'reso_official_csv'),
  ('Contacts.WorkCountyOrParish', 'en', 'Work County Or Parish', 'The county or parish in which the contact''s work is addressed.', 'https://dd.reso.org/DD2.0/Contacts/WorkCountyOrParish/', 'https://dd.reso.org/DD2.0/lookups/CountyOrParish/', '2.0', 'reso_official_csv'),
  ('Contacts.WorkPostalCode', 'en', 'Work Postal Code', 'The postal code of the contact''s work.', 'https://dd.reso.org/DD2.0/Contacts/WorkPostalCode/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkPostalCodePlus4', 'en', 'Work Postal Code Plus 4', 'The four-digit extension of a U.S. Zip Code.', 'https://dd.reso.org/DD2.0/Contacts/WorkPostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('Contacts.WorkStateOrProvince', 'en', 'Work State Or Province', 'The state or province in which the contact''s work is addressed.', 'https://dd.reso.org/DD2.0/Contacts/WorkStateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('EntityEvent.EntityEventSequence', 'en', 'Entity Event Sequence', 'A unique, system-wide ID that can be used to represent the sequence in which an EntityEvent occurred in a given system. This field serves as a logical timestamp, meaning that its values may be used to provide a total ordering of all events that occurred in the EntityEvent Resource. As event records are immutable, this value can grow fairly large over time; therefore, it''s represented by the Int64 data type. This sequence number is not expected to be unique across different organizations. This number must be a positive integer.', 'https://dd.reso.org/DD2.0/EntityEvent/EntityEventSequence/', NULL, '2.0', 'reso_official_csv'),
  ('EntityEvent.ResourceName', 'en', 'Resource Name', 'A unique name given to available resources in order to distinguish them within the producer''s system. In general, this would be something like "Property," "Member," or "Media" but could also be used to represent custom resources.', 'https://dd.reso.org/DD2.0/EntityEvent/ResourceName/', NULL, '2.0', 'reso_official_csv'),
  ('EntityEvent.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record or resource, such as ListingKey, OfficeKey or MemberKey, that allows the record to be uniquely identified as an entity so that it may be fetched from the producer''s system.', 'https://dd.reso.org/DD2.0/EntityEvent/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('EntityEvent.ResourceRecordUrl', 'en', 'Resource Record URL', 'A Uniform Resource Locator (URL) that specifies where consumers may retrieve data corresponding to the given event. As the amount of data available from the EntityEvent Resource is expected to grow rapidly, producers may choose to compute this value rather than storing it.', 'https://dd.reso.org/DD2.0/EntityEvent/ResourceRecordUrl/', NULL, '2.0', 'reso_official_csv'),
  ('Field.FieldKey', 'en', 'Field Key', 'The key used to uniquely identify the field.', 'https://dd.reso.org/DD2.0/Field/FieldKey/', NULL, '2.0', 'reso_official_csv'),
  ('Field.FieldName', 'en', 'Field Name', 'The name of the field as expressed in the payload. For OData APIs, this field MUST meet certain naming requirements and should be consistent with what’s advertised in the OData XML metadata (to be verified in certification). For example, "ListPrice."', 'https://dd.reso.org/DD2.0/Field/FieldName/', NULL, '2.0', 'reso_official_csv'),
  ('Field.ModificationTimestamp', 'en', 'Modification Timestamp', 'The timestamp when the field metadata item was last modified. This is used to help rebuild caches when metadata items change so consumers don''t have to re-pull and reprocess the entire set of metadata when only a small number of changes have been made.', 'https://dd.reso.org/DD2.0/Field/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Field.ResourceName', 'en', 'Resource Name', 'The name of the resource the field belongs to. This will be a RESO Standard Name, when applicable, but may also be a local resource name (e.g., "Property").', 'https://dd.reso.org/DD2.0/Field/ResourceName/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ChangeType', 'en', 'Change Type', 'A description of the last major change on the listing (i.e., Price Reduction, Back on Market, etc.). May be used to display on a summary view of listing results to quickly identify listings that have had major changes recently.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ChangeType/', 'https://dd.reso.org/DD2.0/lookups/ChangeType/', '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ChangedByMember', 'en', 'Changed By Member', 'The member who changed the historical item.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ChangedByMember/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ChangedByMemberID', 'en', 'Changed By Member ID', 'The local, well-know identifier of the member (user) who made the change.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ChangedByMemberID/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ChangedByMemberKey', 'en', 'Changed By Member Key', 'The unique identifier of the member (user) who made the change. This is a foreign key relating to the Member resource''s MemberKey.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ChangedByMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ClassName', 'en', 'Class Name', 'The name of the class in which this history record applies.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ClassName/', 'https://dd.reso.org/DD2.0/lookups/ClassName/', '2.0', 'reso_official_csv'),
  ('HistoryTransactional.EntityEventSequence', 'en', 'Entity Event Sequence', 'A unique, system-wide ID that can be used to represent the sequence in which an EntityEvent occurred in a given system. This field serves as a logical timestamp, meaning that its values may be used to provide a total ordering of all Events that occurred in the Events Resource. As Event records are immutable, this value can grow fairly large over time, and therefore it''s represented by the Int64 data type. This sequence number is not expected to be unique across different organizations. This number must be a positive integer.', 'https://dd.reso.org/DD2.0/HistoryTransactional/EntityEventSequence/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.FieldKey', 'en', 'Field Key', 'The unique identifier of the field with data being changed. This is a foreign key relating to the field found in the resource per the ResourceName field.', 'https://dd.reso.org/DD2.0/HistoryTransactional/FieldKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.FieldName', 'en', 'Field Name', 'The name of the field where data is being changed.', 'https://dd.reso.org/DD2.0/HistoryTransactional/FieldName/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.HistoryTransactionalKey', 'en', 'History Transactional Key', 'A unique identifier for this record from the immediate source. This may be a number or string that can include a Uniform Resource Identifier (URI) or other forms. This is the system being connected to and not necessarily the original source of the record.', 'https://dd.reso.org/DD2.0/HistoryTransactional/HistoryTransactionalKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ModificationTimestamp', 'en', 'Modification Timestamp', 'The timestamp of the last major change on the listing (see also MajorChangeType).', 'https://dd.reso.org/DD2.0/HistoryTransactional/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.NewValue', 'en', 'New Value', 'The new value applied to the named field.', 'https://dd.reso.org/DD2.0/HistoryTransactional/NewValue/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.OriginatingSystem', 'en', 'Originating System', 'The originating system of the HistoryTransactional record.', 'https://dd.reso.org/DD2.0/HistoryTransactional/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.OriginatingSystemHistoryKey', 'en', 'Originating System History Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the history was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System History Key for more information.', 'https://dd.reso.org/DD2.0/HistoryTransactional/OriginatingSystemHistoryKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.OriginatingSystemID', 'en', 'Originating System ID', 'The OUID Resource''s OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the history was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/HistoryTransactional/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the history is originally input. The legal name of the company.', 'https://dd.reso.org/DD2.0/HistoryTransactional/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.PreviousValue', 'en', 'Previous Value', 'The value found in the named field prior to the change represented by this record.', 'https://dd.reso.org/DD2.0/HistoryTransactional/PreviousValue/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ResourceName', 'en', 'Resource Name', 'The name of the resource in which this history record applies.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ResourceName/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ResourceRecordID', 'en', 'Resource Record ID', 'The well-known identifier of the related record from the source resource. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ResourceRecordID/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey). This is the system being connected to and not necessarily the original source of the record. This is a foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/HistoryTransactional/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.SourceSystem', 'en', 'Source System', 'The source system of the HistoryTransactional record.', 'https://dd.reso.org/DD2.0/HistoryTransactional/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.SourceSystemHistoryKey', 'en', 'Source System History Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/HistoryTransactional/SourceSystemHistoryKey/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.SourceSystemID', 'en', 'Source System ID', 'The OUID Resource''s OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/HistoryTransactional/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('HistoryTransactional.SourceSystemName', 'en', 'Source System Name', 'The name of the historical record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/HistoryTransactional/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorCity', 'en', 'Actor City', 'The city location of the actor as recorded by the source.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorCity/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorEmail', 'en', 'Actor Email', 'The email address of the actor in this event.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorEmail/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorID', 'en', 'Actor ID', 'The local, well-known identifier the actor, provided by the source when applicable. This value may not be unique, specifically in the case of aggregation systems. This value should be the human-friendly identifier from the original system. Use of the ID may be common when the actor is an MLS or other software user. Otherwise, use of ActorKey is recommended.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorIP', 'en', 'Actor IP', 'The recorded IP address of the actor in this event. IPv4 addresses are 15 characters and IPv6 addresses are a max of 39 characters. IP addresses should not omit leading zeros (i.e., 10.1.1.1 should appear as 010.001.001.001).', 'https://dd.reso.org/DD2.0/InternetTracking/ActorIP/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorKey', 'en', 'Actor Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, utilize SourceSystemActorKey and/or OriginatingSystemActorKey.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorKey/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorLatitude', 'en', 'Actor Latitude', 'The geographic latitude of some reference point for the location of the actor, specified in degrees and decimal parts. Positive numbers must not include the plus symbol.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorLatitude/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorLongitude', 'en', 'Actor Longitude', 'The geographic longitude of some reference point for the location of the actor, specified in degrees and decimal parts. Positive numbers must not include the plus symbol.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorLongitude/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorOriginatingSystem', 'en', 'Actor Originating System', 'The originating system of the Actor record.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorOriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorOriginatingSystemID', 'en', 'Actor Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorOriginatingSystemName', 'en', 'Actor Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorPhone', 'en', 'Actor Phone', 'The phone number of the actor in this event.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorPhone/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorPhoneExt', 'en', 'Actor Phone Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorPhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorPostalCode', 'en', 'Actor Postal Code', 'The postal code of the actor.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorPostalCode/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorPostalCodePlus4', 'en', 'Actor Postal Code Plus4', 'The four-digit extension of the U.S. Zip Code.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorPostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorRegion', 'en', 'Actor Region', 'A geographical region defined by the source. For this use, the region is not specifically at the city, county, state, country or continent level, and this is typical in Internet tracking standards.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorRegion/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorSourceSystem', 'en', 'Actor Source System', 'The source system of the Actor record.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorSourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorSourceSystemID', 'en', 'Actor Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorSourceSystemName', 'en', 'Actor Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorStateOrProvince', 'en', 'Actor State Or Province', 'The state or province location of the actor as recorded by the source.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorStateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('InternetTracking.ActorType', 'en', 'Actor Type', 'A list of actor types; where the event originated from (e.g., Agent, Bot, Consumer). In implementation, this is typically a required field.', 'https://dd.reso.org/DD2.0/InternetTracking/ActorType/', 'https://dd.reso.org/DD2.0/lookups/ActorType/', '2.0', 'reso_official_csv'),
  ('InternetTracking.ColorDepth', 'en', 'Color Depth', 'The color depth of the actor''s device display.', 'https://dd.reso.org/DD2.0/InternetTracking/ColorDepth/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.DeviceType', 'en', 'Device Type', 'The device type used by the actor (e.g., Mobile, Desktop) in this event.', 'https://dd.reso.org/DD2.0/InternetTracking/DeviceType/', 'https://dd.reso.org/DD2.0/lookups/DeviceType/', '2.0', 'reso_official_csv'),
  ('InternetTracking.EventDescription', 'en', 'Event Description', 'A description of the event being tracked (e.g., "The listing was viewed.").', 'https://dd.reso.org/DD2.0/InternetTracking/EventDescription/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventKey', 'en', 'Event Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, utilize SourceSystemEventKey and/or OriginatingSystemEventKey.', 'https://dd.reso.org/DD2.0/InternetTracking/EventKey/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventLabel', 'en', 'Event Label', 'A short description of the event being tracked.', 'https://dd.reso.org/DD2.0/InternetTracking/EventLabel/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventOriginatingSystem', 'en', 'Event Originating System', 'The originating system of the InternetTracking event.', 'https://dd.reso.org/DD2.0/InternetTracking/EventOriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventOriginatingSystemID', 'en', 'Event Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/EventOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventOriginatingSystemName', 'en', 'Event Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/EventOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventReportedTimestamp', 'en', 'Event Reported Timestamp', 'Date/time of when the event was recorded. This may differ from the EventTimestamp.', 'https://dd.reso.org/DD2.0/InternetTracking/EventReportedTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventSource', 'en', 'Event Source', 'Conveys the source of the EventType. For example, "Map" is the EventSource of an object that has an impression on a map display.', 'https://dd.reso.org/DD2.0/InternetTracking/EventSource/', 'https://dd.reso.org/DD2.0/lookups/EventSource/', '2.0', 'reso_official_csv'),
