  ('InternetTracking.EventSourceSystemID', 'en', 'Event Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/EventSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventSourceSystemName', 'en', 'Event Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/EventSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventTarget', 'en', 'Event Target', 'A defined target of the event type.', 'https://dd.reso.org/DD2.0/InternetTracking/EventTarget/', 'https://dd.reso.org/DD2.0/lookups/EventTarget/', '2.0', 'reso_official_csv'),
  ('InternetTracking.EventTimestamp', 'en', 'Event Timestamp', 'A Coordinated Universal Time (UTC) timestamp of when the event being tracked occurred. In implementation, this is typically a required field.', 'https://dd.reso.org/DD2.0/InternetTracking/EventTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.EventType', 'en', 'Event Type', 'The type of event being tracked. In implementation, this is typically a required a field.', 'https://dd.reso.org/DD2.0/InternetTracking/EventType/', 'https://dd.reso.org/DD2.0/lookups/EventType/', '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectID', 'en', 'Object ID', 'An ID pertaining to the ObjectType (i.e., the MLS listing ID for ObjectType.Listing).', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectIdType', 'en', 'Object ID Type', 'A label that better defines the data in the ObjectID field (i.e., ObjectID is an MLS listing ID or ObjectID is a unique ID from the source).', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectIdType/', 'https://dd.reso.org/DD2.0/lookups/ObjectIdType/', '2.0', 'reso_official_csv'),
