  ('InternetTracking.ObjectOriginatingSystemID', 'en', 'Object Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectOriginatingSystemName', 'en', 'Object Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectSourceSystem', 'en', 'Object Source System', 'The source system of the InternetTracking object.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectSourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectSourceSystemID', 'en', 'Object Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectSourceSystemName', 'en', 'Object Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectType', 'en', 'Object Type', 'The type of object being tracked in this event. In implementation, this is typically a required field.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectType/', 'https://dd.reso.org/DD2.0/lookups/ObjectType/', '2.0', 'reso_official_csv'),
  ('InternetTracking.ObjectURL', 'en', 'Object URL', 'The Uniform Resource Locator (URL) of the tracked event.', 'https://dd.reso.org/DD2.0/InternetTracking/ObjectURL/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.OriginatingSystemActorKey', 'en', 'Originating System Actor Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the member was input). There may be cases where the source system (how the record is received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/InternetTracking/OriginatingSystemActorKey/', NULL, '2.0', 'reso_official_csv'),
  ('InternetTracking.OriginatingSystemEventKey', 'en', 'Originating System Event Key', 'The system key, a unique record identifier, from the originating system, which is the system with authoritative control over the record (e.g., the MLS where the member was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/InternetTracking/OriginatingSystemEventKey/', NULL, '2.0', 'reso_official_csv'),
