  ('InternetTrackingSummary.TrackingType', 'en', 'Tracking Type', 'Defines the type of tracking data being sought (e.g., Office, Agent), a single listing itself or the entire data set from a Unique Organization Identifier (UOI).', 'https://dd.reso.org/DD2.0/InternetTrackingSummary/TrackingType/', 'https://dd.reso.org/DD2.0/lookups/TrackingType/', '2.0', 'reso_official_csv'),
