  ('LockOrBox.ListingCity', 'en', 'Listing City', 'The city of the property where the lockbox/smart lock is located.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingCity/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ListingCountry', 'en', 'Listing Country', 'The country of the property where the lockbox/smart lock is located.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingCountry/', 'https://dd.reso.org/DD2.0/lookups/Country/', '2.0', 'reso_official_csv'),
  ('LockOrBox.ListingId', 'en', 'Listing ID', 'The well-known identifier for the listing where the lockbox/smart lock is located. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ListingKey', 'en', 'Listing Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemLockOrBoxKey and OriginatingSystemLockOrBoxKey.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingKey/', NULL, '2.0', 'reso_official_csv'),
