  ('LockOrBox.ListingPostalCodePlus4', 'en', 'Listing Postal Code Plus 4', 'The four-digit U.S. ZIP Code extension of the property where the lockbox/smart lock is located.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingPostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ListingStateOrProvince', 'en', 'Listing State or Province', 'The state or province of the property where the lockbox/smart lock is located.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingStateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('LockOrBox.ListingTimeZone', 'en', 'Listing Time Zone', 'The standard name of the time zone of the property where the lockbox/smart lock is located, as provided by the IANA tz database.', 'https://dd.reso.org/DD2.0/LockOrBox/ListingTimeZone/', 'https://dd.reso.org/DD2.0/lookups/IanaTimeZoneValues/', '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxAccessTimestamp', 'en', 'Lock or Box Access Timestamp', 'The transactional timestamp automatically recorded by the lockbox/smart lock system representing the date/time the lockbox or lock was last accessed.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxAccessTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxAccessType', 'en', 'Lock or Box Access Type', 'The method of access for the lockbox or smart lock.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxAccessType/', 'https://dd.reso.org/DD2.0/lookups/LockOrBoxAccessType/', '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxId', 'en', 'Lock or Box ID', 'The local, well-known identifier for a given lockbox/smartlock system. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxInstalledTimestamp', 'en', 'Lock or Box Installed Timestamp', 'The transactional timestamp automatically recorded by the lockbox/smart lock system representing the date/time the lockbox or lock was last installed at a property.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxInstalledTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxKey', 'en', 'Lock or Box Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxKey/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxOriginatingSystemId', 'en', 'Lock or Box Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxOriginatingSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxOriginatingSystemKey', 'en', 'Lock or Box Originating System Key', 'The name of the originating record provider. Most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxOriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxOriginatingSystemName', 'en', 'Lock or Box Originating System Name', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record. For example, the Multiple Listing Service where the listing was input. There may be cases where the Source System (how you received the record) is not the Originating System. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxSourceSystemId', 'en', 'Lock or Box Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxSourceSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxSourceSystemKey', 'en', 'Lock or Box Source System Key', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxSourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.LockOrBoxSourceSystemName', 'en', 'Lock or Box Source System Name', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/LockOrBox/LockOrBoxSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the LockOrBox record was last modified.', 'https://dd.reso.org/DD2.0/LockOrBox/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.Notes', 'en', 'Notes', 'Notes or feedback about the property or showing.', 'https://dd.reso.org/DD2.0/LockOrBox/Notes/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.OriginatingSystem', 'en', 'Originating System', 'The originating system of the LockOrBox record.', 'https://dd.reso.org/DD2.0/LockOrBox/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgent', 'en', 'Showing Agent', 'The office contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgent/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentAOR', 'en', 'Showing Agent AOR', 'The showing contact''s board or association of REALTORS®.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentAOR/', 'https://dd.reso.org/DD2.0/lookups/AOR/', '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentEmail', 'en', 'Showing Agent Email', 'The email address of the contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentEmail/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentFirstName', 'en', 'Showing Agent First Name', 'The first name of the contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentFirstName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentFullName', 'en', 'Showing Agent Full Name', 'The first, middle and last name of the contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentFullName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentId', 'en', 'Showing Agent ID', 'The local, well-known lockbox/smartlock system identifier of the showing contact. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentLastName', 'en', 'Showing Agent Last Name', 'The last name of the contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentLastName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentMlsId', 'en', 'Showing Agent MLS ID', 'The local, well-known MLS identifier of the showing contact. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentPhone', 'en', 'Showing Agent Phone', 'The North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentPhone/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingAgentPhoneExt', 'en', 'Showing Agent Phone Extension', 'The phone number extension of the contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingAgentPhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingOffice', 'en', 'Showing Office', 'The agent contact for showings of the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingOffice/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingOfficeId', 'en', 'Showing Office ID', 'The local, well-known lockbox/smart lock system identifier of the showing office. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingOfficeId/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingOfficeName', 'en', 'Showing Office Name', 'The legal name of the brokerage/company showing the property.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingOfficeName/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.ShowingOfficePhone', 'en', 'Showing Office Phone', 'The North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/LockOrBox/ShowingOfficePhone/', NULL, '2.0', 'reso_official_csv'),
  ('LockOrBox.SourceSystem', 'en', 'Source System', 'The source system of the LockOrBox record.', 'https://dd.reso.org/DD2.0/LockOrBox/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.LegacyODataValue', 'en', 'Legacy OData Value', 'The name of the resource the field belongs to. This will be a RESO Standard Name, such as "Property", but may also be a non-standard local resource name.', 'https://dd.reso.org/DD2.0/Lookup/LegacyODataValue/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.LookupKey', 'en', 'Lookup Key', 'The key used to uniquely identify the lookup entry.', 'https://dd.reso.org/DD2.0/Lookup/LookupKey/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.LookupName', 'en', 'Lookup Name', 'The name of the enumeration. This is the LookupField in the adopted Data Dictionary spreadsheet. It is called a "LookupName" in this proposal because more than one field can have a given lookup, so it refers to the name of the lookup rather than a given field. For example, Listing with CountyOrParish and Office with OfficeCountyOrParish having the same CountyOrParish LookupName. This MUST match the Data Dictionary definition for in cases where the lookup is defined. Vendors MAY add their own enumerations otherwise. The LookupName a given field uses is required to be annotated at the field level in the OData XML Metadata, as outlined later in this proposal.', 'https://dd.reso.org/DD2.0/Lookup/LookupName/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.LookupValue', 'en', 'Lookup Value', 'The human-friendly display name the data consumer receives in the payload and uses in queries. This may be a local name or synonym for a given RESO Data Dictionary lookup item.', 'https://dd.reso.org/DD2.0/Lookup/LookupValue/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.ModificationTimestamp', 'en', 'Modification Timestamp', 'The timestamp for when the enumeration value was last modified. This is used to help rebuild caches when metadata items change so consumers don''t have to re-pull and reprocess the entire set of metadata when only a small number of changes have been made.', 'https://dd.reso.org/DD2.0/Lookup/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Lookup.StandardLookupValue', 'en', 'Lookup Display Name', 'The Data Dictionary LookupDisplayName of the enumerated value. This field is required when the LookupValue for a given item corresponds to a RESO standard value, meaning a standard lookup display name, known synonym, local name or translation of that value. Local lookups may omit this value if they don''t correspond to an existing RESO standard lookup value.', 'https://dd.reso.org/DD2.0/Lookup/StandardLookupValue/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ChangedByMember', 'en', 'Changed By Member', 'The member who changed the Media record.', 'https://dd.reso.org/DD2.0/Media/ChangedByMember/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ChangedByMemberID', 'en', 'Changed By Member ID', 'The ID of the user, agent, member, etc., that uploaded the media this record refers to.', 'https://dd.reso.org/DD2.0/Media/ChangedByMemberID/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ChangedByMemberKey', 'en', 'Changed By Member Key', 'The primary key of the member who uploaded the media this record refers to. This is a foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/Media/ChangedByMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ClassName', 'en', 'Class Name', 'The class or table of the listing or other record of the media (e.g., Residential, Lease, Agent, Office, Contact).', 'https://dd.reso.org/DD2.0/Media/ClassName/', 'https://dd.reso.org/DD2.0/lookups/ClassName/', '2.0', 'reso_official_csv'),
  ('Media.HistoryTransactional', 'en', 'History Transactional', 'The history of the Media record.', 'https://dd.reso.org/DD2.0/Media/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ImageHeight', 'en', 'Image Height', 'The height of the image expressed in pixels.', 'https://dd.reso.org/DD2.0/Media/ImageHeight/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ImageOf', 'en', 'Image Of', 'When the media is an image, a list of possible matches such as kitchen, bathroom, front of structure, etc. This field may be used to identify a required image under association or MLS rules.', 'https://dd.reso.org/DD2.0/Media/ImageOf/', 'https://dd.reso.org/DD2.0/lookups/ImageOf/', '2.0', 'reso_official_csv'),
  ('Media.ImageSizeDescription', 'en', 'Image Size Description', 'A text description of the size of the image (i.e., Small, Thumbnail, Medium, Large, X-Large). The largest image must be described as "Largest," and the thumbnail must also be included. A pick list will remain open/extendable.', 'https://dd.reso.org/DD2.0/Media/ImageSizeDescription/', 'https://dd.reso.org/DD2.0/lookups/ImageSizeDescription/', '2.0', 'reso_official_csv'),
  ('Media.ImageWidth', 'en', 'Image Width', 'The width of the image expressed in pixels.', 'https://dd.reso.org/DD2.0/Media/ImageWidth/', NULL, '2.0', 'reso_official_csv'),
  ('Media.LongDescription', 'en', 'Long Description', 'The full robust description of the object.', 'https://dd.reso.org/DD2.0/Media/LongDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Media.MediaAlteration', 'en', 'Media Alteration', 'Photos may be enhanced, altered or even created by manual or computer drafting. This list of lookup values is used to identify when any such alteration or fabrication of the photo has occurred. It is recommended that you check with your local laws and policies on the allowed alterations.', 'https://dd.reso.org/DD2.0/Media/MediaAlteration/', 'https://dd.reso.org/DD2.0/lookups/MediaAlteration/', '2.0', 'reso_official_csv'),
  ('Media.MediaCategory', 'en', 'Media Category', 'A category describing photos, documents, videos, unbranded virtual tours, branded virtual tours, floor plans, logos and other forms of media.', 'https://dd.reso.org/DD2.0/Media/MediaCategory/', 'https://dd.reso.org/DD2.0/lookups/MediaCategory/', '2.0', 'reso_official_csv'),
  ('Media.MediaHTML', 'en', 'Media HTML', 'The JavaScript or other method to embed a video, image, virtual tour or other media.', 'https://dd.reso.org/DD2.0/Media/MediaHTML/', NULL, '2.0', 'reso_official_csv'),
  ('Media.MediaKey', 'en', 'Media Key', 'A unique identifier for this record from the immediate source. This may be a number or a string that can include a Uniform Resource Identifier (URI) or other forms. This is the system you are connecting to and not necessarily the original source of the record.', 'https://dd.reso.org/DD2.0/Media/MediaKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.MediaModificationTimestamp', 'en', 'Media Modification Timestamp', 'A timestamp that is updated when a change to the object has been made, which may differ from a change to the Media Resource.', 'https://dd.reso.org/DD2.0/Media/MediaModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Media.MediaObjectID', 'en', 'Media Object ID', 'The ID of the image, supplement or other object specified by the given media record.', 'https://dd.reso.org/DD2.0/Media/MediaObjectID/', NULL, '2.0', 'reso_official_csv'),
  ('Media.MediaStatus', 'en', 'Media Status', 'The status of the media item referenced by this record (i.e., updated, deleted, etc.).', 'https://dd.reso.org/DD2.0/Media/MediaStatus/', 'https://dd.reso.org/DD2.0/lookups/MediaStatus/', '2.0', 'reso_official_csv'),
  ('Media.MediaType', 'en', 'Media Type', 'Media types as defined by the Internet Assigned Numbers Authority (IANA), http://www.iana.org/assignments/media-types/index.html. Note that the former name of MimeType, used by both IANA and RESO, may still be in use by some systems/entities.', 'https://dd.reso.org/DD2.0/Media/MediaType/', 'https://dd.reso.org/DD2.0/lookups/MediaType/', '2.0', 'reso_official_csv'),
  ('Media.MediaURL', 'en', 'Media URL', 'The Uniform Resource Identifier (URI) to the media file referenced by this record.', 'https://dd.reso.org/DD2.0/Media/MediaURL/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the Media record was last modified.', 'https://dd.reso.org/DD2.0/Media/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Media.Order', 'en', 'Order', 'Only a positive integer, including zero. Element zero is the primary photo per RESO convention.', 'https://dd.reso.org/DD2.0/Media/Order/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystem', 'en', 'Originating System', 'The originating system of the Media record.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier''s OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the media was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemMediaKey', 'en', 'Originating System Media Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the media was input). There may be cases where the source system (how the record is received) is not the originating system. See Source System Media Key for more information.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemMediaKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the media is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemResourceRecordId', 'en', 'Originating System Resource Record ID', 'The originating system''s well-known identifier of the related record from the source resource. The value may be identical to that of the key, but the ID is intended to be the value used by a human to retrieve the information about a specific listing. With multiple originating systems or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value. This most commonly would be the ListingId as it exists in the originating system.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemResourceRecordId/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemResourceRecordKey', 'en', 'Originating System Resource Record Key', 'The originating system''s primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey, TeamKey). The ResourceName identifies the resource being referenced. OriginatingSystemName or OriginatingSystemId are used to identify the originating system.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.OriginatingSystemResourceRecordSystemId', 'en', 'Originating System Resource Record System ID', 'The system ID of the resource record from the originating system is used when the resource record is originated from a different system than the media. This is the system ID of the OriginatingSystemResourceRecordID and/or the OriginatingSystemResourceRecordKey when they are from a different system than the OriginatingSystemID and/or OriginatingSystemName.', 'https://dd.reso.org/DD2.0/Media/OriginatingSystemResourceRecordSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('Media.Permission', 'en', 'Permission', 'The permission-level of the media (i.e., Public, Private, IDX, VOW, Office Only, Firm Only, Agent Only).', 'https://dd.reso.org/DD2.0/Media/Permission/', 'https://dd.reso.org/DD2.0/lookups/Permission/', '2.0', 'reso_official_csv'),
  ('Media.PreferredPhotoYN', 'en', 'Preferred Photo Yes/No', 'A flag indicating whether or not the media record in question is the preferred photo. This will typically mean the photo shown when only one of the photos is displayed. This flag may be true/false, yes/no or another true, false or unknown indicator. As with all flags, the field may be null.', 'https://dd.reso.org/DD2.0/Media/PreferredPhotoYN/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ResourceName', 'en', 'Resource Name', 'The resource or table of the listing or other record the media relates to (i.e., Property, Member, Office, etc.).', 'https://dd.reso.org/DD2.0/Media/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('Media.ResourceRecordID', 'en', 'Resource Record ID', 'The well-known identifier of the related record from the source resource. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/Media/ResourceRecordID/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey, TeamKey). This is the system being connected to and not necessarily the original source of the record. This is a foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/Media/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.ShortDescription', 'en', 'Short Description', 'The short text given to summarize the object, commonly used as the short description displayed under a photo.', 'https://dd.reso.org/DD2.0/Media/ShortDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystem', 'en', 'Source System', 'The source system of the Media record.', 'https://dd.reso.org/DD2.0/Media/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemID', 'en', 'Source System ID', 'The OUID Resource''s OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Media/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemMediaKey', 'en', 'Source System Media Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Media/SourceSystemMediaKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemName', 'en', 'Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Media/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemResourceRecordId', 'en', 'Source System Resource Record ID', 'The source system''s well-known identifier of the related record from the source resource. The value may be identical to that of the key, but the ID is intended to be the value used by a human to retrieve the information about a specific listing. With multiple originating systems or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value. This most commonly would be the ListingId as it exists in the source system.', 'https://dd.reso.org/DD2.0/Media/SourceSystemResourceRecordId/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemResourceRecordKey', 'en', 'Source System Resource Record Key', 'The source system''s primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey, TeamKey). The ResourceName identifies the resource being referenced. SourceSystemName or SourceSystemId are used to identify the originating system.', 'https://dd.reso.org/DD2.0/Media/SourceSystemResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('Media.SourceSystemResourceRecordSystemId', 'en', 'Source System Resource Record System ID', 'The system ID of the resource record from the source system is used when the resource record is sourced from a different system than the media. This is the system ID of the SourceSystemResourceRecordID and/or the SourceSystemResourceRecordKey when they are from a different system than the SourceSystemID and/or SourceSystemName.', 'https://dd.reso.org/DD2.0/Media/SourceSystemResourceRecordSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('Member.HistoryTransactional', 'en', 'History Transactional', 'The history of the Member record.', 'https://dd.reso.org/DD2.0/Member/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('Member.JobTitle', 'en', 'Job Title', 'The title or position of the member within their organization.', 'https://dd.reso.org/DD2.0/Member/JobTitle/', NULL, '2.0', 'reso_official_csv'),
  ('Member.LastLoginTimestamp', 'en', 'Last Login Timestamp', 'The date/time the member last logged into the source or other system.', 'https://dd.reso.org/DD2.0/Member/LastLoginTimestamp/', NULL, '2.0', 'reso_official_csv'),
