  ('MemberAssociation.MemberAssociationPrimaryIndicator', 'en', 'Member Association Primary Indicator', 'An indicator showing whether the member''s association membership status is primary, secondary, or not applicable (i.e., P, S, X).', 'https://dd.reso.org/DD2.0/MemberAssociation/MemberAssociationPrimaryIndicator/', NULL, '2.0', 'reso_official_csv'),
