  ('MemberAssociation.MemberMlsId', 'en', 'Member MLS ID', 'The local, well-known identifier for the member. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/MemberAssociation/MemberMlsId/', NULL, '2.0', 'reso_official_csv'),
