  ('MemberAssociation.SourceSystemId', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/MemberAssociation/SourceSystemId/', NULL, '2.0', 'reso_official_csv'),
  ('MemberAssociation.SourceSystemMemberKey', 'en', 'Source System Member Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/MemberAssociation/SourceSystemMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('MemberAssociation.SourceSystemName', 'en', 'Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/MemberAssociation/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
