  ('OUID.OrganizationMlsVendorOuid', 'en', 'Organization MLS Vendor OUID', 'If the organization uses an MLS system, this is that vendor''s Unique Organization Identifier (UOI).', 'https://dd.reso.org/DD2.0/OUID/OrganizationMlsVendorOuid/', NULL, '2.0', 'reso_official_csv'),
  ('OUID.OrganizationName', 'en', 'Organization Name', 'The textual name of the organization represented by a given Unique Organization Identifier (UOI) record.', 'https://dd.reso.org/DD2.0/OUID/OrganizationName/', NULL, '2.0', 'reso_official_csv'),
