  ('OUID.OrganizationSocialMedia', 'en', 'Organization Social Media', 'A collection of the types of social media fields available for this organization. The collection includes the type of system and other details pertinent about social media', 'https://dd.reso.org/DD2.0/OUID/OrganizationSocialMedia/', NULL, '2.0', 'reso_official_csv'),
