  ('OUID.OrganizationStatus', 'en', 'Organization Status', 'Determines whether or not if the organization is active or inactive. Active organizations are marked by a 1 and inactive organizations are marked by a 0. This field is not nullable.', 'https://dd.reso.org/DD2.0/OUID/OrganizationStatus/', NULL, '2.0', 'reso_official_csv'),
