  ('OfficeCorporateLicense.OfficeKey', 'en', 'Office Key', 'A system unique identifier. Specifically, in aggregation systems, the Key is the system unique identifier from the system that the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set. This is a foreign key relating to the Office resource''s OfficeKey.', 'https://dd.reso.org/DD2.0/OfficeCorporateLicense/OfficeKey/', NULL, '2.0', 'reso_official_csv'),
  ('OfficeCorporateLicense.OfficeMlsId', 'en', 'Office MLS ID', 'The local, well-known identifier. This value may not be unique, specifically in the case of aggregation systems, this value should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/OfficeCorporateLicense/OfficeMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.AppointmentRequiredYN', 'en', 'Appointment Required Yes/No', 'Indicates whether or not the open house requires an appointment.', 'https://dd.reso.org/DD2.0/OpenHouse/AppointmentRequiredYN/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.HistoryTransactional', 'en', 'History Transactional', 'The history of the OpenHouse record.', 'https://dd.reso.org/DD2.0/OpenHouse/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.Listing', 'en', 'Listing', 'The listing associated with the open house.', 'https://dd.reso.org/DD2.0/OpenHouse/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ListingId', 'en', 'Listing ID', 'The well-known identifier for the listing related to this open house. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/OpenHouse/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ListingKey', 'en', 'Listing Key', 'A unique identifier for the listing record related to this open house. This may be a number or string that can include a Uniform Resource Identifier (URI) or other forms. This is the system being connected to and not necessarily the original source of the record. This may be a foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/OpenHouse/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.LivestreamOpenHouseURL', 'en', 'Livestream Open House URL', 'A link to an open house livestream event.', 'https://dd.reso.org/DD2.0/OpenHouse/LivestreamOpenHouseURL/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.Media', 'en', 'Media', 'The media related to the OpenHouse record.', 'https://dd.reso.org/DD2.0/OpenHouse/Media/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the OpenHouse record was last modified.', 'https://dd.reso.org/DD2.0/OpenHouse/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseAttendedBy', 'en', 'Open House Attended By', 'States whether or not the open house will be attended by a licensed agent (i.e., Agent, Seller, Unattended).', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseAttendedBy/', 'https://dd.reso.org/DD2.0/lookups/Attended/', '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseDate', 'en', 'Open House Date', 'The date on which the open house will occur.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseDate/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseEndTime', 'en', 'Open House End Time', 'The time the open house ends.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseEndTime/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseId', 'en', 'Open House ID', 'The well-known identifier for the OpenHouse Resource. The value may be identical to that of OpenHouseKey, but OpenHouseId is intended to be the value used by a human to retrieve the information about a specific open house. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseId/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseKey', 'en', 'Open House Key', 'A unique identifier for this record from the immediate source. This may be a number or string that can include a Uniform Resource Identifier (URI) or other forms. This is the system you are connecting to and not necessarily the original source of the record.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseKey/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseRemarks', 'en', 'Open House Remarks', 'Comments, instructions or information about the open house.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseRemarks/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseStartTime', 'en', 'Open House Start Time', 'The time the open house begins.', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseStartTime/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseStatus', 'en', 'Open House Status', 'Status of the open house (i.e., Active, Canceled, Ended).', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseStatus/', 'https://dd.reso.org/DD2.0/lookups/OpenHouseStatus/', '2.0', 'reso_official_csv'),
  ('OpenHouse.OpenHouseType', 'en', 'Open House Type', 'The type of open house (i.e., Public, Broker, Office, Association, Private (invitation or targeted publication)).', 'https://dd.reso.org/DD2.0/OpenHouse/OpenHouseType/', 'https://dd.reso.org/DD2.0/lookups/OpenHouseType/', '2.0', 'reso_official_csv'),
  ('OpenHouse.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the open house was entered and made visible to members of the MLS.', 'https://dd.reso.org/DD2.0/OpenHouse/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OriginatingSystem', 'en', 'Originating System', 'The originating system of the OpenHouse record.', 'https://dd.reso.org/DD2.0/OpenHouse/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the open house was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/OpenHouse/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the open house was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/OpenHouse/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the open house is originally input. The legal name of the company.', 'https://dd.reso.org/DD2.0/OpenHouse/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.Refreshments', 'en', 'Refreshments', 'A description of the refreshments that will be served at the open house.', 'https://dd.reso.org/DD2.0/OpenHouse/Refreshments/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ShowingAgent', 'en', 'Showing Agent', 'The member record of the showing agent.', 'https://dd.reso.org/DD2.0/OpenHouse/ShowingAgent/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ShowingAgentFirstName', 'en', 'Showing Agent First Name', 'The first name of the showing agent.', 'https://dd.reso.org/DD2.0/OpenHouse/ShowingAgentFirstName/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ShowingAgentKey', 'en', 'Showing Agent Key', 'A system unique identifier. Specifically, in aggregation systems, the ListAgentKey is the system unique identifier from the system where the record was retrieved. This may be identical to the related xxxId. This is a foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/OpenHouse/ShowingAgentKey/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ShowingAgentLastName', 'en', 'Showing Agent Last Name', 'The last name of the showing agent.', 'https://dd.reso.org/DD2.0/OpenHouse/ShowingAgentLastName/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.ShowingAgentMlsID', 'en', 'Showing Agent MLS ID', 'The local, well-known identifier for the member. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/OpenHouse/ShowingAgentMlsID/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.SocialMedia', 'en', 'Social Media', 'The social media related to the OpenHouse record.', 'https://dd.reso.org/DD2.0/OpenHouse/SocialMedia/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.SourceSystem', 'en', 'Source System', 'The source system of the OpenHouse record.', 'https://dd.reso.org/DD2.0/OpenHouse/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/OpenHouse/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/OpenHouse/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('OpenHouse.SourceSystemName', 'en', 'Source System Name', 'The name of the open house record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/OpenHouse/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.ClassName', 'en', 'Class Name', 'Name of the class to which the record is referencing.', 'https://dd.reso.org/DD2.0/OtherPhone/ClassName/', 'https://dd.reso.org/DD2.0/lookups/ClassName/', '2.0', 'reso_official_csv'),
  ('OtherPhone.HistoryTransactional', 'en', 'History Transactional', 'The history of the OtherPhone record.', 'https://dd.reso.org/DD2.0/OtherPhone/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the OtherPhone record was last modified.', 'https://dd.reso.org/DD2.0/OtherPhone/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.OtherPhoneExt', 'en', 'Other Phone Ext', 'The extension of the given phone number (if applicable).', 'https://dd.reso.org/DD2.0/OtherPhone/OtherPhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.OtherPhoneKey', 'en', 'Other Phone Key', 'A system unique identifier. Specifically, in aggregation systems, the key is the system unique identifier from the system that the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set.', 'https://dd.reso.org/DD2.0/OtherPhone/OtherPhoneKey/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.OtherPhoneNumber', 'en', 'Other Phone Number', 'The phone option allowing members to convey additional phone numbers other than those already covered by the MemberMobilePhone, MemberFax and other specified fields.', 'https://dd.reso.org/DD2.0/OtherPhone/OtherPhoneNumber/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.OtherPhoneType', 'en', 'Other Phone Type', 'The type of phone record that does not already exist in the given phone fields or if a second of any type of phone field is needed (i.e., HomePhone2, BrothersPhone, etc.).', 'https://dd.reso.org/DD2.0/OtherPhone/OtherPhoneType/', 'https://dd.reso.org/DD2.0/lookups/OtherPhoneType/', '2.0', 'reso_official_csv'),
  ('OtherPhone.ResourceName', 'en', 'Resource Name', 'The resource or table of the listing or other record the media relates to (i.e., Property, Member, Office, etc.).', 'https://dd.reso.org/DD2.0/OtherPhone/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('OtherPhone.ResourceRecordID', 'en', 'Resource Record ID', 'The well-known identifier of the related record from the source resource. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/OtherPhone/ResourceRecordID/', NULL, '2.0', 'reso_official_csv'),
  ('OtherPhone.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey, TeamKey). This is the system you are connecting to and not necessarily the original source of the record. This is a foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/OtherPhone/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AboveGradeFinishedArea', 'en', 'Above Grade Finished Area', 'The finished area within the structure that is at or above the surface of the ground.', 'https://dd.reso.org/DD2.0/Property/AboveGradeFinishedArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AboveGradeFinishedAreaSource', 'en', 'Above Grade Finished Area Source', 'The source of the measurements. This is a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/AboveGradeFinishedAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
  ('Property.AboveGradeFinishedAreaUnits', 'en', 'Above Grade Finished Area Units', 'A pick list of the unit of measurement for the area (e.g., Square Feet, Square Meters).', 'https://dd.reso.org/DD2.0/Property/AboveGradeFinishedAreaUnits/', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/', '2.0', 'reso_official_csv'),
  ('Property.AboveGradeUnfinishedArea', 'en', 'Above Grade Unfinished Area', 'The unfinished area within the structure that is at or above the surface of the ground.', 'https://dd.reso.org/DD2.0/Property/AboveGradeUnfinishedArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AboveGradeUnfinishedAreaSource', 'en', 'Above Grade Unfinished Area Source', 'The source of the measurements of the unfinished area above grade. This is a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/AboveGradeUnfinishedAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
  ('Property.AboveGradeUnfinishedAreaUnits', 'en', 'Above Grade Unfinished Area Units', 'A pick list of the unit of measurement for the unfinished area above grade (e.g., Square Feet, Square Meters).', 'https://dd.reso.org/DD2.0/Property/AboveGradeUnfinishedAreaUnits/', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/', '2.0', 'reso_official_csv'),
  ('Property.AccessCode', 'en', 'Access Code', 'The code to gain access through the secured gate for a property located behind an unmanned security gate such as in a gated community.', 'https://dd.reso.org/DD2.0/Property/AccessCode/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AccessibilityFeatures', 'en', 'Accessibility Features', 'A list or description of the accessibility features included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/AccessibilityFeatures/', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/', '2.0', 'reso_official_csv'),
  ('Property.ActivationDate', 'en', 'Activation Date', 'Indicates when the listing agent intends to change the property to the Active status.', 'https://dd.reso.org/DD2.0/Property/ActivationDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AdditionalParcelsDescription', 'en', 'Additional Parcels Description', 'If additional parcels are included in the sale, a list of those parcel''s IDs separated by commas. Do not include the first or primary parcel number, that should be located in the Parcel Number field.', 'https://dd.reso.org/DD2.0/Property/AdditionalParcelsDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AdditionalParcelsYN', 'en', 'Additional Parcels Yes/No', 'Indicates whether or not more than one parcel or lot is included in the sale.', 'https://dd.reso.org/DD2.0/Property/AdditionalParcelsYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AnchorsCoTenants', 'en', 'Anchors & Cotenants', 'The main or most notable tenants as well as other tenants of the shopping center or mall in which the commercial property is located.', 'https://dd.reso.org/DD2.0/Property/AnchorsCoTenants/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Appliances', 'en', 'Appliances', 'A list of the appliances that will be included in the sale/lease of the property.', 'https://dd.reso.org/DD2.0/Property/Appliances/', 'https://dd.reso.org/DD2.0/lookups/Appliances/', '2.0', 'reso_official_csv'),
  ('Property.ArchitecturalStyle', 'en', 'Architectural Style', 'A list describing the style of the structure (e.g., Victorian, Ranch, Craftsman).', 'https://dd.reso.org/DD2.0/Property/ArchitecturalStyle/', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/', '2.0', 'reso_official_csv'),
  ('Property.AssociationAmenities', 'en', 'Association Amenities', 'The amenities provided by the homeowner association, mobile park or complex (e.g., pool, clubhouse).', 'https://dd.reso.org/DD2.0/Property/AssociationAmenities/', 'https://dd.reso.org/DD2.0/lookups/AssociationAmenities/', '2.0', 'reso_official_csv'),
  ('Property.AssociationFee', 'en', 'Association Fee', 'A fee paid by the homeowner to the homeowner association that is used for upkeep of common areas, the neighborhood or other association-related benefits.', 'https://dd.reso.org/DD2.0/Property/AssociationFee/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationFee2', 'en', 'Association Fee 2', 'A fee paid by the homeowner to the second of two homeowner associations that is used for upkeep of common areas, the neighborhood or other association-related benefits.', 'https://dd.reso.org/DD2.0/Property/AssociationFee2/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationFee2Frequency', 'en', 'Association Fee 2 Frequency', 'The frequency the association fee is paid (e.g., weekly, monthly, annually, bimonthly, one time).', 'https://dd.reso.org/DD2.0/Property/AssociationFee2Frequency/', 'https://dd.reso.org/DD2.0/lookups/FeeFrequency/', '2.0', 'reso_official_csv'),
  ('Property.AssociationFeeFrequency', 'en', 'Association Fee Frequency', 'The frequency the association fee is paid (e.g., weekly, monthly, annually, bimonthly, one time).', 'https://dd.reso.org/DD2.0/Property/AssociationFeeFrequency/', 'https://dd.reso.org/DD2.0/lookups/FeeFrequency/', '2.0', 'reso_official_csv'),
  ('Property.AssociationFeeIncludes', 'en', 'Association Fee Includes', 'The services included with the association fee (e.g., landscaping, trash, water).', 'https://dd.reso.org/DD2.0/Property/AssociationFeeIncludes/', 'https://dd.reso.org/DD2.0/lookups/AssociationFeeIncludes/', '2.0', 'reso_official_csv'),
  ('Property.AssociationName', 'en', 'Association Name', 'The name of the homeowner association.', 'https://dd.reso.org/DD2.0/Property/AssociationName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationName2', 'en', 'Association Name 2', 'The name of the second of two homeowner associations.', 'https://dd.reso.org/DD2.0/Property/AssociationName2/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationPhone', 'en', 'Association Phone', 'The phone number of the homeowner association. North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/AssociationPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationPhone2', 'en', 'Association Phone 2', 'The phone number of the second of two homeowner associations. North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/AssociationPhone2/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AssociationYN', 'en', 'Association Yes/No', 'Indicates whether there is a homeowner association. A separate Y/N field is needed because not all associations have dues.', 'https://dd.reso.org/DD2.0/Property/AssociationYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AttachedGarageYN', 'en', 'Attached Garage Yes/No', 'A flag indicating whether or not the garage is attached to the dwelling.', 'https://dd.reso.org/DD2.0/Property/AttachedGarageYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AttributionContact', 'en', 'Attribution Contact', 'A text field to convey a specific contact phone number or email address for the listing firm.', 'https://dd.reso.org/DD2.0/Property/AttributionContact/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AvailabilityDate', 'en', 'Availability Date', 'The date the property will be available for possession/occupation.', 'https://dd.reso.org/DD2.0/Property/AvailabilityDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.AvailableLeaseType', 'en', 'Available Lease Type', 'Information about the available types of lease for the property (i.e., Net, NNN, NN, Gross, Absolute Net, Escalation Clause, Ground Lease, etc.).', 'https://dd.reso.org/DD2.0/Property/AvailableLeaseType/', 'https://dd.reso.org/DD2.0/lookups/ExistingLeaseType/', '2.0', 'reso_official_csv'),
  ('Property.BackOnMarketDate', 'en', 'Back on Market Date', 'The date a listing, which had previously gone off market, went back to being on market. This date typically will reflect contractual dates. System timestamp should leverage the term Timestamp rather than Date in the field name.', 'https://dd.reso.org/DD2.0/Property/BackOnMarketDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Basement', 'en', 'Basement', 'A list of information and features about the basement (i.e., None/Slab, Finished, Partially Finished, Crawl Space, Dirt, Outside Entrance, Radon Mitigation).', 'https://dd.reso.org/DD2.0/Property/Basement/', 'https://dd.reso.org/DD2.0/lookups/Basement/', '2.0', 'reso_official_csv'),
  ('Property.BasementYN', 'en', 'Basement Yes/No', 'Indicates whether or not the property has a basement.', 'https://dd.reso.org/DD2.0/Property/BasementYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsFull', 'en', 'Bathrooms Full', 'A room containing all four of the four elements constituting a bath: toilet, sink, bathtub, shower head (in tub or stall). Some may considered a sink, toilet and tub (without a shower) a full bath, while others may consider that to be a three-quarters bath. In the event that the BathroomsThreeQuarter field is not in use, this field may represent the sum of all full and three-quarters bathrooms.', 'https://dd.reso.org/DD2.0/Property/BathroomsFull/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsHalf', 'en', 'Bathrooms Half', 'A room containing two of the four elements constituting a bath: toilet, sink, bathtub, shower head (in a tub or stall). A half bath will typically contain a sink and toilet.', 'https://dd.reso.org/DD2.0/Property/BathroomsHalf/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsOneQuarter', 'en', 'Bathrooms One Quarter', 'A room containing one of the four elements constituting a bath: toilet, sink, bathtub, shower head (in tub or stall). Examples include a vanity with a sink or a water closet (WC), which is a room with only a toilet.', 'https://dd.reso.org/DD2.0/Property/BathroomsOneQuarter/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsPartial', 'en', 'Bathrooms Partial', 'The number of partial bathrooms in the property being sold/leased. When used in combination with the BathroomsFull field, this replaces (or is the sum of) all half and one-quarter bathrooms. In the event that the BathroomsThreeQuarter field is not used, BathroomsFull replaces (or is the sum of) all full and three-quarters baths. This field should not be used in combination with the BathroomsOneQuarter or BathroomsHalf fields.', 'https://dd.reso.org/DD2.0/Property/BathroomsPartial/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsThreeQuarter', 'en', 'Bathrooms Three Quarter', 'A room containing three of the four elements constituting a bath: toilet, sink, bathtub, shower head (in a tub or stall). A typical three-quarters bath will contain a sink, toilet and shower. Some may considered a sink, toilet and tub (without a shower) a three-quarters bath, while others consider this to be a full bath.', 'https://dd.reso.org/DD2.0/Property/BathroomsThreeQuarter/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BathroomsTotalInteger', 'en', 'Bathrooms Total Integer', 'The simple sum of the number of bathrooms. For example, for a property with two full bathrooms and one half bathroom, the Bathrooms Total Integer would be 3. Expressing this example as 2.5 would require a non-standard field name. Decimal-based bathrooms are not recommended, they are possible via the Data Dictionary''s extensibility.', 'https://dd.reso.org/DD2.0/Property/BathroomsTotalInteger/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BedroomsPossible', 'en', 'Bedrooms Possible', 'The sum of BedroomsTotal plus other rooms that may be used as a bedroom but are not defined as a bedroom per local policy.', 'https://dd.reso.org/DD2.0/Property/BedroomsPossible/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BedroomsTotal', 'en', 'Bedrooms Total', 'The total number of bedrooms in the dwelling.', 'https://dd.reso.org/DD2.0/Property/BedroomsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BelowGradeFinishedArea', 'en', 'Below Grade Finished Area', 'The finished area within the structure that is below ground.', 'https://dd.reso.org/DD2.0/Property/BelowGradeFinishedArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BelowGradeFinishedAreaSource', 'en', 'Below Grade Finished Area Source', 'The source of the measurements. This is a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/BelowGradeFinishedAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
  ('Property.BelowGradeFinishedAreaUnits', 'en', 'Below Grade Finished Area Units', 'A pick list of the unit of measurement for the area (e.g., Square Feet, Square Meters).', 'https://dd.reso.org/DD2.0/Property/BelowGradeFinishedAreaUnits/', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/', '2.0', 'reso_official_csv'),
  ('Property.BelowGradeUnfinishedArea', 'en', 'Below Grade Unfinished Area', 'The unfinished area within the structure that is below ground.', 'https://dd.reso.org/DD2.0/Property/BelowGradeUnfinishedArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BelowGradeUnfinishedAreaSource', 'en', 'Below Grade Unfinished Area Source', 'The source of the measurements of the unfinished area below grade. This is a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/BelowGradeUnfinishedAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
