  ('Property.BuyerBrokerageCompensation', 'en', 'Buyer Brokerage Compensation', 'The total compensation to be paid to the buyer''s brokerage for this sale, expressed as either a percentage or a constant currency amount.', 'https://dd.reso.org/DD2.0/Property/BuyerBrokerageCompensation/', NULL, '2.0', 'reso_official_csv'),
  ('Property.BuyerBrokerageCompensationType', 'en', 'Buyer Brokerage Compensation Type', 'A list of types to clarify the value entered in the BuyerBrokerageCompensation field. For example, $, % or some other clarification of the BuyerAgencyCompensation field.', 'https://dd.reso.org/DD2.0/Property/BuyerBrokerageCompensationType/', 'https://dd.reso.org/DD2.0/lookups/CompensationType/', '2.0', 'reso_official_csv'),
