  ('Property.CarportYN', 'en', 'Carport Yes/No', 'A flag indicating that the listing has a carport. This flag may be true/false, yes/no or another true, false or unknown indicator. As with all flags, the field may be null.', 'https://dd.reso.org/DD2.0/Property/CarportYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.CarrierRoute', 'en', 'Carrier Route', 'The group of addresses to which the U.S. Postal Service (USPS) assigns the same code to aid in mail delivery. For the USPS, these codes are nine digits: five numbers for the ZIP Code, one letter for the carrier route type and three numbers for the carrier route number.', 'https://dd.reso.org/DD2.0/Property/CarrierRoute/', NULL, '2.0', 'reso_official_csv'),
