  ('Property.CityRegion', 'en', 'City Region', 'A subsection or area of a defined city (e.g., SOHO in New York, NY; Ironbound in Newark, NJ; Inside the Beltway).', 'https://dd.reso.org/DD2.0/Property/CityRegion/', NULL, '2.0', 'reso_official_csv'),
