  ('Property.Concessions', 'en', 'Concessions', 'Indicates whether or not there are concessions included in the sales agreement (i.e., Yes, No or Call Listing Agent).', 'https://dd.reso.org/DD2.0/Property/Concessions/', 'https://dd.reso.org/DD2.0/lookups/Concessions/', '2.0', 'reso_official_csv'),
  ('Property.ConcessionsAmount', 'en', 'Concessions Amount', 'The dollar amount of the concessions. If the concessions are made by the seller, some may subtract this value from the sales price as a means of calculating their own true price. If concessions are made by the buyer, some may add this amount to the sale price to create their own true price. Concessions made by both buyer and seller should be subtracted from each other, providing a net value. Details of this calculation should be added to the Concessions Comments field.', 'https://dd.reso.org/DD2.0/Property/ConcessionsAmount/', NULL, '2.0', 'reso_official_csv'),
