  ('Property.ListAgentTollFreePhone', 'en', 'List Agent Toll Free Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/ListAgentTollFreePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListAgentURL', 'en', 'List Agent URL', 'The website Uniform Resource Identifier (URI) of the listing agent.', 'https://dd.reso.org/DD2.0/Property/ListAgentURL/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListAgentVoiceMail', 'en', 'List Agent Voice Mail', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/ListAgentVoiceMail/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListAgentVoiceMailExt', 'en', 'List Agent Voice Mail Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Property/ListAgentVoiceMailExt/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOffice', 'en', 'List Office', 'The listing agent''s office.', 'https://dd.reso.org/DD2.0/Property/ListOffice/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeAOR', 'en', 'List Office AOR', 'The listing office''s board or association of REALTORS®.', 'https://dd.reso.org/DD2.0/Property/ListOfficeAOR/', 'https://dd.reso.org/DD2.0/lookups/AOR/', '2.0', 'reso_official_csv'),
  ('Property.ListOfficeEmail', 'en', 'List Office Email', 'The email address of the listing office.', 'https://dd.reso.org/DD2.0/Property/ListOfficeEmail/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeFax', 'en', 'List Office Fax', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/ListOfficeFax/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeKey', 'en', 'List Office Key', 'A system unique identifier. Specifically, in aggregation systems, the key is the system unique identifier from the system where the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set. This is a foreign key relating to the Office Resource''s OfficeKey.', 'https://dd.reso.org/DD2.0/Property/ListOfficeKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeMlsId', 'en', 'List Office MLS ID', 'The local, well-known identifier. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/Property/ListOfficeMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeName', 'en', 'List Office Name', 'The legal name of the brokerage representing the seller.', 'https://dd.reso.org/DD2.0/Property/ListOfficeName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeNationalAssociationId', 'en', 'List Office National Association ID', 'The national association ID of the listing office (e.g., the NRDS number in the U.S.).', 'https://dd.reso.org/DD2.0/Property/ListOfficeNationalAssociationId/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficePhone', 'en', 'List Office Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/ListOfficePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficePhoneExt', 'en', 'List Office Phone Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Property/ListOfficePhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListOfficeURL', 'en', 'List Office URL', 'The website Uniform Resource Identifier (URI) for the listing office.', 'https://dd.reso.org/DD2.0/Property/ListOfficeURL/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListPrice', 'en', 'List Price', 'The current price of the property as determined by the seller and the seller''s broker. For auctions, this is the minimum or reserve price.', 'https://dd.reso.org/DD2.0/Property/ListPrice/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListPriceLow', 'en', 'List Price Low', 'The lower price used for Value Range Pricing. The List Price must be greater than or equal to the ListPriceLow.', 'https://dd.reso.org/DD2.0/Property/ListPriceLow/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListTeam', 'en', 'List Team', 'Two or more agents working on the listing agent''s team.', 'https://dd.reso.org/DD2.0/Property/ListTeam/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListTeamKey', 'en', 'List Team Key', 'A system unique identifier. Specifically, in aggregation systems, the key is the system unique identifier from the system where the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set. This is a foreign key relating to the Teams Resource''s TeamKey.', 'https://dd.reso.org/DD2.0/Property/ListTeamKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListTeamName', 'en', 'List Team Name', 'The name of the team representing the seller.', 'https://dd.reso.org/DD2.0/Property/ListTeamName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListingAgreement', 'en', 'Listing Agreement', 'The nature of the agreement between the seller and the listing agent (e.g., Exclusive Agency, Open Listing).', 'https://dd.reso.org/DD2.0/Property/ListingAgreement/', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/', '2.0', 'reso_official_csv'),
  ('Property.ListingContractDate', 'en', 'Listing Contract Date', 'The effective date of the agreement between the seller and the seller''s broker. This is the date entered by the agent reflecting when the change occurred contractually, not a timestamp of when the change was made in the MLS.', 'https://dd.reso.org/DD2.0/Property/ListingContractDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListingId', 'en', 'Listing ID', 'The well-known identifier for the listing. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/Property/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListingKey', 'en', 'Listing Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/Property/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListingService', 'en', 'Listing Service', 'The type or level of service the listing member will be providing to the selling homeowner (e.g., Full Service, Limited Service, Entry Only). This will typically be a single selection.', 'https://dd.reso.org/DD2.0/Property/ListingService/', 'https://dd.reso.org/DD2.0/lookups/ListingService/', '2.0', 'reso_official_csv'),
  ('Property.ListingTerms', 'en', 'Listing Terms', 'Terms of the listing such as Lien Release, Subject to Court Approval or Owner Will Carry. Also may include options that describe the financing terms that are acceptable to the seller (i.e., Cash, Assumable, FHA, etc.).', 'https://dd.reso.org/DD2.0/Property/ListingTerms/', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/', '2.0', 'reso_official_csv'),
  ('Property.ListingURL', 'en', 'Listing URL', 'Provides a link to the specific listing on a brokerage website, agent website or other public-facing source.', 'https://dd.reso.org/DD2.0/Property/ListingURL/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ListingURLDescription', 'en', 'Listing URL Description', 'A pick list of options showing where the listing URL resides (i.e., Brokerage Website, Agent Website, etc.).', 'https://dd.reso.org/DD2.0/Property/ListingURLDescription/', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/', '2.0', 'reso_official_csv'),
  ('Property.LivingArea', 'en', 'Living Area', 'The total livable area within the structure.', 'https://dd.reso.org/DD2.0/Property/LivingArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LivingAreaSource', 'en', 'Living Area Source', 'The source of the measurements. This is a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/LivingAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
  ('Property.LivingAreaUnits', 'en', 'Living Area Units', 'A pick list of the unit of measurement for the area (e.g., Square Feet, Square Meters).', 'https://dd.reso.org/DD2.0/Property/LivingAreaUnits/', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/', '2.0', 'reso_official_csv'),
  ('Property.LockBoxLocation', 'en', 'Lock Box Location', 'A field describing the location of the lockbox.', 'https://dd.reso.org/DD2.0/Property/LockBoxLocation/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LockBoxSerialNumber', 'en', 'Lock Box Serial Number', 'The serial number of the lockbox placed on the property.', 'https://dd.reso.org/DD2.0/Property/LockBoxSerialNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LockBoxType', 'en', 'Lock Box Type', 'A field describing the type of lockbox.', 'https://dd.reso.org/DD2.0/Property/LockBoxType/', 'https://dd.reso.org/DD2.0/lookups/LockBoxType/', '2.0', 'reso_official_csv'),
  ('Property.Longitude', 'en', 'Longitude', 'The geographic longitude of some reference point on the property, specified in degrees and decimal parts. Positive numbers must not include the plus symbol.', 'https://dd.reso.org/DD2.0/Property/Longitude/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LotDimensionsSource', 'en', 'Lot Dimensions Source', 'The source of the measurements. This may be a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/LotDimensionsSource/', 'https://dd.reso.org/DD2.0/lookups/LotDimensionsSource/', '2.0', 'reso_official_csv'),
  ('Property.LotFeatures', 'en', 'Lot Features', 'A list of features or a description of the lot included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/LotFeatures/', 'https://dd.reso.org/DD2.0/lookups/LotFeatures/', '2.0', 'reso_official_csv'),
  ('Property.LotSizeAcres', 'en', 'Lot Size Acres', 'The total acres of the lot. This field is related to Lot Size Area and Lot Size Units and must be in sync with the values represented in those fields. Lot Size Source also applies to this field when used.', 'https://dd.reso.org/DD2.0/Property/LotSizeAcres/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LotSizeArea', 'en', 'Lot Size Area', 'The total area of the lot. See Lot Size Units for the units of measurement (e.g., square feet, square meters, acres).', 'https://dd.reso.org/DD2.0/Property/LotSizeArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LotSizeDimensions', 'en', 'Lot Size Dimensions', 'The dimensions of the lot minimally represented as length and width (i.e. 250 x 180) or a measurement of all sides of the polygon representing the property lines of the property (i.e., 30 x 50 x 120 x 60 x 22).', 'https://dd.reso.org/DD2.0/Property/LotSizeDimensions/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LotSizeSource', 'en', 'Lot Size Source', 'The source of the measurements. This may be a pick list of options showing the source of the measurement (e.g., Agent, Assessor, Estimate).', 'https://dd.reso.org/DD2.0/Property/LotSizeSource/', 'https://dd.reso.org/DD2.0/lookups/LotSizeSource/', '2.0', 'reso_official_csv'),
  ('Property.LotSizeSquareFeet', 'en', 'Lot Size Square Feet', 'The total square footage of the lot. This field is related to Lot Size Area and Lot Size Units and must be in sync with the values represented in those fields. Lot Size Source also applies to this field when used.', 'https://dd.reso.org/DD2.0/Property/LotSizeSquareFeet/', NULL, '2.0', 'reso_official_csv'),
  ('Property.LotSizeUnits', 'en', 'Lot Size Units', 'A pick list of the unit of measurement for the area (e.g., Square Feet, Square Meters, Acres).', 'https://dd.reso.org/DD2.0/Property/LotSizeUnits/', 'https://dd.reso.org/DD2.0/lookups/LotSizeUnits/', '2.0', 'reso_official_csv'),
  ('Property.MLSAreaMajor', 'en', 'MLS Area Major', 'The major marketing area name, as defined by the MLS or other nongovernmental organization. If there is only one MLS area in use, it must be the MLSAreaMajor.', 'https://dd.reso.org/DD2.0/Property/MLSAreaMajor/', 'https://dd.reso.org/DD2.0/lookups/MLSAreaMajor/', '2.0', 'reso_official_csv'),
  ('Property.MLSAreaMinor', 'en', 'MLS Area Minor', 'The minor/submarketing area name, as defined by the MLS or other nongovernmental organization. If there is only one MLS area in use, it must be the MLSAreaMajor.', 'https://dd.reso.org/DD2.0/Property/MLSAreaMinor/', 'https://dd.reso.org/DD2.0/lookups/MLSAreaMinor/', '2.0', 'reso_official_csv'),
  ('Property.MainLevelBathrooms', 'en', 'Main Level Bathrooms', 'The number of bathrooms located on the main or entry level of the property.', 'https://dd.reso.org/DD2.0/Property/MainLevelBathrooms/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MainLevelBedrooms', 'en', 'Main Level Bedrooms', 'The number of bedrooms located on the main or entry level of the property.', 'https://dd.reso.org/DD2.0/Property/MainLevelBedrooms/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MaintenanceExpense', 'en', 'Maintenance Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/MaintenanceExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MajorChangeTimestamp', 'en', 'Major Change Timestamp', 'The timestamp of the last major change on the listing (see also MajorChangeType).', 'https://dd.reso.org/DD2.0/Property/MajorChangeTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MajorChangeType', 'en', 'Major Change Type', 'A description of the last major change on the listing (i.e., Price Reduction, Back on Market). This may be used to display on a summary view of listing results to quickly identify listings that have had major changes recently.', 'https://dd.reso.org/DD2.0/Property/MajorChangeType/', 'https://dd.reso.org/DD2.0/lookups/ChangeType/', '2.0', 'reso_official_csv'),
  ('Property.Make', 'en', 'Make', 'The make of the mobile or manufactured home.', 'https://dd.reso.org/DD2.0/Property/Make/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ManagerExpense', 'en', 'Manager Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations. This is for an individual manager. Use ProfessionalManagementExpense for a management company.', 'https://dd.reso.org/DD2.0/Property/ManagerExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MapCoordinate', 'en', 'Map Coordinate', 'A map coordinate for the property, as determined by local custom. This is not necessarily the same as the geographic coordinate but may depend on the coordinate system used by whatever mapping service is customarily used by the listing service.', 'https://dd.reso.org/DD2.0/Property/MapCoordinate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MapCoordinateSource', 'en', 'Map Coordinate Source', 'The name of the map or map book publisher.', 'https://dd.reso.org/DD2.0/Property/MapCoordinateSource/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MapURL', 'en', 'Map URL', 'A Uniform Resource Identifier (URI) to a map of the property.', 'https://dd.reso.org/DD2.0/Property/MapURL/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Media', 'en', 'Media', 'A collection of media items related to the Property record.', 'https://dd.reso.org/DD2.0/Property/Media/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MiddleOrJuniorSchool', 'en', 'Middle Or Junior School', 'The name of the junior or middle school having a catchment area that includes the associated property.', 'https://dd.reso.org/DD2.0/Property/MiddleOrJuniorSchool/', 'https://dd.reso.org/DD2.0/lookups/MiddleOrJuniorSchool/', '2.0', 'reso_official_csv'),
  ('Property.MiddleOrJuniorSchoolDistrict', 'en', 'Middle Or Junior School District', 'The name of the junior or middle school district having a catchment area that includes the associated property.', 'https://dd.reso.org/DD2.0/Property/MiddleOrJuniorSchoolDistrict/', 'https://dd.reso.org/DD2.0/lookups/MiddleOrJuniorSchoolDistrict/', '2.0', 'reso_official_csv'),
  ('Property.MlsStatus', 'en', 'MLS Status', 'A local or regional status that is well known by business users. Each MlsStatus field must map to a single StandardStatus. Multiple MlsStatus fields may map to a single StandardStatus.', 'https://dd.reso.org/DD2.0/Property/MlsStatus/', 'https://dd.reso.org/DD2.0/lookups/MlsStatus/', '2.0', 'reso_official_csv'),
  ('Property.MobileDimUnits', 'en', 'Mobile Dimensions Units', 'A pick list of the unit of linear measurement (e.g., Feet, Meters, Yards, Kilometers, Miles).', 'https://dd.reso.org/DD2.0/Property/MobileDimUnits/', 'https://dd.reso.org/DD2.0/lookups/LinearUnits/', '2.0', 'reso_official_csv'),
  ('Property.MobileHomeRemainsYN', 'en', 'Mobile Home Remains Yes/No', 'Indicates whether or not the mobile home is to remain and be included in the sale of the property.', 'https://dd.reso.org/DD2.0/Property/MobileHomeRemainsYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MobileLength', 'en', 'Mobile Length', 'The length of the mobile/manufactured home.', 'https://dd.reso.org/DD2.0/Property/MobileLength/', NULL, '2.0', 'reso_official_csv'),
  ('Property.MobileWidth', 'en', 'Mobile Width', 'The width of the mobile/manufactured home.', 'https://dd.reso.org/DD2.0/Property/MobileWidth/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Model', 'en', 'Model', 'The model of the mobile or manufactured home.', 'https://dd.reso.org/DD2.0/Property/Model/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the listing was last modified.', 'https://dd.reso.org/DD2.0/Property/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NetOperatingIncome', 'en', 'Net Operating Income', 'The net operating income is the revenue from a property after operating expenses have been deducted but before deducting income taxes and financing expenses (interest and principal payments). For example, gross income - operating expenses = net operating income (NOI).', 'https://dd.reso.org/DD2.0/Property/NetOperatingIncome/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NewConstructionYN', 'en', 'New Construction Yes/No', 'Indicates whether or not the property is newly constructed and has not been previously occupied.', 'https://dd.reso.org/DD2.0/Property/NewConstructionYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NewTaxesExpense', 'en', 'New Taxes Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/NewTaxesExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfBuildings', 'en', 'Number Of Buildings', 'The total number of separate buildings included in the income property.', 'https://dd.reso.org/DD2.0/Property/NumberOfBuildings/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfFullTimeEmployees', 'en', 'Number Of Full Time Employees', 'The current number of individuals employed by the business on a full-time basis.', 'https://dd.reso.org/DD2.0/Property/NumberOfFullTimeEmployees/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfLots', 'en', 'Number Of Lots', 'The total number of lots on the property or included in the sale. Land properties are often sold with multiple lots. It is important to be able to describe how many lots are in the property, and not all lots have separate parcel IDs.', 'https://dd.reso.org/DD2.0/Property/NumberOfLots/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfPads', 'en', 'Number Of Pads', 'The number of pads or spaces in the mobile home park.', 'https://dd.reso.org/DD2.0/Property/NumberOfPads/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfPartTimeEmployees', 'en', 'Number Of Part Time Employees', 'The current number of individuals employed by the business on a part-time basis.', 'https://dd.reso.org/DD2.0/Property/NumberOfPartTimeEmployees/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfSeparateElectricMeters', 'en', 'Number Of Separate Electric Meters', 'The total number of separate electric meters on the property.', 'https://dd.reso.org/DD2.0/Property/NumberOfSeparateElectricMeters/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfSeparateGasMeters', 'en', 'Number Of Separate Gas Meters', 'The total number of separate gas meters on the property.', 'https://dd.reso.org/DD2.0/Property/NumberOfSeparateGasMeters/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfSeparateWaterMeters', 'en', 'Number Of Separate Water Meters', 'The total number of separate water meters on the property.', 'https://dd.reso.org/DD2.0/Property/NumberOfSeparateWaterMeters/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfUnitsInCommunity', 'en', 'Number Of Units In Community', 'The total number of units in the building, complex or community. This is not the number of units being sold, but rather the size of the community in which the dwelling being sold is located.', 'https://dd.reso.org/DD2.0/Property/NumberOfUnitsInCommunity/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfUnitsLeased', 'en', 'Number Of Units Leased', 'The total number of units currently under a lease agreement.', 'https://dd.reso.org/DD2.0/Property/NumberOfUnitsLeased/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfUnitsMoMo', 'en', 'Number Of Units Month To Month', 'The total number of units leasable month to month.', 'https://dd.reso.org/DD2.0/Property/NumberOfUnitsMoMo/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfUnitsTotal', 'en', 'Number Of Units Total', 'Total number of units included in the income property, occupied or unoccupied.', 'https://dd.reso.org/DD2.0/Property/NumberOfUnitsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Property.NumberOfUnitsVacant', 'en', 'Number Of Units Vacant', 'The number of units currently vacant.', 'https://dd.reso.org/DD2.0/Property/NumberOfUnitsVacant/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OccupantName', 'en', 'Occupant Name', 'The name of the current occupant, if any, of the property being sold.', 'https://dd.reso.org/DD2.0/Property/OccupantName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OccupantPhone', 'en', 'Occupant Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/OccupantPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OccupantType', 'en', 'Occupant Type', 'A field that describes the type of occupant (i.e., Owner, Tenant, Vacant).', 'https://dd.reso.org/DD2.0/Property/OccupantType/', 'https://dd.reso.org/DD2.0/lookups/OccupantType/', '2.0', 'reso_official_csv'),
  ('Property.OffMarketDate', 'en', 'Off Market Date', 'The date the listing was taken off market. Where possible, this date represents the date entered by the agent, reflecting when the change occurred contractually, not a timestamp of when the change was made in the MLS.', 'https://dd.reso.org/DD2.0/Property/OffMarketDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OffMarketTimestamp', 'en', 'Off Market Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the most recent date/time the listing''s status was set to an off-market status (not Active or Backup)', 'https://dd.reso.org/DD2.0/Property/OffMarketTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OnMarketDate', 'en', 'On Market Date', 'The date the listing was placed on market. Where possible, this date is reflective of the date entered by the agent reflecting when the change occurred contractually, not a timestamp of when the change was made in the MLS.', 'https://dd.reso.org/DD2.0/Property/OnMarketDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OnMarketTimestamp', 'en', 'On Market Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the most recent date/time the listing''s status was set to Active or Backup. This also includes initial input of the listing to Active/Backup or from a draft or approval status to Active/Backup.', 'https://dd.reso.org/DD2.0/Property/OnMarketTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OpenHouse', 'en', 'Open House', 'A collection of open house items related to the Property record.', 'https://dd.reso.org/DD2.0/Property/OpenHouse/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OpenHouseModificationTimestamp', 'en', 'Open House Modification Timestamp', 'A system-generated timestamp of when the last update or change to the open house information for this listing was made.', 'https://dd.reso.org/DD2.0/Property/OpenHouseModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OpenParkingSpaces', 'en', 'Open Parking Spaces', 'The number of open or uncovered parking spaces included in the sale.', 'https://dd.reso.org/DD2.0/Property/OpenParkingSpaces/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OpenParkingYN', 'en', 'Open Parking Yes/No', 'A flag indicating that any parking spaces associated with the property are not covered by a roof.', 'https://dd.reso.org/DD2.0/Property/OpenParkingYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OperatingExpense', 'en', 'Operating Expense', 'The costs associated with the operation and maintenance of an income-producing property.', 'https://dd.reso.org/DD2.0/Property/OperatingExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OperatingExpenseIncludes', 'en', 'Operating Expense Includes', 'When individual expense fields are not used and only a total is entered, this lists the expenses that are included in the OperatingExpense field.', 'https://dd.reso.org/DD2.0/Property/OperatingExpenseIncludes/', 'https://dd.reso.org/DD2.0/lookups/OperatingExpenseIncludes/', '2.0', 'reso_official_csv'),
  ('Property.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the listing was entered and made visible to members of the MLS.', 'https://dd.reso.org/DD2.0/Property/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OriginalListPrice', 'en', 'Original List Price', 'The original price of the property on the initial agreement between the seller and the seller''s broker.', 'https://dd.reso.org/DD2.0/Property/OriginalListPrice/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OriginatingSystem', 'en', 'Originating System', 'The originating system of the Property record.', 'https://dd.reso.org/DD2.0/Property/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OriginatingSystemID', 'en', 'Originating System ID', 'The OUID Resource''s OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Property/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the listing was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/Property/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/Property/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OtherEquipment', 'en', 'Other Equipment', 'A list of other equipment that will be included in the sale of the property.', 'https://dd.reso.org/DD2.0/Property/OtherEquipment/', 'https://dd.reso.org/DD2.0/lookups/OtherEquipment/', '2.0', 'reso_official_csv'),
  ('Property.OtherExpense', 'en', 'Other Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/OtherExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OtherParking', 'en', 'Other Parking', 'Other types of parking available to, or part of, the property.', 'https://dd.reso.org/DD2.0/Property/OtherParking/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OtherStructures', 'en', 'Other Structures', 'A list of structures other than the main dwelling (e.g., Guest House, Barn, Shed).', 'https://dd.reso.org/DD2.0/Property/OtherStructures/', 'https://dd.reso.org/DD2.0/lookups/OtherStructures/', '2.0', 'reso_official_csv'),
  ('Property.OwnerName', 'en', 'Owner Name', 'The name of the owner of the property being sold.', 'https://dd.reso.org/DD2.0/Property/OwnerName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OwnerPays', 'en', 'Owner Pays', 'A list of expenses for the property paid for by the owner as opposed to the tenant (e.g., Water, Trash, Electric).', 'https://dd.reso.org/DD2.0/Property/OwnerPays/', 'https://dd.reso.org/DD2.0/lookups/OwnerPays/', '2.0', 'reso_official_csv'),
  ('Property.OwnerPhone', 'en', 'Owner Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/OwnerPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Ownership', 'en', 'Ownership', 'A text description of the manner in which title to a property is held (e.g., Trust, Corporation, Joint Tenant, Individual).', 'https://dd.reso.org/DD2.0/Property/Ownership/', NULL, '2.0', 'reso_official_csv'),
  ('Property.OwnershipType', 'en', 'Ownership Type', 'The current type of ownership of the business being sold (e.g., Corporation, LLC, Sole Proprietor, Partnership).', 'https://dd.reso.org/DD2.0/Property/OwnershipType/', 'https://dd.reso.org/DD2.0/lookups/OwnershipType/', '2.0', 'reso_official_csv'),
  ('Property.ParcelNumber', 'en', 'Parcel Number', 'A number used to uniquely identify a parcel or lot. This number is typically issued by the county or county assessor. The assessor''s parcel number (APN) format varies from county to county. It is recommended that all parcel numbers are transmitted without dashes or hyphens.', 'https://dd.reso.org/DD2.0/Property/ParcelNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ParkManagerName', 'en', 'Park Manager Name', 'The name of the manager of the mobile home park.', 'https://dd.reso.org/DD2.0/Property/ParkManagerName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ParkManagerPhone', 'en', 'Park Manager Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Property/ParkManagerPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ParkName', 'en', 'Park Name', 'The name of the mobile home park or corporate/commercial park.', 'https://dd.reso.org/DD2.0/Property/ParkName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ParkingFeatures', 'en', 'Parking Features', 'A list of features about or a description of the parking included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/ParkingFeatures/', 'https://dd.reso.org/DD2.0/lookups/ParkingFeatures/', '2.0', 'reso_official_csv'),
  ('Property.ParkingTotal', 'en', 'Parking Total', 'The total number of parking spaces included in the sale.', 'https://dd.reso.org/DD2.0/Property/ParkingTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PastureArea', 'en', 'Pasture Area', 'A measurement or percentage of the property that has been allocated as pasture or grazing area.', 'https://dd.reso.org/DD2.0/Property/PastureArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PatioAndPorchFeatures', 'en', 'Patio And Porch Features', 'A list of features about or a description of the patio or porch included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/PatioAndPorchFeatures/', 'https://dd.reso.org/DD2.0/lookups/PatioAndPorchFeatures/', '2.0', 'reso_official_csv'),
  ('Property.PendingTimestamp', 'en', 'Pending Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the most recent date/time the listing''s status was set to Pending.', 'https://dd.reso.org/DD2.0/Property/PendingTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PestControlExpense', 'en', 'Pest Control Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/PestControlExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PetsAllowed', 'en', 'Pets Allowed', 'Indicates whether or not pets are allowed at the property being leased, usually as a list of yes, no and more detailed restrictions/allowances.', 'https://dd.reso.org/DD2.0/Property/PetsAllowed/', 'https://dd.reso.org/DD2.0/lookups/PetsAllowed/', '2.0', 'reso_official_csv'),
  ('Property.PhotosChangeTimestamp', 'en', 'Photos Change Timestamp', 'A system-generated timestamp of when the last update or change to the photos for this listing was made.', 'https://dd.reso.org/DD2.0/Property/PhotosChangeTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PhotosCount', 'en', 'Photos Count', 'The total number of pictures or photos included with the listing.', 'https://dd.reso.org/DD2.0/Property/PhotosCount/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PoolExpense', 'en', 'Pool Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/PoolExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PoolFeatures', 'en', 'Pool Features', 'A list of features about or a description of a pool included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/PoolFeatures/', 'https://dd.reso.org/DD2.0/lookups/PoolFeatures/', '2.0', 'reso_official_csv'),
  ('Property.PoolPrivateYN', 'en', 'Pool Private Yes/No', 'The property has a privately owned pool that is included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/PoolPrivateYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Possession', 'en', 'Possession', 'A list defining when possession will occur (i.e., COE, COE+1, etc.).', 'https://dd.reso.org/DD2.0/Property/Possession/', 'https://dd.reso.org/DD2.0/lookups/Possession/', '2.0', 'reso_official_csv'),
  ('Property.PossibleUse', 'en', 'Possible Use', 'A list of the type(s) of possible or best uses of the property. Probable use gives a good indication of what the best use or potential use of the property could be (e.g., Residential, Recreational, Commercial, Retail).', 'https://dd.reso.org/DD2.0/Property/PossibleUse/', 'https://dd.reso.org/DD2.0/lookups/CurrentOrPossibleUse/', '2.0', 'reso_official_csv'),
  ('Property.PostalCity', 'en', 'Postal City', 'The official city per the U.S. Postal Service (USPS), which may be different from the recorded city.', 'https://dd.reso.org/DD2.0/Property/PostalCity/', 'https://dd.reso.org/DD2.0/lookups/PostalCity/', '2.0', 'reso_official_csv'),
  ('Property.PostalCode', 'en', 'Postal Code', 'The postal code portion of a street or mailing address.', 'https://dd.reso.org/DD2.0/Property/PostalCode/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PostalCodePlus4', 'en', 'Postal Code Plus4', 'The last four digits of a nine-digit U.S. ZIP Code.', 'https://dd.reso.org/DD2.0/Property/PostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PowerProduction', 'en', 'Power Production', 'A collection of the types of power production system(s) available on the property. The collection includes the type of system and other details about the power produced and age of the system.', 'https://dd.reso.org/DD2.0/Property/PowerProduction/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PowerProductionType', 'en', 'Power Production Type', 'A list of the types of power production systems available on the property. A relational implementation of power production must omit the type from the field name and use PowerProductionType to create a vertical representation of the various types of power production available.', 'https://dd.reso.org/DD2.0/Property/PowerProductionType/', 'https://dd.reso.org/DD2.0/lookups/PowerProductionType/', '2.0', 'reso_official_csv'),
  ('Property.PowerProductionYN', 'en', 'Power Production Yes/No', 'A flag indicating that the listing has a Power Production system.', 'https://dd.reso.org/DD2.0/Property/PowerProductionYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PreviousListPrice', 'en', 'Previous List Price', 'The most recent previous list price of the listing.', 'https://dd.reso.org/DD2.0/Property/PreviousListPrice/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PriceChangeTimestamp', 'en', 'Price Change Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the listing''s price was last changed.', 'https://dd.reso.org/DD2.0/Property/PriceChangeTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PrivateOfficeRemarks', 'en', 'Private Office Remarks', 'A Remarks field that is only visible to members of the same offices as the listing agent.', 'https://dd.reso.org/DD2.0/Property/PrivateOfficeRemarks/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PrivateRemarks', 'en', 'Private Remarks', 'Remarks that may contain security or proprietary information and should be restricted from public view.', 'https://dd.reso.org/DD2.0/Property/PrivateRemarks/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ProfessionalManagementExpense', 'en', 'Professional Management Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations. This is for a management company. Use ManagerExpense for a individual manager.', 'https://dd.reso.org/DD2.0/Property/ProfessionalManagementExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PropertyAttachedYN', 'en', 'Property Attached Yes/No', 'Indicates whether or not the primary structure is attached to another structure that is not included in the sale (i.e., one unit of a duplex). This flag may be True/False, Yes/No or a list of attached or detached. As with all flags, the field may be null. In some systems, this information may be part of the property subtype.', 'https://dd.reso.org/DD2.0/Property/PropertyAttachedYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PropertyCondition', 'en', 'Property Condition', 'A list describing the condition of the property and any structures included in the sale.', 'https://dd.reso.org/DD2.0/Property/PropertyCondition/', 'https://dd.reso.org/DD2.0/lookups/PropertyCondition/', '2.0', 'reso_official_csv'),
  ('Property.PropertySubType', 'en', 'Property Sub Type', 'A list of types of residential and residential lease properties (e.g., Single-Family Residence, Condominium, Townhouse) or a list of subtypes for mobile (e.g., Manufactured Home, Manufactured On Land).', 'https://dd.reso.org/DD2.0/Property/PropertySubType/', 'https://dd.reso.org/DD2.0/lookups/PropertySubType/', '2.0', 'reso_official_csv'),
  ('Property.PropertyTimeZoneName', 'en', 'Property Time Zone Name', 'The standard name of the property time zone, as provided by the IANA tz database.', 'https://dd.reso.org/DD2.0/Property/PropertyTimeZoneName/', 'https://dd.reso.org/DD2.0/lookups/IanaTimeZoneValues/', '2.0', 'reso_official_csv'),
  ('Property.PropertyTimeZoneObservesDstYN', 'en', 'Property Time Zone Observes DST Yes/No', 'Indicates whether the property is in a time zone that observes Daylight Savings Time (DST).', 'https://dd.reso.org/DD2.0/Property/PropertyTimeZoneObservesDstYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PropertyTimeZoneStandardOffset', 'en', 'Property Time Zone Standard Offset', 'The time zone offset is the difference, in minutes, between Coordinated Universal Time (UTC) and local time.', 'https://dd.reso.org/DD2.0/Property/PropertyTimeZoneStandardOffset/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PropertyType', 'en', 'Property Type', 'A list of types of properties (e.g., Residential, Lease, Income, Land, Mobile, Commercial Sale).', 'https://dd.reso.org/DD2.0/Property/PropertyType/', 'https://dd.reso.org/DD2.0/lookups/PropertyType/', '2.0', 'reso_official_csv'),
  ('Property.PublicRemarks', 'en', 'Public Remarks', 'Text remarks that may be displayed to the public. In an MLS, it is the field where information is entered for the public. This information is intended to be visible online. This is typically information that describes the selling points of the building and/or land for sale. Local conditions and rules will determine what such content can contain. Generally, any information pertaining to entry to the property, the seller and/or tenant, or listing member contact information is excluded. In other systems, these remarks will be determined by local business rules.', 'https://dd.reso.org/DD2.0/Property/PublicRemarks/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PublicSurveyRange', 'en', 'Public Survey Range', 'The range identified by the Public Land Survey System (PLSS).', 'https://dd.reso.org/DD2.0/Property/PublicSurveyRange/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PublicSurveySection', 'en', 'Public Survey Section', 'The section identified by the Public Land Survey System (PLSS).', 'https://dd.reso.org/DD2.0/Property/PublicSurveySection/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PublicSurveyTownship', 'en', 'Public Survey Township', 'The township identified by the Public Land Survey System (PLSS).', 'https://dd.reso.org/DD2.0/Property/PublicSurveyTownship/', NULL, '2.0', 'reso_official_csv'),
  ('Property.PurchaseContractDate', 'en', 'Purchase Contract Date', 'With for-sale listings, this represents the date an offer was accepted and the listing was no longer on market. This is the date entered by the agent reflecting when the change occurred contractually, not a timestamp of when the change was made in the MLS. With lease listings, this may represent a meeting of the minds to lease but with some contractual requirements yet to be fulfilled, such as contract signing or receipt of the deposit.', 'https://dd.reso.org/DD2.0/Property/PurchaseContractDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.RVParkingDimensions', 'en', 'RV Parking Dimensions', 'The dimensions of the RV parking area minimally represented as length and width (i.e., 25'' x 18'') or a measurement of all sides of the polygon representing the usable RV parking space (i.e., 33'' x 15'' x 12'' x 60'').', 'https://dd.reso.org/DD2.0/Property/RVParkingDimensions/', NULL, '2.0', 'reso_official_csv'),
  ('Property.RangeArea', 'en', 'Range Area', 'The measurement or percentage of the property that has been allocated as range.', 'https://dd.reso.org/DD2.0/Property/RangeArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.RentControlYN', 'en', 'Rent Control Yes/No', 'Indicates whether or not the property is in a rent-control area.', 'https://dd.reso.org/DD2.0/Property/RentControlYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.RentIncludes', 'en', 'Rent Includes', 'A list of services or items that the tenant is not responsible to pay.', 'https://dd.reso.org/DD2.0/Property/RentIncludes/', 'https://dd.reso.org/DD2.0/lookups/RentIncludes/', '2.0', 'reso_official_csv'),
  ('Property.RoadFrontageType', 'en', 'Road Frontage Type', 'A pick list of types of road frontage (i.e., County, Freeway, Interstate, None). The road frontage of the property is an important factor in determining property value and its appropriateness for intended use.', 'https://dd.reso.org/DD2.0/Property/RoadFrontageType/', 'https://dd.reso.org/DD2.0/lookups/RoadFrontageType/', '2.0', 'reso_official_csv'),
  ('Property.RoadResponsibility', 'en', 'Road Responsibility', 'The person or entity responsible for road maintenance (e.g., City, County, Private).', 'https://dd.reso.org/DD2.0/Property/RoadResponsibility/', 'https://dd.reso.org/DD2.0/lookups/RoadResponsibility/', '2.0', 'reso_official_csv'),
  ('Property.RoadSurfaceType', 'en', 'Road Surface Type', 'A pick list of types of road surfaces in use to access the property. Road surfaces for property access are an important factor in determining property value and its appropriateness for intended use.', 'https://dd.reso.org/DD2.0/Property/RoadSurfaceType/', 'https://dd.reso.org/DD2.0/lookups/RoadSurfaceType/', '2.0', 'reso_official_csv'),
  ('Property.Roof', 'en', 'Roof', 'A list describing the roof style type (e.g., Spanish Tile, Composite, Shake).', 'https://dd.reso.org/DD2.0/Property/Roof/', 'https://dd.reso.org/DD2.0/lookups/Roof/', '2.0', 'reso_official_csv'),
  ('Property.RoomType', 'en', 'Room Type', 'A list of identifiers for specific interior spaces within a structure (e.g., Bedroom, Bathroom, Kitchen, Living Room). A relational implementation of rooms must omit the type from the field name and use RoomType to create a vertical representation of the various rooms. Note that garage or basement should not be added as a room type, as these are represented by the ParkingFeatures and Basement fields, respectively.', 'https://dd.reso.org/DD2.0/Property/RoomType/', 'https://dd.reso.org/DD2.0/lookups/RoomType/', '2.0', 'reso_official_csv'),
  ('Property.Rooms', 'en', 'Rooms', 'A collection of types of rooms and details/features about the given room.', 'https://dd.reso.org/DD2.0/Property/Rooms/', NULL, '2.0', 'reso_official_csv'),
  ('Property.RoomsTotal', 'en', 'Rooms Total', 'The number of rooms in a dwelling.', 'https://dd.reso.org/DD2.0/Property/RoomsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SeatingCapacity', 'en', 'Seating Capacity', 'The seating capacity of the business being sold.', 'https://dd.reso.org/DD2.0/Property/SeatingCapacity/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SecurityFeatures', 'en', 'Security Features', 'A list describing the security features included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/SecurityFeatures/', 'https://dd.reso.org/DD2.0/lookups/SecurityFeatures/', '2.0', 'reso_official_csv'),
  ('Property.SeniorCommunityYN', 'en', 'Senior Community Yes/No', 'Indicates whether or not a community is a senior community.', 'https://dd.reso.org/DD2.0/Property/SeniorCommunityYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SerialU', 'en', 'Serial U', 'The serial number of the mobile or manufactured home. For the first or only unit/section, use Serial U over Serial X or Serial XX.', 'https://dd.reso.org/DD2.0/Property/SerialU/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SerialX', 'en', 'Serial X', 'The serial number of the mobile or manufactured home. For two units/sections, Serial U should be used first, Serial X second.', 'https://dd.reso.org/DD2.0/Property/SerialX/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SerialXX', 'en', 'Serial XX', 'The serial number of the mobile or manufactured home. For two units/sections, Serial U should be used first, Serial X (or Serial XX) second.', 'https://dd.reso.org/DD2.0/Property/SerialXX/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Sewer', 'en', 'Sewer', 'A list describing the sewer or septic features of a property.', 'https://dd.reso.org/DD2.0/Property/Sewer/', 'https://dd.reso.org/DD2.0/lookups/Sewer/', '2.0', 'reso_official_csv'),
  ('Property.ShowingAdvanceNotice', 'en', 'Showing Advance Notice', 'The hours of advance notice required to schedule a showing.', 'https://dd.reso.org/DD2.0/Property/ShowingAdvanceNotice/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingAttendedYN', 'en', 'Showing Attended Yes/No', 'Indicates whether or not this home requires an attended showing (i.e., Yes = licensed agent representing the seller must be present during showing).', 'https://dd.reso.org/DD2.0/Property/ShowingAttendedYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingConsiderations', 'en', 'Showing Considerations', 'A pick list of conditions that may require caution or further consideration, such as bringing someone with you, when showing the property (i.e., Electricity Not On, Inconsistent Cell Service, No Exterior Lighting).', 'https://dd.reso.org/DD2.0/Property/ShowingConsiderations/', 'https://dd.reso.org/DD2.0/lookups/ShowingConsiderations/', '2.0', 'reso_official_csv'),
  ('Property.ShowingContactName', 'en', 'Showing Contact Name', 'The name of the contact for the showing of the listed property.', 'https://dd.reso.org/DD2.0/Property/ShowingContactName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingContactPhone', 'en', 'Showing Contact Phone', 'A telephone number that should be called to arrange showing the property.', 'https://dd.reso.org/DD2.0/Property/ShowingContactPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingContactPhoneExt', 'en', 'Showing Contact Phone Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Property/ShowingContactPhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingContactType', 'en', 'Showing Contact Type', 'The type of contact for the showing (i.e., Agent, Broker, Seller).', 'https://dd.reso.org/DD2.0/Property/ShowingContactType/', 'https://dd.reso.org/DD2.0/lookups/ShowingContactType/', '2.0', 'reso_official_csv'),
  ('Property.ShowingDays', 'en', 'Showing Days', 'The days of the week that the property is available for showing (i.e., Sundays, Mondays, Tuesdays, Wednesdays, Thursdays, Fridays, Saturdays).', 'https://dd.reso.org/DD2.0/Property/ShowingDays/', 'https://dd.reso.org/DD2.0/lookups/ShowingDays/', '2.0', 'reso_official_csv'),
  ('Property.ShowingEndTime', 'en', 'Showing End Time', 'From the days selected in the ShowingDays field, the end time that the property is available for showing.', 'https://dd.reso.org/DD2.0/Property/ShowingEndTime/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingInstructions', 'en', 'Showing Instructions', 'Remarks that detail the seller''s instructions for showing the subject property. Showing instructions may include contact information, showing times, notice required or other information. These remarks are privileged and are not for public viewing.', 'https://dd.reso.org/DD2.0/Property/ShowingInstructions/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ShowingRequirements', 'en', 'Showing Requirements', 'A pick list of types of notice required to see the home (i.e., Appointment Required, Courtesy Call Only, Go Direct, etc.).', 'https://dd.reso.org/DD2.0/Property/ShowingRequirements/', 'https://dd.reso.org/DD2.0/lookups/ShowingRequirements/', '2.0', 'reso_official_csv'),
  ('Property.ShowingServiceName', 'en', 'Showing Service Name', 'The name of the showing service used to request showings on the listing.', 'https://dd.reso.org/DD2.0/Property/ShowingServiceName/', 'https://dd.reso.org/DD2.0/lookups/ShowingServiceName/', '2.0', 'reso_official_csv'),
  ('Property.ShowingStartTime', 'en', 'Showing Start Time', 'From the days selected in the ShowingDays field, the start time that the property is available for showing.', 'https://dd.reso.org/DD2.0/Property/ShowingStartTime/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SignOnPropertyYN', 'en', 'Sign On Property Yes/No', 'Indicates whether or not there a sign on the property.', 'https://dd.reso.org/DD2.0/Property/SignOnPropertyYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SimpleDaysOnMarket', 'en', 'Simple Days on Market', 'A simplified version of days on market (DOM) where the calculation is a simple start and end, such as the difference between the listing input or contract date and the date of sale.', 'https://dd.reso.org/DD2.0/Property/SimpleDaysOnMarket/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Skirt', 'en', 'Skirt', 'A list of types of mobile home skirting.', 'https://dd.reso.org/DD2.0/Property/Skirt/', 'https://dd.reso.org/DD2.0/lookups/Skirt/', '2.0', 'reso_official_csv'),
  ('Property.SocialMedia', 'en', 'Social Media', 'A collection of social media items related to the Property record.', 'https://dd.reso.org/DD2.0/Property/SocialMedia/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SourceSystem', 'en', 'Source System', 'The source system of the Property record.', 'https://dd.reso.org/DD2.0/Property/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SourceSystemID', 'en', 'Source System ID', 'The OUID Resource''s OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Property/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Property/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SourceSystemName', 'en', 'Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Property/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SpaFeatures', 'en', 'Spa Features', 'A list of features or a description of the spa included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/SpaFeatures/', 'https://dd.reso.org/DD2.0/lookups/SpaFeatures/', '2.0', 'reso_official_csv'),
  ('Property.SpaYN', 'en', 'Spa Yes/No', 'Indicates whether or not the property has a spa.', 'https://dd.reso.org/DD2.0/Property/SpaYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SpecialLicenses', 'en', 'Special Licenses', 'Special licenses required/used by the business being sold (e.g., Beer/Wine, Class H, Professional, Gambling, None).', 'https://dd.reso.org/DD2.0/Property/SpecialLicenses/', 'https://dd.reso.org/DD2.0/lookups/SpecialLicenses/', '2.0', 'reso_official_csv'),
  ('Property.SpecialListingConditions', 'en', 'Special Listing Conditions', 'A list of options that describe the type of sale (e.g., Standard, REO, Short Sale, Probate, Auction, NOD) at the time of listing.', 'https://dd.reso.org/DD2.0/Property/SpecialListingConditions/', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/', '2.0', 'reso_official_csv'),
  ('Property.StandardStatus', 'en', 'Standard Status', 'The status of the listing as it reflects the state of the contract between the listing agent and seller, or an agreement with a buyer (e.g., Active, Active Under Contract, Canceled, Closed, Expired, Pending, Withdrawn). This is a single-select field.', 'https://dd.reso.org/DD2.0/Property/StandardStatus/', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/', '2.0', 'reso_official_csv'),
  ('Property.StartShowingDate', 'en', 'Start Showing Date', 'The date the listing agent/broker expects to start showing the property.', 'https://dd.reso.org/DD2.0/Property/StartShowingDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StateOrProvince', 'en', 'State Or Province', 'Text field containing the accepted postal abbreviation for the state or province.', 'https://dd.reso.org/DD2.0/Property/StateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('Property.StateRegion', 'en', 'State Region', 'A subsection or area of a defined state or province (e.g., Florida Keys, Hudson Valley in New York, Silicon Valley in California).', 'https://dd.reso.org/DD2.0/Property/StateRegion/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StatusChangeTimestamp', 'en', 'Status Change Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time the listing''s status was last changed.', 'https://dd.reso.org/DD2.0/Property/StatusChangeTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Stories', 'en', 'Stories', 'The number of floors in the property being sold.', 'https://dd.reso.org/DD2.0/Property/Stories/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StoriesTotal', 'en', 'Stories Total', 'The total number of floors in the building. In the case of multi-dwelling structures, this is the entire structure and not the individual dwelling being sold.', 'https://dd.reso.org/DD2.0/Property/StoriesTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StreetAdditionalInfo', 'en', 'Street Additional Info', 'Information other than a prefix or suffix for the street portion of a postal address.', 'https://dd.reso.org/DD2.0/Property/StreetAdditionalInfo/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StreetDirPrefix', 'en', 'Street Direction Prefix', 'The direction indicator that precedes the listed property''s street name.', 'https://dd.reso.org/DD2.0/Property/StreetDirPrefix/', 'https://dd.reso.org/DD2.0/lookups/StreetDirection/', '2.0', 'reso_official_csv'),
  ('Property.StreetDirSuffix', 'en', 'Street Direction Suffix', 'The direction indicator that follows a listed property''s street address.', 'https://dd.reso.org/DD2.0/Property/StreetDirSuffix/', 'https://dd.reso.org/DD2.0/lookups/StreetDirection/', '2.0', 'reso_official_csv'),
  ('Property.StreetName', 'en', 'Street Name', 'The street name portion of a listed property''s street address.', 'https://dd.reso.org/DD2.0/Property/StreetName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StreetNumber', 'en', 'Street Number', 'The street number portion of a listed property''s street address. In some areas, the street number may contain non numeric characters. This field can also contain extensions and modifiers to the street number, such as "1/2" or "B." This street number field should not include prefixes, direction or suffixes.', 'https://dd.reso.org/DD2.0/Property/StreetNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StreetNumberNumeric', 'en', 'Street Number Numeric', 'The integer portion of the street number.', 'https://dd.reso.org/DD2.0/Property/StreetNumberNumeric/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StreetSuffix', 'en', 'Street Suffix', 'The suffix portion of a listed property''s street address.', 'https://dd.reso.org/DD2.0/Property/StreetSuffix/', 'https://dd.reso.org/DD2.0/lookups/StreetSuffix/', '2.0', 'reso_official_csv'),
  ('Property.StreetSuffixModifier', 'en', 'Street Suffix Modifier', 'Allows for the entry of a unique street suffix that was not found in the Street Suffix pick list or to extend or prefix the suffix.', 'https://dd.reso.org/DD2.0/Property/StreetSuffixModifier/', NULL, '2.0', 'reso_official_csv'),
  ('Property.StructureType', 'en', 'Structure Type', 'The type of structure that the property completely or partially encompasses. For example, houses or cabins are the overall structure and typically sold or leased as a whole. Multifamily and docks may be sold in whole but are often sold or leased by unit/slip. This field is the type of structure as opposed to style, which is under the Architectural Style field.', 'https://dd.reso.org/DD2.0/Property/StructureType/', 'https://dd.reso.org/DD2.0/lookups/StructureType/', '2.0', 'reso_official_csv'),
  ('Property.SubAgencyCompensation', 'en', 'Sub Agency Compensation', 'The total commission to be paid to the subagency, expressed as either a percentage or a constant currency amount.', 'https://dd.reso.org/DD2.0/Property/SubAgencyCompensation/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SubAgencyCompensationType', 'en', 'Sub Agency Compensation Type', 'A list of types to clarify the value entered in the SubAgencyCompensation field. For example $, % or some other clarification of SubAgencyCompensation.', 'https://dd.reso.org/DD2.0/Property/SubAgencyCompensationType/', 'https://dd.reso.org/DD2.0/lookups/CompensationType/', '2.0', 'reso_official_csv'),
  ('Property.SubdivisionName', 'en', 'Subdivision Name', 'A neighborhood, community, complex or builder tract.', 'https://dd.reso.org/DD2.0/Property/SubdivisionName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SuppliesExpense', 'en', 'Supplies Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/SuppliesExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.SyndicateTo', 'en', 'Syndicate To', 'When permitted by the broker, the options made by the agent on behalf of the seller, where they would like their listings syndicated (e.g., Zillow, Trulia, Realtor.com, Homes.com).', 'https://dd.reso.org/DD2.0/Property/SyndicateTo/', 'https://dd.reso.org/DD2.0/lookups/SyndicateTo/', '2.0', 'reso_official_csv'),
  ('Property.SyndicationRemarks', 'en', 'Syndication Remarks', 'For MLSs that host a separate "Public Remarks" for syndication purposes, this field should be defaulted to contain public remarks. Upon broker decision, it should be modified to include contact and other information denied by IDX rules but allowed under local and national regulations.', 'https://dd.reso.org/DD2.0/Property/SyndicationRemarks/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxAnnualAmount', 'en', 'Tax Annual Amount', 'The annual property tax amount as of the last assessment made by the taxing authority.', 'https://dd.reso.org/DD2.0/Property/TaxAnnualAmount/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxAnnualAmountPerLivingAreaUnit', 'en', 'Tax Annual Amount Per Living Area Unit', 'The annual property tax amount as of the last assessment made by the taxing authority divided by the property’s living area. The LivingAreaUnits field defines the area unit type (e.g., Square Feet or Square Meters).', 'https://dd.reso.org/DD2.0/Property/TaxAnnualAmountPerLivingAreaUnit/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxAnnualAmountPerSquareFoot', 'en', 'Tax Annual Amount Per Square Foot', 'The annual property tax amount as of the last assessment made by the taxing authority divided by the property’s living area square footage.', 'https://dd.reso.org/DD2.0/Property/TaxAnnualAmountPerSquareFoot/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxAssessedValue', 'en', 'Tax Assessed Value', 'The property value as of the last assessment made by the taxing authority.', 'https://dd.reso.org/DD2.0/Property/TaxAssessedValue/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxBlock', 'en', 'Tax Block', 'A type of legal description for land in developed areas where streets or other rights-of-ways delineate large parcels of land referred to as divided into lots on which homes or other types of developments are built. An example would read "Lot 12 of Block 45 of Tract 3002 of the City of San Dunes, Desert County." Such a description would also reference an official plat filed with the clerk or recorder for that area which shows the location of the block and often the dimensions of the lots therein.', 'https://dd.reso.org/DD2.0/Property/TaxBlock/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxBookNumber', 'en', 'Tax Book Number', 'Some systems of parcel identification incorporate a method that utilizes a county identifier, a tax book number, a tax map number and a parcel identification number.', 'https://dd.reso.org/DD2.0/Property/TaxBookNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxLegalDescription', 'en', 'Tax Legal Description', 'A type of legal description for land in developed areas where streets or other rights-of-ways delineate large parcels of land referred to as divided into lots on which homes or other types of developments are built. An example would read "Lot 12 of Block 45 of Tract 3002 of the City of San Dunes, Desert County." Such a description would also reference an official plat filed with the clerk or recorder for that area which shows the location of the block and often the dimensions of the lots therein. The text here is also an index into the property as described by the County Recorder.', 'https://dd.reso.org/DD2.0/Property/TaxLegalDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxLot', 'en', 'Tax Lot', 'A type of legal description for land in developed areas where streets or other rights-of-ways delineate large parcels of land referred to as divided into lots on which homes or other types of developments are built. An example would read "Lot 12 of Block 45 of Tract 3002 of the City of San Dunes, Desert County." Such a description would also reference an official plat filed with the clerk or recorder for that area which shows the location of the block and often the dimensions of the lots therein.', 'https://dd.reso.org/DD2.0/Property/TaxLot/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxMapNumber', 'en', 'Tax Map Number', 'Some systems of parcel identification incorporate a method that utilizes a county identifier, a tax book number, a tax map number and a parcel identification number.', 'https://dd.reso.org/DD2.0/Property/TaxMapNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxOtherAnnualAssessmentAmount', 'en', 'Tax Other Annual Assessment Amount', 'Any other annual taxes, not including the tax reported in the TaxAmount field, as of the last assessment made by the taxing authority.', 'https://dd.reso.org/DD2.0/Property/TaxOtherAnnualAssessmentAmount/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxParcelLetter', 'en', 'Tax Parcel Letter', 'Some systems of parcel identification incorporate a method that utilizes a county identifier, a tax book number, a tax map number and a parcel identification number.', 'https://dd.reso.org/DD2.0/Property/TaxParcelLetter/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxStatusCurrent', 'en', 'Tax Status Current', 'The current tax status of the mobile home in cases where the land or space is included in the sale.', 'https://dd.reso.org/DD2.0/Property/TaxStatusCurrent/', 'https://dd.reso.org/DD2.0/lookups/TaxStatusCurrent/', '2.0', 'reso_official_csv'),
  ('Property.TaxTract', 'en', 'Tax Tract', 'A type of legal description for land in developed areas where streets or other rights-of-ways delineate large parcels of land referred to as divided into lots on which homes or other types of developments are built. An example would read "Lot 12 of Block 45 of Tract 3002 of the City of San Dunes, Desert County." Such a description would also reference an official plat filed with the clerk or recorder for that area which shows the location of the block and often the dimensions of the lots therein.', 'https://dd.reso.org/DD2.0/Property/TaxTract/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TaxYear', 'en', 'Tax Year', 'The year in which the last assessment of the property value/tax was made.', 'https://dd.reso.org/DD2.0/Property/TaxYear/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TenantPays', 'en', 'Tenant Pays', 'A list of services or items that the tenant is responsible to pay.', 'https://dd.reso.org/DD2.0/Property/TenantPays/', 'https://dd.reso.org/DD2.0/lookups/TenantPays/', '2.0', 'reso_official_csv'),
  ('Property.Topography', 'en', 'Topography', 'The state of the surface of the land included with the property (i.e., flat, rolling, etc.).', 'https://dd.reso.org/DD2.0/Property/Topography/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TotalActualRent', 'en', 'Total Actual Rent', 'Total actual rent currently being collected from tenants of the income property.', 'https://dd.reso.org/DD2.0/Property/TotalActualRent/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Township', 'en', 'Township', 'A subdivision of the county.', 'https://dd.reso.org/DD2.0/Property/Township/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TransactionBrokerCompensation', 'en', 'Transaction Broker Compensation', 'The total commission to be paid to the transaction facilitator, expressed as either a percentage or a constant currency amount.', 'https://dd.reso.org/DD2.0/Property/TransactionBrokerCompensation/', NULL, '2.0', 'reso_official_csv'),
  ('Property.TransactionBrokerCompensationType', 'en', 'Transaction Broker Compensation Type', 'A list of types to clarify the value entered in the TransactionBrokerCompensation field. For example $, % or some other clarification of the TransactionBrokerCompensation.', 'https://dd.reso.org/DD2.0/Property/TransactionBrokerCompensationType/', 'https://dd.reso.org/DD2.0/lookups/CompensationType/', '2.0', 'reso_official_csv'),
  ('Property.TrashExpense', 'en', 'Trash Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/TrashExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.UnitNumber', 'en', 'Unit Number', 'A text field containing the unit number or portion of a larger building or complex that should appear following the street suffix or, if it exists, the street suffix direction in the street address (e.g., Apt G, #55).', 'https://dd.reso.org/DD2.0/Property/UnitNumber/', NULL, '2.0', 'reso_official_csv'),
  ('Property.UnitTypeType', 'en', 'Unit Type Type', 'A list of floor plans or configurations of an individual unit (e.g., 1 Bedroom, Studio, Loft) in a multi-family or multi-unit development. A relational implementation of UnitTypes must omit the type from the field name and use UnitTypeType to create a vertical representation of the various unit types. Repeating of the word "type" in the field name is intentional.', 'https://dd.reso.org/DD2.0/Property/UnitTypeType/', 'https://dd.reso.org/DD2.0/lookups/UnitTypeType/', '2.0', 'reso_official_csv'),
  ('Property.UnitTypes', 'en', 'Unit Types', 'A collection of types of units included in the income (multifamily) property. The collection includes a type, beds, baths and other aspects of the type of unit behind described.', 'https://dd.reso.org/DD2.0/Property/UnitTypes/', NULL, '2.0', 'reso_official_csv'),
  ('Property.UnitsFurnished', 'en', 'Units Furnished', 'States whether or not the units are furnished (i.e., All Units, Varies By Unit, None).', 'https://dd.reso.org/DD2.0/Property/UnitsFurnished/', 'https://dd.reso.org/DD2.0/lookups/UnitsFurnished/', '2.0', 'reso_official_csv'),
  ('Property.UniversalPropertyId', 'en', 'Universal Property ID', 'The RESO Universal Property Identifier (UPI) is a unique identifier for all real property in the U.S. and Canada. It is based on country and local identification methods and is limited to real property. For cases such as shares of real property, units and other more granular cases, please utilize the UniversalPropertySubId.', 'https://dd.reso.org/DD2.0/Property/UniversalPropertyId/', NULL, '2.0', 'reso_official_csv'),
  ('Property.UniversalPropertySubId', 'en', 'Universal Property Sub ID', 'A unique identifier for all subsets or shares of real property in the U.S. and Canada. This may include Stock Cooperatives, Community Apartment, Units for Rent, etc. Informally abbreviated as UPSI, it is based on country and local identification methods, just as the Universal Property Identifier (UPI), but it is limited to subsets or shares of real property. For cases of complete real property, please utilize the UniversalPropertyId field.', 'https://dd.reso.org/DD2.0/Property/UniversalPropertySubId/', NULL, '2.0', 'reso_official_csv'),
  ('Property.UnparsedAddress', 'en', 'Unparsed Address', 'A text representation of the address with the full civic location as a single entity. It may optionally include any of City, StateOrProvince, PostalCode and Country.', 'https://dd.reso.org/DD2.0/Property/UnparsedAddress/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Utilities', 'en', 'Utilities', 'A list of the utilities for the property being sold/leased.', 'https://dd.reso.org/DD2.0/Property/Utilities/', 'https://dd.reso.org/DD2.0/lookups/Utilities/', '2.0', 'reso_official_csv'),
  ('Property.VacancyAllowance', 'en', 'Vacancy Allowance', 'An estimate of the amount of rent that may be foregone because of unoccupied units.', 'https://dd.reso.org/DD2.0/Property/VacancyAllowance/', NULL, '2.0', 'reso_official_csv'),
  ('Property.VacancyAllowanceRate', 'en', 'Vacancy Allowance Rate', 'An estimate of the percent of rent that may be foregone because of unoccupied units.', 'https://dd.reso.org/DD2.0/Property/VacancyAllowanceRate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Vegetation', 'en', 'Vegetation', 'A list of the type(s) of residential vegetation on the property (not farm crops).', 'https://dd.reso.org/DD2.0/Property/Vegetation/', 'https://dd.reso.org/DD2.0/lookups/Vegetation/', '2.0', 'reso_official_csv'),
  ('Property.VideosChangeTimestamp', 'en', 'Videos Change Timestamp', 'A system-generated timestamp of when the last update or change to the videos for this listing was made.', 'https://dd.reso.org/DD2.0/Property/VideosChangeTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Property.VideosCount', 'en', 'Videos Count', 'The total number of videos or virtual tours included with the listing.', 'https://dd.reso.org/DD2.0/Property/VideosCount/', NULL, '2.0', 'reso_official_csv'),
  ('Property.View', 'en', 'View', 'A view as seen from the listed property.', 'https://dd.reso.org/DD2.0/Property/View/', 'https://dd.reso.org/DD2.0/lookups/View/', '2.0', 'reso_official_csv'),
  ('Property.ViewYN', 'en', 'View Yes/No', 'The property has a view.', 'https://dd.reso.org/DD2.0/Property/ViewYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.VirtualTourURLBranded', 'en', 'Virtual Tour URL Branded', 'A text field that holds the Uniform Resource Locator (URL) for a branded virtual tour of the property.', 'https://dd.reso.org/DD2.0/Property/VirtualTourURLBranded/', NULL, '2.0', 'reso_official_csv'),
  ('Property.VirtualTourURLUnbranded', 'en', 'Virtual Tour URL Unbranded', 'A text field that holds the Uniform Resource Locator (URL) for an unbranded virtual tour of the property.', 'https://dd.reso.org/DD2.0/Property/VirtualTourURLUnbranded/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WalkScore', 'en', 'Walk Score', 'A walkability index based on the time to walk from a property to nearby essentials such as grocery stores, schools, churches, etc. See https://www.walkscore.com/ for more information and requirements for using Walk Score.', 'https://dd.reso.org/DD2.0/Property/WalkScore/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WaterBodyName', 'en', 'Water Body Name', 'The name, if known, of the body of water on which the property is located (e.g., lake name, river name, ocean name, sea name, canal name).', 'https://dd.reso.org/DD2.0/Property/WaterBodyName/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WaterSewerExpense', 'en', 'Water Sewer Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/WaterSewerExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WaterSource', 'en', 'Water Source', 'A list of the source(s) of water for the property.', 'https://dd.reso.org/DD2.0/Property/WaterSource/', 'https://dd.reso.org/DD2.0/lookups/WaterSource/', '2.0', 'reso_official_csv'),
  ('Property.WaterfrontFeatures', 'en', 'Waterfront Features', 'The features of the waterfront on which the property is located.', 'https://dd.reso.org/DD2.0/Property/WaterfrontFeatures/', 'https://dd.reso.org/DD2.0/lookups/WaterfrontFeatures/', '2.0', 'reso_official_csv'),
  ('Property.WaterfrontYN', 'en', 'Waterfront Yes/No', 'The property is on a waterfront.', 'https://dd.reso.org/DD2.0/Property/WaterfrontYN/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WindowFeatures', 'en', 'Window Features', 'A list of features or a description of the windows included in the sale/lease.', 'https://dd.reso.org/DD2.0/Property/WindowFeatures/', 'https://dd.reso.org/DD2.0/lookups/WindowFeatures/', '2.0', 'reso_official_csv'),
  ('Property.WithdrawnDate', 'en', 'Withdrawn Date', 'The date that the listing was withdrawn from the market. This is not when a listing contract was canceled or closed, but a withdrawal from the market while the contract between the seller and listing agent is still in effect and an offer has not been accepted. This is the date entered by the agent reflecting when the change occurred contractually, not a timestamp of when the change was made in the MLS.', 'https://dd.reso.org/DD2.0/Property/WithdrawnDate/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WoodedArea', 'en', 'Wooded Area', 'A measurement or percentage of the property that is wooded or forest.', 'https://dd.reso.org/DD2.0/Property/WoodedArea/', NULL, '2.0', 'reso_official_csv'),
  ('Property.WorkmansCompensationExpense', 'en', 'Workmans Compensation Expense', 'The annual expense that is not paid directly by the tenant and is included in the Operating Expense calculations.', 'https://dd.reso.org/DD2.0/Property/WorkmansCompensationExpense/', NULL, '2.0', 'reso_official_csv'),
  ('Property.YearBuilt', 'en', 'Year Built', 'The year that an occupancy permit is first granted for the house or other local measure of initial habitability of the build. The type of definition permits an empty value with an attribute noting that it is an unknown date or that the building is new construction. While constraints have not been applied, convention at the time of adoption has this as a four-digit year value.', 'https://dd.reso.org/DD2.0/Property/YearBuilt/', NULL, '2.0', 'reso_official_csv'),
  ('Property.YearBuiltDetails', 'en', 'Year Built Details', 'A description of the details behind the year the structure was built.', 'https://dd.reso.org/DD2.0/Property/YearBuiltDetails/', NULL, '2.0', 'reso_official_csv'),
  ('Property.YearBuiltEffective', 'en', 'Year Built Effective', 'The year a major rebuild/renovated of the structure occurred.', 'https://dd.reso.org/DD2.0/Property/YearBuiltEffective/', NULL, '2.0', 'reso_official_csv'),
  ('Property.YearBuiltSource', 'en', 'Year Built Source', 'A list of sources of the year built (e.g., Appraiser, Assessor, Builder, Estimated).', 'https://dd.reso.org/DD2.0/Property/YearBuiltSource/', 'https://dd.reso.org/DD2.0/lookups/YearBuiltSource/', '2.0', 'reso_official_csv'),
  ('Property.YearEstablished', 'en', 'Year Established', 'The year the business being sold was established.', 'https://dd.reso.org/DD2.0/Property/YearEstablished/', NULL, '2.0', 'reso_official_csv'),
  ('Property.YearsCurrentOwner', 'en', 'Years Current Owner', 'The number of years the current owner has had possession of the business.', 'https://dd.reso.org/DD2.0/Property/YearsCurrentOwner/', NULL, '2.0', 'reso_official_csv'),
  ('Property.Zoning', 'en', 'Zoning', 'A division of the city or county into areas of different permissible land uses. This field should be used for the short code that is commonly used. For full textual descriptions, please use the ZoningDescription field.', 'https://dd.reso.org/DD2.0/Property/Zoning/', NULL, '2.0', 'reso_official_csv'),
  ('Property.ZoningDescription', 'en', 'Zoning Description', 'A list of descriptions of the zoning of the property. The zoning codes are often nondescriptive and variant. This provides a more descriptive form of the zoning for the property (e.g., Agricultural, Residential, Rezone Possible). Specific zone codes must be added to the Zoning field.', 'https://dd.reso.org/DD2.0/Property/ZoningDescription/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenBuildingVerificationKey', 'en', 'Green Building Verification Key', 'A unique identifier for this record. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenBuildingVerificationKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenBuildingVerificationType', 'en', 'Green Building Verification Type', 'The name of the verification or certification awarded to a new or pre-existing residential or commercial structure (e.g., LEED, ENERGY STAR, ICC-700).', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenBuildingVerificationType/', 'https://dd.reso.org/DD2.0/lookups/GreenBuildingVerificationType/', '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationBody', 'en', 'Green Verification Body', 'The name of the body or group providing the verification/certification/rating named in the GreenBuildingVerificationType field. There is almost always a direct correlation between bodies and programs.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationBody/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationMetric', 'en', 'Green Verification Metric', 'A final score indicating the performance of energy efficiency design and measures in the home as tested by a third-party rater. Points achieved to earn a certification in the GreenVerificationRating field do not apply to this field. The Home Energy Rating System (HERS) Index is most common with new homes and runs with a lower number being more efficient. A net-zero home uses zero energy and has a HERS score of 0. A home that produces more energy than it uses has a negative score. Home Energy Score is a tool more common for existing homes and runs with a higher number being more efficient. It takes square footage into account and caps with 10 as the highest number of points.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationMetric/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationRating', 'en', 'Green Verification Rating', 'Many verifications or certifications have a rating system that provides an indication of the structure''s level of energy efficiency. When expressed in a numeric value, please use the GreenVerificationMetric field. Verifications and certifications can also be a name, such as Gold or Silver, which is the purpose of this field.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationRating/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationSource', 'en', 'Green Verification Source', 'The source of the green data. It may address photovoltaic characteristics or a verified score, certification, label, etc. This may be a pick list of options showing the source (i.e., Program Sponsor, Program Verifier, Public Record, Assessor, etc.).', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationSource/', 'https://dd.reso.org/DD2.0/lookups/GreenVerificationSource/', '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationStatus', 'en', 'Green Verification Status', 'Many verification programs include a multistep process that may begin with plans and specs, involve testing and/or submission of building specifications along the way, and include a final verification step. When ratings are involved, it is not uncommon for the final rating to be either higher or lower than the target preliminary rating. Sometimes the final approval is not available until after sale and occupancy. Status indicates what the target was at the time of listing and may be updated when verification is complete. To limit liability concerns, this field reflects information that was available at the time of listing or updated later and should be confirmed by the buyer.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationStatus/', 'https://dd.reso.org/DD2.0/lookups/GreenVerificationStatus/', '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationURL', 'en', 'Green Verification URL', 'Provides a link to the specific property’s high-performance rating or scoring details directly from and hosted by the sponsoring body of the program. It typically provides thorough details, for example, which points were achieved and how, or, in the case of a score, what specifically was tested and the results.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationURL/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationVersion', 'en', 'Green Verification Version', 'The version of the green certification or verification that was awarded. Some rating programs have a year, a version or possibly both.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationVersion/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.GreenVerificationYear', 'en', 'Green Verification Year', 'The year the green certification or verification was awarded.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/GreenVerificationYear/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.HistoryTransactional', 'en', 'History Transactional', 'The history of the PropertyGreenVerification record.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.Listing', 'en', 'Listing', 'The listing associated with the PropertyGreenVerification record.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.ListingId', 'en', 'Listing ID', 'This is the foreign ID relating to the property. The well-known identifier for the listing. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.ListingKey', 'en', 'Listing Key', 'This is the foreign key relating to the property. A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see the Property Resource''s SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyGreenVerification.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the PropertyGreenVerification record was last modified.', 'https://dd.reso.org/DD2.0/PropertyGreenVerification/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.HistoryTransactional', 'en', 'History Transactional', 'The history of the PropertyPowerProduction record.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.Listing', 'en', 'Listing', 'The listing associated with the PropertyPowerProduction record.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.ListingId', 'en', 'Listing ID', 'This is the foreign ID relating to the Property Resource; the well-known identifier for the listing. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.ListingKey', 'en', 'Listing Key', 'This is the foreign key relating to the Property Resource; the unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see the Property Resource''s SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the PropertyPowerProduction record was last modified.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionAnnual', 'en', 'Power Production Annual', 'The most important metric of a renewables system is the amount of power it produces per year. This number can be actual or estimated. Annual production for systems producing electricity like wind or solar are measured in kilowatt hours (kWh) per year. A kWh is like a measure of the distance traveled per hour for a car - how far did it go over a certain period of time. Annual production is influenced by the size of the system, the conditions (How shady are the trees? How many cloudy days?) and the installation. Sellers typically have access to software that provides historical production totals.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionAnnual/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionAnnualStatus', 'en', 'Power Production Annual Status', 'The most important metric of a renewables system is the amount of power it produces per year. This number can be actual, estimated or a combination of each if less than 12 months of actual data is available (any missing months of actual data is extrapolated). This field allows the status of the number shown in the PowerProducationAnnual field to be clarified.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionAnnualStatus/', 'https://dd.reso.org/DD2.0/lookups/PowerProductionAnnualStatus/', '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionKey', 'en', 'Power Production Key', 'A unique identifier for this record. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionOwnership', 'en', 'Power Production Ownership', 'The ownership of the power production system (e.g., Seller Owned or Third-Party Owned).', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionOwnership/', 'https://dd.reso.org/DD2.0/lookups/PowerProductionOwnership/', '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionSize', 'en', 'Power Production Size', 'The "capacity" of a renewables system. Size is measured in kilowatts (kW) DC (direct current). A kW indicates how much power the system can produce under standard conditions, like the size of a car engine. Renewables systems are sized when they are installed to cover all or a portion of the power needs of the property. Therefore, a system designed to produce 50% of the power needs will be sized smaller than a system on the exact same property designed to produce 100%. Size may be influenced by available space at the property, orientation, landscaping, etc.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionSize/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionType', 'en', 'Power Production Type', 'A list of the type of power production systems available on the property.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionType/', 'https://dd.reso.org/DD2.0/lookups/PowerProductionType/', '2.0', 'reso_official_csv'),
  ('PropertyPowerProduction.PowerProductionYearInstall', 'en', 'Power Production Year Install', 'The year a renewables system was installed. Ideally, this should be the year the system was interconnected with the grid and began producing power. Renewables systems have a limited lifespan, and recording the year a system was installed helps buyers and appraisers determine the remaining useful life of the system.', 'https://dd.reso.org/DD2.0/PropertyPowerProduction/PowerProductionYearInstall/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.DateOfInstallation', 'en', 'Date Of Installation', 'The date the power storage system was installed.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/DateOfInstallation/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.InformationSource', 'en', 'Information Source', 'The provider of the information about the power storage system.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/InformationSource/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the system representing the date/time the PropertyPowerStorage record was last modified.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.NameplateCapacity', 'en', 'Nameplate Capacity', 'The kWh the battery is theoretically able to store.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/NameplateCapacity/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.PowerStorageKey', 'en', 'Power Storage Key', 'A system unique identifier. Specifically, in aggregation systems, the PowerStorageKey is the system unique identifier from the system that the record was retrieved.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/PowerStorageKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyPowerStorage.PowerStorageType', 'en', 'Power Storage Type', 'The type of battery.', 'https://dd.reso.org/DD2.0/PropertyPowerStorage/PowerStorageType/', 'https://dd.reso.org/DD2.0/lookups/PowerStorageType/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.BedroomClosetType', 'en', 'Bedroom Closet Type', 'A list of possible closet types for a bedroom.', 'https://dd.reso.org/DD2.0/PropertyRooms/BedroomClosetType/', 'https://dd.reso.org/DD2.0/lookups/ClosetType/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.HistoryTransactional', 'en', 'History Transactional', 'The history of the PropertyRooms record.', 'https://dd.reso.org/DD2.0/PropertyRooms/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.Listing', 'en', 'Listing', 'The listing associated with the PropertyRooms record.', 'https://dd.reso.org/DD2.0/PropertyRooms/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.ListingId', 'en', 'Listing ID', 'This is the foreign ID relating to the Property Resource. The-well known identifier for the listing. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/PropertyRooms/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.ListingKey', 'en', 'Listing Key', 'This is the foreign key relating to the Property resource. A unique identifier for this record from the immediate source. A string that can include URI or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see the Property Resource''s SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/PropertyRooms/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the PropertyRooms record was last modified.', 'https://dd.reso.org/DD2.0/PropertyRooms/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomArea', 'en', 'Room Area', 'The area of the room being described. Use the RoomAreaUnits field to describe the unit of measurement for the value in this field.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomArea/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomAreaSource', 'en', 'Room Area Source', 'The source of the measurement of the given room''s area.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomAreaSource/', 'https://dd.reso.org/DD2.0/lookups/AreaSource/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomAreaUnits', 'en', 'Room Area Units', 'The unit of measurement used for the value in the RoomArea field (e.g., Square Feet, Square Meters).', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomAreaUnits/', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomDescription', 'en', 'Room Description', 'A textual description of the given room.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomDescription/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomDimensions', 'en', 'Room Dimensions', 'A textual description of the dimensions of the given room.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomDimensions/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomFeatures', 'en', 'Room Features', 'A list of features present in the given room.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomFeatures/', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomKey', 'en', 'Room Key', 'A unique identifier for this record. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomLength', 'en', 'Room Length', 'A numeric representation of the length of the given room. See the RoomLengthWidthUnits field for the unit of measurement used for the length and width.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomLength/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomLengthWidthSource', 'en', 'Room Length Width Source', 'The source of the measurement of the given units length and width.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomLengthWidthSource/', 'https://dd.reso.org/DD2.0/lookups/RoomLengthWidthSource/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomLengthWidthUnits', 'en', 'Room Length Width Units', 'The unit of measurement used for the value of RoomLength and RoomWidth fields (e.g., Feet, Meters).', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomLengthWidthUnits/', 'https://dd.reso.org/DD2.0/lookups/LinearUnits/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomLevel', 'en', 'Room Level', 'The level within the dwelling on which the given room is located.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomLevel/', 'https://dd.reso.org/DD2.0/lookups/RoomLevel/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomType', 'en', 'Room Type', 'The type of room being described by the other fields in the PropertyRooms resource.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomType/', 'https://dd.reso.org/DD2.0/lookups/RoomType/', '2.0', 'reso_official_csv'),
  ('PropertyRooms.RoomWidth', 'en', 'Room Width', 'A numeric representation of the width of a given room. See the RoomLengthWidthUnits field for the unit of measurement used for the length and width.', 'https://dd.reso.org/DD2.0/PropertyRooms/RoomWidth/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.HistoryTransactional', 'en', 'History Transactional', 'The history of the PropertyUnitTypes record.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.Listing', 'en', 'Listing', 'The listing associated with the PropertyUnitTypes record.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.ListingId', 'en', 'Listing ID', 'The foreign ID relating to the Property Resource; the well-known identifier for the listing. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.ListingKey', 'en', 'Listing Key', 'The foreign key relating to the Property Resource; a unique identifier for this record from the immediate source; a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see the Property Resource''s SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the PropertyUnitTypes record was last modified.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeActualRent', 'en', 'Unit Type Actual Rent', 'The actual rent per month being collected for a given type of unit.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeActualRent/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeBathsTotal', 'en', 'Unit Type Baths Total', 'The total number of baths for a given type of unit.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeBathsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeBedsTotal', 'en', 'Unit Type Beds Total', 'The total number of bedrooms for a given type of unit.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeBedsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeDescription', 'en', 'Unit Type Description', 'A textual description of a given type of unit.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeDescription/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeFurnished', 'en', 'Unit Type Furnished', 'The level of furnishing for a given type of unit (i.e., Furnished, Partial or Unfurnished).', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeFurnished/', 'https://dd.reso.org/DD2.0/lookups/Furnished/', '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeGarageAttachedYN', 'en', 'Unit Type Garage Attached Yes/No', 'Answers whether or not the given type of unit has an attached garage.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeGarageAttachedYN/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeGarageSpaces', 'en', 'Unit Type Garage Spaces', 'The number of garage spaces included with the given type of unit.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeGarageSpaces/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeKey', 'en', 'Unit Type Key', 'A unique identifier for this record. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeKey/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeProForma', 'en', 'Unit Type Pro Forma', 'The pro forma rent or the expected rental income from the given type of unit. This may vary from actual rent, which can be affected by factors other than current market value.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeProForma/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeTotalRent', 'en', 'Unit Type Total Rent', 'The total actual rent is the sum of all rent being collected for all units of the given type. For example, if you had five units of a particular type, each collecting $1,000, the total actual rent would be $5,000.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeTotalRent/', NULL, '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeType', 'en', 'Unit Type Type', 'A list of possible unit types (e.g., 1 Bedroom, 2 Bedroom, 3 Bedroom, Studio, Loft).', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeType/', 'https://dd.reso.org/DD2.0/lookups/UnitTypeType/', '2.0', 'reso_official_csv'),
  ('PropertyUnitTypes.UnitTypeUnitsTotal', 'en', 'Unit Type Units Total', 'The total number of units of the given type.', 'https://dd.reso.org/DD2.0/PropertyUnitTypes/UnitTypeUnitsTotal/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ActiveYN', 'en', 'Active Yes/No', 'If set to True, the given automated email is active. False records may be disabled or waiting activation.', 'https://dd.reso.org/DD2.0/Prospecting/ActiveYN/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.BccEmailList', 'en', 'BCC Email List', 'A comma-separated list of email addresses that are the blind carbon copy (Bcc) address that the automated emails are being sent to.', 'https://dd.reso.org/DD2.0/Prospecting/BccEmailList/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.BccMeYN', 'en', 'BCC Me Yes/No', 'When set to True, the automated mail is also sent as a blind carbon copy (Bcc) to the member who created the automated email.', 'https://dd.reso.org/DD2.0/Prospecting/BccMeYN/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.CcEmailList', 'en', 'CC Email List', 'A comma-separated list of email addresses that are the carbon copy (Cc) address that the automated emails are being sent to.', 'https://dd.reso.org/DD2.0/Prospecting/CcEmailList/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ClientActivatedYN', 'en', 'Client Activated Yes/No', 'If set to True, the client has clicked through to accept automatic emails. Recipient acceptance is an important part of CAN-SPAM and other automated bulk email regulations.', 'https://dd.reso.org/DD2.0/Prospecting/ClientActivatedYN/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ConciergeNotificationsYN', 'en', 'Concierge Notifications Yes/No', 'If set to True, notifications are to be sent to the member when the auto email is in Concierge mode.', 'https://dd.reso.org/DD2.0/Prospecting/ConciergeNotificationsYN/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ConciergeYN', 'en', 'Concierge Yes/No', 'When set to True, the automated mail is in Concierge mode and is to be approved by the member before being sent to the client.', 'https://dd.reso.org/DD2.0/Prospecting/ConciergeYN/', NULL, '2.0', 'reso_official_csv'),
