  ('Prospecting.DailySchedule', 'en', 'Daily Schedule', 'When Daily is selected as the ScheduleType, a list of days of the week and AM or PM options.', 'https://dd.reso.org/DD2.0/Prospecting/DailySchedule/', 'https://dd.reso.org/DD2.0/lookups/DailySchedule/', '2.0', 'reso_official_csv'),
