  ('Prospecting.LastNewChangedTimestamp', 'en', 'Last New Changed Timestamp', 'The timestamp of when the prospector last found new or modified listings for an automated email.', 'https://dd.reso.org/DD2.0/Prospecting/LastNewChangedTimestamp/', NULL, '2.0', 'reso_official_csv'),
