  ('Prospecting.MessageNew', 'en', 'Message New', 'The body of the automated email message when the first email is sent for the prospecting campaign.', 'https://dd.reso.org/DD2.0/Prospecting/MessageNew/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.MessageRevise', 'en', 'Message Revise', 'The body of the automated email message to be used when the criteria or settings of an automated email has been modified.', 'https://dd.reso.org/DD2.0/Prospecting/MessageRevise/', NULL, '2.0', 'reso_official_csv'),
