  ('Prospecting.OwnerMemberKey', 'en', 'Owner Member Key', 'The unique identifier (key) of the member owning the contact. This is a foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/Prospecting/OwnerMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ProspectingKey', 'en', 'Prospecting Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey variants.', 'https://dd.reso.org/DD2.0/Prospecting/ProspectingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Prospecting.ReasonActiveOrDisabled', 'en', 'Reason Active Or Disabled', 'A list of reasons the automated email was set to inactive or set back to active (e.g., Agent Disabled, Over Limit, No Listings Found, Reactivated, Client Disabled).', 'https://dd.reso.org/DD2.0/Prospecting/ReasonActiveOrDisabled/', 'https://dd.reso.org/DD2.0/lookups/ReasonActiveOrDisabled/', '2.0', 'reso_official_csv'),
