  ('Queue.OriginatingSystem', 'en', 'Originating System', 'The originating system of the Queue record.', 'https://dd.reso.org/DD2.0/Queue/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the queue record was generated. In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Queue/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the queue record was originally generated. The legal name of the company.', 'https://dd.reso.org/DD2.0/Queue/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.OriginatingSystemQueueKey', 'en', 'Originating System Queue Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the queue record was generated). There may be cases where the source system (how the record is received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/Queue/OriginatingSystemQueueKey/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.QueueTransactionKey', 'en', 'Queue Transaction Key', 'A unique identifier for this record from the immediate source. This may be a number, or string that can include Uniform Resource Identifier (URI) or other forms. This is the system you are connecting to and not necessarily the original source of the record.', 'https://dd.reso.org/DD2.0/Queue/QueueTransactionKey/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.QueueTransactionType', 'en', 'Queue Transaction Type', 'The type of change that the queue transaction record is representing (e.g., Add, Change, Delete).', 'https://dd.reso.org/DD2.0/Queue/QueueTransactionType/', 'https://dd.reso.org/DD2.0/lookups/QueueTransactionType/', '2.0', 'reso_official_csv'),
  ('Queue.ResourceName', 'en', 'Resource Name', 'The name of the resource which this queue record is referencing.', 'https://dd.reso.org/DD2.0/Queue/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('Queue.ResourceRecordID', 'en', 'Resource Record ID', 'The well-known identifier of the related record from the source resource. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/Queue/ResourceRecordID/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey). This is the system being connected to and is not necessarily the original source of the record. This is a foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/Queue/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.SourceSystem', 'en', 'Source System', 'The source system of the Queue record.', 'https://dd.reso.org/DD2.0/Queue/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Queue.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Queue/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
