  ('Rules.OriginatingSystem', 'en', 'Originating System', 'The originating system of the Rules record.', 'https://dd.reso.org/DD2.0/Rules/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the rule originated). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Rules/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider where the rule is originally input, which is the legal name of the company and most commonly the name of the MLS.', 'https://dd.reso.org/DD2.0/Rules/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.OriginatingSystemRuleKey', 'en', 'Originating System Rule Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the rule originated). There may be cases where the source system (how the record is received) is not the originating system. See Source System Rule Key for more information.', 'https://dd.reso.org/DD2.0/Rules/OriginatingSystemRuleKey/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.ResourceName', 'en', 'Resource Name', 'The resource to which the rule refers (e.g., Property, Member, Office, Open House, etc.).', 'https://dd.reso.org/DD2.0/Rules/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('Rules.RuleAction', 'en', 'Rule Action', 'The action to be taken when processing the rule.', 'https://dd.reso.org/DD2.0/Rules/RuleAction/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleDescription', 'en', 'Rule Description', 'A detailed textual description of the rule.', 'https://dd.reso.org/DD2.0/Rules/RuleDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleEnabledYN', 'en', 'Rule Enabled Yes/No', 'Is the rule currently enabled?', 'https://dd.reso.org/DD2.0/Rules/RuleEnabledYN/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleErrorText', 'en', 'Rule Error Text', 'Textual information conveyed when the given rule is in error or fails (e.g., the listing price must be greater than 0).', 'https://dd.reso.org/DD2.0/Rules/RuleErrorText/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleExpression', 'en', 'Rule Expression', 'The expression or details of the rule.', 'https://dd.reso.org/DD2.0/Rules/RuleExpression/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleFormat', 'en', 'Rule Format', 'The format of the rule (e.g., $filter, JavaScript, REBR).', 'https://dd.reso.org/DD2.0/Rules/RuleFormat/', 'https://dd.reso.org/DD2.0/lookups/RuleFormat/', '2.0', 'reso_official_csv'),
  ('Rules.RuleHelpText', 'en', 'Rule Help Text', 'The text that might be displayed on a form that helps the user fix the rule (e.g., enter phone number in the following 10-digit format: ###-###-####).', 'https://dd.reso.org/DD2.0/Rules/RuleHelpText/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleKey', 'en', 'Rule Key', 'The primary key of the individual Rule record.', 'https://dd.reso.org/DD2.0/Rules/RuleKey/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleName', 'en', 'Rule Name', 'A descriptive name for the rule.', 'https://dd.reso.org/DD2.0/Rules/RuleName/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleOrder', 'en', 'Rule Order', 'When in use, execution of rules are to follow the order specified by this field. Any rule that references another field will need to be ordered.', 'https://dd.reso.org/DD2.0/Rules/RuleOrder/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleType', 'en', 'Rule Type', 'The type of rule (e.g., Validation, Required, Warning, etc.).', 'https://dd.reso.org/DD2.0/Rules/RuleType/', 'https://dd.reso.org/DD2.0/lookups/RuleType/', '2.0', 'reso_official_csv'),
  ('Rules.RuleVersion', 'en', 'Rule Version', 'A rule version that uses semantic versioning. See https://semver.org/.', 'https://dd.reso.org/DD2.0/Rules/RuleVersion/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.RuleWarningText', 'en', 'Rule Warning Text', 'Textual information conveyed when a given rule has met a condition that warrants a warning message (e.g., sale price entered differs from listing price by more than 25%).', 'https://dd.reso.org/DD2.0/Rules/RuleWarningText/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.SourceSystem', 'en', 'Source System', 'The source system of the Rules record.', 'https://dd.reso.org/DD2.0/Rules/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.SourceSystemHistoryKey', 'en', 'Source System History Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Rules/SourceSystemHistoryKey/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Rules/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Rules.SourceSystemName', 'en', 'Source System Name', 'The name of the rule record provider, that being the system from which the record was directly received and the legal name of the company.', 'https://dd.reso.org/DD2.0/Rules/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.ClassName', 'en', 'Class Name', 'The class or table to which the SearchQuery criteria refers (e.g., Residential, Residential Lease, Residential Income, Commercial Sale).', 'https://dd.reso.org/DD2.0/SavedSearch/ClassName/', 'https://dd.reso.org/DD2.0/lookups/ClassName/', '2.0', 'reso_official_csv'),
  ('SavedSearch.HistoryTransactional', 'en', 'History Transactional', 'The collection history items related to the SavedSearch record.', 'https://dd.reso.org/DD2.0/SavedSearch/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.Member', 'en', 'Member', 'The member associated with the saved search.', 'https://dd.reso.org/DD2.0/SavedSearch/Member/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.MemberKey', 'en', 'Member Key', 'A system unique identifier. Specifically, in aggregation systems, the MemberKey is the system unique identifier from the system that the record was retrieved. This may be identical to the related xxxId. This is a foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/SavedSearch/MemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.MemberMlsId', 'en', 'Member MLS ID', 'The local, well-known identifier for the member. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/SavedSearch/MemberMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time that the saved search was last modified.', 'https://dd.reso.org/DD2.0/SavedSearch/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'The transactional timestamp automatically recorded by the MLS system representing the date/time that the saved search was entered.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystem', 'en', 'Originating System', 'The originating system of the SavedSearch record.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the MLS where the saved search was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the saved search was input). There may be cases where the source system (how the record was received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystemMemberKey', 'en', 'Originating System Member Key', 'Unique identifier from the originating system, which is commonly a key to that system. In the case where data is passed through more than one system, this is the originating system key. This is a foreign key relating to the system where this record was originated.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystemMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystemMemberName', 'en', 'Originating System Member Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company to be used for display.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystemMemberName/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the saved search is originally input. The legal name of the company.', 'https://dd.reso.org/DD2.0/SavedSearch/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.ResourceName', 'en', 'Resource Name', 'The resource to which the SearchQuery criteria refers (e.g., Property, OpenHouse, Agent, Office, Contacts).', 'https://dd.reso.org/DD2.0/SavedSearch/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('SavedSearch.SavedSearchDescription', 'en', 'Saved Search Description', 'A textual description of the saved search input by the member who created the saved search.', 'https://dd.reso.org/DD2.0/SavedSearch/SavedSearchDescription/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SavedSearchKey', 'en', 'Saved Search Key', 'A unique identifier for this record from the immediate source. This may be a number or string that can include a Uniform Resource Identifier (URI) or other forms. This is the system being connected to and not necessarily the original source of the record.', 'https://dd.reso.org/DD2.0/SavedSearch/SavedSearchKey/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SavedSearchName', 'en', 'Saved Search Name', 'The name given to the search by the member inputting the saved search.', 'https://dd.reso.org/DD2.0/SavedSearch/SavedSearchName/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SavedSearchType', 'en', 'Saved Search Type', 'Determines if the saved search used to pass criteria is to be stored and executed by the client or if it is a key to be passed to the host for execution (i.e., Client Receives Criteria, Host Returns Listings). May be described at the record level with this field or at some other level of implementation to be determined by the RESO Research & Development Workgroup.', 'https://dd.reso.org/DD2.0/SavedSearch/SavedSearchType/', 'https://dd.reso.org/DD2.0/lookups/SavedSearchType/', '2.0', 'reso_official_csv'),
  ('SavedSearch.SearchQuery', 'en', 'Search Query', 'The textual representation of the search performed by the member that was saved. It is required to present in the OData $filter format. Additional formats are under review. See additional documentation for specific requirements for this field.', 'https://dd.reso.org/DD2.0/SavedSearch/SearchQuery/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SearchQueryExceptionDetails', 'en', 'Search Query Exception Details', 'A free-text description used to expand on the SearchQueryExceptions selections made by the host.', 'https://dd.reso.org/DD2.0/SavedSearch/SearchQueryExceptionDetails/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SearchQueryExceptions', 'en', 'Search Query Exceptions', 'A list of exceptions or errors with the given search query during its creation by the host. Analogous to an error code, this is the host''s opportunity to describe an inability to fully express a saved search under the constraints of the given protocol (i.e., $filter). The client may use this information to bring attention to the user about a given saved search and a need to review or recreate the search.', 'https://dd.reso.org/DD2.0/SavedSearch/SearchQueryExceptions/', 'https://dd.reso.org/DD2.0/lookups/SearchQueryExceptions/', '2.0', 'reso_official_csv'),
  ('SavedSearch.SearchQueryHumanReadable', 'en', 'Search Query Human Readable', 'A human readable version of the search query that is commonly used for display and may not contain all actual criteria. For actual search criteria, use the SearchQuery field.', 'https://dd.reso.org/DD2.0/SavedSearch/SearchQueryHumanReadable/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SearchQueryType', 'en', 'Search Query Type', 'A pick list of the type of query language used in the SearchQuery field (e.g., DMQL2, $filter).', 'https://dd.reso.org/DD2.0/SavedSearch/SearchQueryType/', 'https://dd.reso.org/DD2.0/lookups/SearchQueryType/', '2.0', 'reso_official_csv'),
  ('SavedSearch.SourceSystem', 'en', 'Source System', 'The source system of the SavedSearch record.', 'https://dd.reso.org/DD2.0/SavedSearch/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/SavedSearch/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/SavedSearch/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('SavedSearch.SourceSystemName', 'en', 'Source System Name', 'The name of the record provider of the saved search. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/SavedSearch/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentOriginatingSystem', 'en', 'Agent Originating System', 'The originating system of the member associated with the showing.', 'https://dd.reso.org/DD2.0/Showing/AgentOriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentOriginatingSystemID', 'en', 'Agent Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record was retrieved, see the Source System fields.', 'https://dd.reso.org/DD2.0/Showing/AgentOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentOriginatingSystemName', 'en', 'Agent Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company. In cases where the originating system was not where the record was retrieved, see the Source System fields.', 'https://dd.reso.org/DD2.0/Showing/AgentOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentSourceSystem', 'en', 'Agent Source System', 'The source system of the member associated with the showing.', 'https://dd.reso.org/DD2.0/Showing/AgentSourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentSourceSystemID', 'en', 'Agent Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/AgentSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.AgentSourceSystemName', 'en', 'Agent Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/AgentSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.HistoryTransactional', 'en', 'History Transactional', 'The history of the Showing record.', 'https://dd.reso.org/DD2.0/Showing/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.Listing', 'en', 'Listing', 'The listing associated with the showing.', 'https://dd.reso.org/DD2.0/Showing/Listing/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingId', 'en', 'Listing ID', 'The well-known identifier for the listing being shown. The value may be identical to that of the listing key, but the listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/Showing/ListingId/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingKey', 'en', 'Listing Key', 'A unique identifier for this record. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/Showing/ListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingOriginatingSystem', 'en', 'Listing Originating System', 'The originating system of the Listing record associated with the showing.', 'https://dd.reso.org/DD2.0/Showing/ListingOriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingOriginatingSystemID', 'en', 'Listing Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record was retrieved, see the Source System fields.', 'https://dd.reso.org/DD2.0/Showing/ListingOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingOriginatingSystemName', 'en', 'Listing Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company. In cases where the originating system was not where the record was retrieved, see the Source System fields.', 'https://dd.reso.org/DD2.0/Showing/ListingOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingSourceSystem', 'en', 'Listing Source System', 'The source system of the Listing record associated with the showing.', 'https://dd.reso.org/DD2.0/Showing/ListingSourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingSourceSystemID', 'en', 'Listing Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/ListingSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ListingSourceSystemName', 'en', 'Listing Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/ListingSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.Media', 'en', 'Media', 'The media associated with the Showing record.', 'https://dd.reso.org/DD2.0/Showing/Media/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the system representing the date/time the Showing record was last modified.', 'https://dd.reso.org/DD2.0/Showing/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'The transactional timestamp automatically recorded by the system representing the date/time the showing record was entered and made visible to members of the system.', 'https://dd.reso.org/DD2.0/Showing/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.OriginatingSystemAgentKey', 'en', 'Originating System Agent Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the showing service in which the member was input). There may be cases where the source system (how the record is received) is not the originating system. See SourceSystemAgentKey for more information.', 'https://dd.reso.org/DD2.0/Showing/OriginatingSystemAgentKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.OriginatingSystemListingKey', 'en', 'Originating System Listing Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the member was input). There may be cases where the source system (how the record is received) is not the originating system. See SourceSystemKey for more information.', 'https://dd.reso.org/DD2.0/Showing/OriginatingSystemListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.OriginatingSystemShowingKey', 'en', 'Originating System Showing Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the member was input). There may be cases where the source system (how the record is received) is not the originating system. See SourceSystemKey fields for more information.', 'https://dd.reso.org/DD2.0/Showing/OriginatingSystemShowingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingAgent', 'en', 'Showing Agent', 'The showing agent.', 'https://dd.reso.org/DD2.0/Showing/ShowingAgent/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingAgentKey', 'en', 'Showing Agent Key', 'A system unique identifier of the member who has scheduled to access the property. Specifically, in aggregation systems, the ListAgentKey is the system unique identifier from the system where the record was retrieved. This may be identical to the related xxxId. This is a foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/Showing/ShowingAgentKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingAgentMlsID', 'en', 'Showing Agent MLS ID', 'The local, well-known identifier for the member who has scheduled to access the property, most commonly representing a buyer. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/Showing/ShowingAgentMlsID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingAllowed', 'en', 'Showings Allowed', 'The main Y/N field to denote whether showings are allowed to be requested at this time. There may be future showings previously scheduled.', 'https://dd.reso.org/DD2.0/Showing/ShowingAllowed/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingEndTimestamp', 'en', 'Showing End Timestamp', 'The date and time the showing ends. Where other timestamps are typically stored in Coordinated Universal Time (UTC), showing start and end date/times are typically stored in the local time zone of the property being showed.', 'https://dd.reso.org/DD2.0/Showing/ShowingEndTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingId', 'en', 'Showing ID', 'The well-known identifier for the Showing record. The value may be identical to that of the ShowingKey, but the ShowingID is intended to be the value used by a human to retrieve the information about a specific showing. In a multiple-originating system or a merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/Showing/ShowingId/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingKey', 'en', 'Showing Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemShowingKey and OriginatingSystemShowingKey.', 'https://dd.reso.org/DD2.0/Showing/ShowingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingOriginatingSystem', 'en', 'Showing Originating System', 'The originating system of the Showing record.', 'https://dd.reso.org/DD2.0/Showing/ShowingOriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingOriginatingSystemID', 'en', 'Showing Originating System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the listing was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/ShowingOriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingOriginatingSystemName', 'en', 'Showing Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the listing is originally input by the member. The legal name of the company.', 'https://dd.reso.org/DD2.0/Showing/ShowingOriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingRequestedTimestamp', 'en', 'Showing Requested Timestamp', 'The date/time when the showing agent submitted a request to access the property. This is a system timestamp normally generated by a showing system, which is commonly the originating system for showing records.', 'https://dd.reso.org/DD2.0/Showing/ShowingRequestedTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingSourceSystem', 'en', 'Showing Source System', 'The source system of the Showing record.', 'https://dd.reso.org/DD2.0/Showing/ShowingSourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingSourceSystemID', 'en', 'Showing Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/ShowingSourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingSourceSystemName', 'en', 'Showing Source System Name', 'The name of the immediate record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Showing/ShowingSourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingStartTimestamp', 'en', 'Showing Start Timestamp', 'The date and time the showing begins. Where other timestamps are typically stored in Coordinated Universal Time (UTC), showing start and end date/times are typically stored in the local time zone of the property being showed.', 'https://dd.reso.org/DD2.0/Showing/ShowingStartTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.ShowingStatus', 'en', 'Showing Status', 'The current state of showing acceptance on the listing.', 'https://dd.reso.org/DD2.0/Showing/ShowingStatus/', 'https://dd.reso.org/DD2.0/lookups/ShowingStatus/', '2.0', 'reso_official_csv'),
  ('Showing.ShowingTimeZone', 'en', 'Showing Time Zone', 'The standard name of the time zone, as provided by the IANA tz database. This denotes the time zone of the property being shown.', 'https://dd.reso.org/DD2.0/Showing/ShowingTimeZone/', 'https://dd.reso.org/DD2.0/lookups/IanaTimeZoneValues/', '2.0', 'reso_official_csv'),
  ('Showing.ShowingUrl', 'en', 'Showing Deep Link URL', 'The Uniform Resource Locator (URL) that links to the originating system.', 'https://dd.reso.org/DD2.0/Showing/ShowingUrl/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.SocialMedia', 'en', 'Social Media', 'The social media associated with the Showing record.', 'https://dd.reso.org/DD2.0/Showing/SocialMedia/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.SourceSystemAgentKey', 'en', 'Source System Agent Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/SourceSystemAgentKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.SourceSystemListingKey', 'en', 'Source System Listing Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/SourceSystemListingKey/', NULL, '2.0', 'reso_official_csv'),
  ('Showing.SourceSystemShowingKey', 'en', 'Source System Showing Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Showing/SourceSystemShowingKey/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ModificationTimestamp', 'en', 'Modification Timestamp', 'The transactional timestamp automatically recorded by the system representing the date/time the ShowingAppointment record was last modified.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAgentKey', 'en', 'Showing Agent Key', 'A system unique identifier of the member who has scheduled to access the property. Specifically, in aggregation systems, the ListAgentKey is the system unique identifier from the system in which the record was retrieved. This may be identical to the related xxxId and is a foreign key relating to the Member Key of the Member Resource.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAgentKey/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAgentMlsId', 'en', 'Showing Agent MLS ID', 'The local, well-known identifier for the member who has scheduled to access the property, most commonly representing a buyer. This value may not be unique. Specifically, in the case of aggregation systems, this value should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAgentMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentDate', 'en', 'Showing Appointment Date', 'The date of the showing appointment.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentDate/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentEndTime', 'en', 'Showing Appointment End Time', 'The local end time of the showing appointment. The locale is defined by the showing.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentEndTime/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentId', 'en', 'Showing Appointment ID', 'The ID assigned to a requested appointment.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentId/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentKey', 'en', 'Showing Appointment Key', 'A system unique identifier. Specifically, the local key to the ShowingAppointment resource.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentKey/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentMethod', 'en', 'Showing Appointment Method', 'The method of showing (i.e., in-person, virtual, etc.) confirmed for the property.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentMethod/', 'https://dd.reso.org/DD2.0/lookups/ShowingAppointmentMethod/', '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentStartTime', 'en', 'Showing Appointment Start Time', 'The local start time of the showing appointment. The locale is defined by the showing.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentStartTime/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingAppointmentStatus', 'en', 'Showing Appointment Status', 'The status of the requested showing appointment.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingAppointmentStatus/', 'https://dd.reso.org/DD2.0/lookups/ShowingAppointmentStatus/', '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingId', 'en', 'Showing ID', 'The well-known identifier for the showing record. The value may be identical to that of the ShowingKey, but the ShowingId is intended to be the value used by a human to retrieve the information about a specific showing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingId/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAppointment.ShowingKey', 'en', 'Showing Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/ShowingAppointment/ShowingKey/', NULL, '2.0', 'reso_official_csv'),
