  ('ShowingAvailability.ShowingMethod', 'en', 'Showing Method', 'The type of showings (i.e., in-person, virtual, etc.) allowed for the property.', 'https://dd.reso.org/DD2.0/ShowingAvailability/ShowingMethod/', 'https://dd.reso.org/DD2.0/lookups/ShowingMethod/', '2.0', 'reso_official_csv'),
