  ('ShowingAvailability.UniqueOrganizationIdentifier', 'en', 'Unique Organization Identifier', 'This is the unique ID assigned to organizations included in the OUID Resource. Assignment of Unique Organization Identifiers (UOIs) will be centralized and may not be created by systems hosting the OUID Resource.', 'https://dd.reso.org/DD2.0/ShowingAvailability/UniqueOrganizationIdentifier/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingAvailability.UniversalPropertyId', 'en', 'Universal Property ID', 'The Universal Property Identifier (UPI) is a unique identifier based on country and local identification methods for all real property in the U.S. and Canada. For cases such as shares of real property, units and other more granular cases, please utilize the UniversalPropertySubId.', 'https://dd.reso.org/DD2.0/ShowingAvailability/UniversalPropertyId/', NULL, '2.0', 'reso_official_csv'),
