  ('ShowingRequest.ShowingKey', 'en', 'Showing Key', 'A unique identifier for this record from the immediate source. This is a string that can include a Uniform Resource Identifier (URI) or other forms. This is the local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingKey/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingRequest.ShowingMethodRequest', 'en', 'Showing Method Request', 'The method of showing (i.e., in-person, virtual, etc.) requested for the property.', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingMethodRequest/', 'https://dd.reso.org/DD2.0/lookups/ShowingMethodRequest/', '2.0', 'reso_official_csv'),
