  ('ShowingRequest.ShowingRequestEndTime', 'en', 'Showing Request End Time', 'The local end time of the showing request. The locale is defined by the showing.', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingRequestEndTime/', NULL, '2.0', 'reso_official_csv'),
  ('ShowingRequest.ShowingRequestId', 'en', 'Showing Request ID', 'The requestor''s unique ID attached to the request.', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingRequestId/', NULL, '2.0', 'reso_official_csv'),
