  ('ShowingRequest.ShowingRequestType', 'en', 'Showing Request Type', 'The type of showing being requested (e.g., first, second, broker preview, broker price opinion, inspection).', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingRequestType/', 'https://dd.reso.org/DD2.0/lookups/ShowingRequestType/', '2.0', 'reso_official_csv'),
  ('ShowingRequest.ShowingRequestedDate', 'en', 'Showing Requested Date', 'The date when the showing was requested.', 'https://dd.reso.org/DD2.0/ShowingRequest/ShowingRequestedDate/', NULL, '2.0', 'reso_official_csv'),
