  ('SocialMedia.ResourceName', 'en', 'Resource Name', 'The resource or table of the listing or other record that the media relates to (i.e., Property, Member, Office, etc.).', 'https://dd.reso.org/DD2.0/SocialMedia/ResourceName/', 'https://dd.reso.org/DD2.0/lookups/ResourceName/', '2.0', 'reso_official_csv'),
  ('SocialMedia.ResourceRecordID', 'en', 'Resource Record ID', 'The well-known identifier of the related record from the source resource. The value may be identical to that of the Listing Key, but the Listing ID is intended to be the value used by a human to retrieve the information about a specific listing. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/SocialMedia/ResourceRecordID/', NULL, '2.0', 'reso_official_csv'),
  ('SocialMedia.ResourceRecordKey', 'en', 'Resource Record Key', 'The primary key of the related record from the source resource (e.g., ListingKey, AgentKey, OfficeKey, TeamKey). The system being connected to, not necessarily the original source of the record. A foreign key from the resource selected in the ResourceName field.', 'https://dd.reso.org/DD2.0/SocialMedia/ResourceRecordKey/', NULL, '2.0', 'reso_official_csv'),
  ('SocialMedia.SocialMediaKey', 'en', 'Social Media Key', 'A system unique identifier. Specifically, in aggregation systems, the key is the system unique identifier from the system that the record was just retrieved. This may be identical to the related xxxId identifier, but the key is guaranteed unique for this record set.', 'https://dd.reso.org/DD2.0/SocialMedia/SocialMediaKey/', NULL, '2.0', 'reso_official_csv'),
  ('SocialMedia.SocialMediaType', 'en', 'Social Media Type', 'A list of types of sites or social media that a member Uniform Resource Locator (URL) or ID is referring to (e.g., Website, Blog, Facebook, Twitter, LinkedIn, Instagram).', 'https://dd.reso.org/DD2.0/SocialMedia/SocialMediaType/', 'https://dd.reso.org/DD2.0/lookups/SocialMediaType/', '2.0', 'reso_official_csv'),
