  ('TeamMembers.HistoryTransactional', 'en', 'History Transactional', 'The history of the TeamMembers record.', 'https://dd.reso.org/DD2.0/TeamMembers/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
