  ('TeamMembers.MemberKey', 'en', 'Member Key', 'A system unique identifier. Specifically, the foreign key relating to the Member Resource''s MemberKey.', 'https://dd.reso.org/DD2.0/TeamMembers/MemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.MemberLoginId', 'en', 'Member Login ID', 'The ID used to log on to the MLS system.', 'https://dd.reso.org/DD2.0/TeamMembers/MemberLoginId/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.MemberMlsId', 'en', 'Member MLS ID', 'The local, well-known identifier for the member. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/TeamMembers/MemberMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the roster (member or office) record was last modified.', 'https://dd.reso.org/DD2.0/TeamMembers/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'Date/time the roster (member or office) record was originally input into the source system.', 'https://dd.reso.org/DD2.0/TeamMembers/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
