  ('TeamMembers.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the team member was input). There may be cases where the source system (how the record is received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/TeamMembers/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the team member is originally input. The legal name of the company.', 'https://dd.reso.org/DD2.0/TeamMembers/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.SourceSystem', 'en', 'Source System', 'The source system of the TeamMembers record.', 'https://dd.reso.org/DD2.0/TeamMembers/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/TeamMembers/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/TeamMembers/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.SourceSystemName', 'en', 'Source System Name', 'The name of the team member record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/TeamMembers/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.TeamImpersonationLevel', 'en', 'Team Impersonation Level', 'The level of impersonation the member is allowed within the team (i.e., Impersonate (to work as the team), On Behalf (to show the team name but also show the member''s info), None (don''t allow this member to appear as part of team)).', 'https://dd.reso.org/DD2.0/TeamMembers/TeamImpersonationLevel/', 'https://dd.reso.org/DD2.0/lookups/TeamImpersonationLevel/', '2.0', 'reso_official_csv'),
