  ('TeamMembers.TeamMemberKey', 'en', 'Team Member Key', 'A system unique identifier. Specifically, the local key to the TeamMembers resource.', 'https://dd.reso.org/DD2.0/TeamMembers/TeamMemberKey/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.TeamMemberNationalAssociationId', 'en', 'Team Member National Association ID', 'The national association ID of the member (e.g., in the U.S., this is an M1 or NRDS number).', 'https://dd.reso.org/DD2.0/TeamMembers/TeamMemberNationalAssociationId/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.TeamMemberStateLicense', 'en', 'Team Member State License', 'The license of the member. Multiple licenses should be separated with a comma and space.', 'https://dd.reso.org/DD2.0/TeamMembers/TeamMemberStateLicense/', NULL, '2.0', 'reso_official_csv'),
  ('TeamMembers.TeamMemberType', 'en', 'Team Member Type', 'The role of the member within the team (e.g., Team Lead, Showing Agent, Buyer Agent).', 'https://dd.reso.org/DD2.0/TeamMembers/TeamMemberType/', 'https://dd.reso.org/DD2.0/lookups/TeamMemberType/', '2.0', 'reso_official_csv'),
  ('Teams.HistoryTransactional', 'en', 'History Transactional', 'The history of the Teams record.', 'https://dd.reso.org/DD2.0/Teams/HistoryTransactional/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.Media', 'en', 'Media', 'The media associated with the Teams record.', 'https://dd.reso.org/DD2.0/Teams/Media/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the roster (team or office) record was last modified.', 'https://dd.reso.org/DD2.0/Teams/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.OriginalEntryTimestamp', 'en', 'Original Entry Timestamp', 'The date/time the roster (team or office) record was originally input into the source system.', 'https://dd.reso.org/DD2.0/Teams/OriginalEntryTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.OriginatingSystem', 'en', 'Originating System', 'The originating system of the Teams record.', 'https://dd.reso.org/DD2.0/Teams/OriginatingSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.OriginatingSystemID', 'en', 'Originating System ID', 'The RESO Unique Organization Identifier''s (UOI) OrganizationUniqueId of the originating record provider. The originating system is the system with authoritative control over the record (e.g., the name of the MLS where the team was input). In cases where the originating system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Teams/OriginatingSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.OriginatingSystemKey', 'en', 'Originating System Key', 'The system key, a unique record identifier, from the originating system. The originating system is the system with authoritative control over the record (e.g., the MLS where the team was input). There may be cases where the source system (how the record is received) is not the originating system. See Source System Key for more information.', 'https://dd.reso.org/DD2.0/Teams/OriginatingSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.OriginatingSystemName', 'en', 'Originating System Name', 'The name of the originating record provider, most commonly the name of the MLS. The place where the team is originally input. The legal name of the company.', 'https://dd.reso.org/DD2.0/Teams/OriginatingSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.SocialMediaType', 'en', 'Social Media Type', 'A list of types of sites or social media that the team Uniform Resource Locator (URL) or ID is referring to (e.g., website, blog, Facebook, Twitter, LinkedIn, Instagram).', 'https://dd.reso.org/DD2.0/Teams/SocialMediaType/', 'https://dd.reso.org/DD2.0/lookups/SocialMediaType/', '2.0', 'reso_official_csv'),
  ('Teams.SourceSystem', 'en', 'Source System', 'The source system of the Teams record.', 'https://dd.reso.org/DD2.0/Teams/SourceSystem/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.SourceSystemID', 'en', 'Source System ID', 'The RESO Unique Organization Identifier''s (UOI) OrganizationUniqueId of the source record provider. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Teams/SourceSystemID/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.SourceSystemKey', 'en', 'Source System Key', 'The system key, a unique record identifier, from the source system. The source system is the system from which the record was directly received. In cases where the source system was not where the record originated (the authoritative system), see the Originating System fields.', 'https://dd.reso.org/DD2.0/Teams/SourceSystemKey/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.SourceSystemName', 'en', 'Source System Name', 'The name of the team record provider. The system from which the record was directly received. The legal name of the company.', 'https://dd.reso.org/DD2.0/Teams/SourceSystemName/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamAddress1', 'en', 'Team Address 1', 'The street number, direction, name and suffix of the team.', 'https://dd.reso.org/DD2.0/Teams/TeamAddress1/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamAddress2', 'en', 'Team Address 2', 'The unit/suite number of the team.', 'https://dd.reso.org/DD2.0/Teams/TeamAddress2/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamCarrierRoute', 'en', 'Team Carrier Route', 'The group of addresses to which the U.S. Postal Service (USPS) assigns the same code to aid in mail delivery. For the USPS, these codes are 9 digits: 5 numbers for the ZIP Code, one letter for the carrier route type, and 3 numbers for the carrier route number.', 'https://dd.reso.org/DD2.0/Teams/TeamCarrierRoute/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamCity', 'en', 'Team City', 'The city of the team.', 'https://dd.reso.org/DD2.0/Teams/TeamCity/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamCountry', 'en', 'Team Country', 'The country abbreviation in a postal address.', 'https://dd.reso.org/DD2.0/Teams/TeamCountry/', 'https://dd.reso.org/DD2.0/lookups/Country/', '2.0', 'reso_official_csv'),
  ('Teams.TeamCountyOrParish', 'en', 'Team County Or Parish', 'The county or parish in which the team is addressed.', 'https://dd.reso.org/DD2.0/Teams/TeamCountyOrParish/', 'https://dd.reso.org/DD2.0/lookups/CountyOrParish/', '2.0', 'reso_official_csv'),
  ('Teams.TeamDescription', 'en', 'Team Description', 'A description or marketing information about the team.', 'https://dd.reso.org/DD2.0/Teams/TeamDescription/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamDirectPhone', 'en', 'Team Direct Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamDirectPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamEmail', 'en', 'Team Email', 'The email address of the team.', 'https://dd.reso.org/DD2.0/Teams/TeamEmail/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamFax', 'en', 'Team Fax', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamFax/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamKey', 'en', 'Team Key', 'A system unique identifier. Specifically, in aggregation systems, the TeamKey is the system unique identifier from the system where the record was retrieved.', 'https://dd.reso.org/DD2.0/Teams/TeamKey/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLead', 'en', 'Team Lead', 'The team lead for the given team.', 'https://dd.reso.org/DD2.0/Teams/TeamLead/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadKey', 'en', 'Team Lead Key', 'The unique system identifier of the team''s lead member.', 'https://dd.reso.org/DD2.0/Teams/TeamLeadKey/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadLoginId', 'en', 'Team Lead Login ID', 'The ID used to log on to the MLS system.', 'https://dd.reso.org/DD2.0/Teams/TeamLeadLoginId/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadMlsId', 'en', 'Team Lead MLS ID', 'The local, well-known identifier for the team lead. This value may not be unique, specifically in the case of aggregation systems, and it should be the identifier from the original system.', 'https://dd.reso.org/DD2.0/Teams/TeamLeadMlsId/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadNationalAssociationId', 'en', 'Team Lead National Association ID', 'The national association ID of the team lead (i.e., NRDS number in the U.S.).', 'https://dd.reso.org/DD2.0/Teams/TeamLeadNationalAssociationId/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadStateLicense', 'en', 'Team Lead State License', 'The license of the team lead. Multiple licenses should be separated with a comma and space.', 'https://dd.reso.org/DD2.0/Teams/TeamLeadStateLicense/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamLeadStateLicenseState', 'en', 'Team Lead State License State', 'The state in which the team lead is licensed.', 'https://dd.reso.org/DD2.0/Teams/TeamLeadStateLicenseState/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('Teams.TeamMobilePhone', 'en', 'Team Mobile Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamMobilePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamName', 'en', 'Team Name', 'The name under which the team operates. If a business, this may be a DBA (doing business as).', 'https://dd.reso.org/DD2.0/Teams/TeamName/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamOfficePhone', 'en', 'Team Office Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamOfficePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamOfficePhoneExt', 'en', 'Team Office Phone Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Teams/TeamOfficePhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamPostalCode', 'en', 'Team Postal Code', 'The postal code of the team.', 'https://dd.reso.org/DD2.0/Teams/TeamPostalCode/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamPostalCodePlus4', 'en', 'Team Postal Code Plus 4', 'The four-digit extension of the U.S. Zip Code.', 'https://dd.reso.org/DD2.0/Teams/TeamPostalCodePlus4/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamPreferredPhone', 'en', 'Team Preferred Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamPreferredPhone/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamPreferredPhoneExt', 'en', 'Team Preferred Phone Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Teams/TeamPreferredPhoneExt/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamStateOrProvince', 'en', 'Team State Or Province', 'The state or province in which the team is addressed.', 'https://dd.reso.org/DD2.0/Teams/TeamStateOrProvince/', 'https://dd.reso.org/DD2.0/lookups/StateOrProvince/', '2.0', 'reso_official_csv'),
  ('Teams.TeamStatus', 'en', 'Team Status', 'Determines whether the account is active, inactive or under disciplinary action.', 'https://dd.reso.org/DD2.0/Teams/TeamStatus/', 'https://dd.reso.org/DD2.0/lookups/TeamStatus/', '2.0', 'reso_official_csv'),
  ('Teams.TeamTollFreePhone', 'en', 'Team Toll Free Phone', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamTollFreePhone/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamVoiceMail', 'en', 'Team Voice Mail', 'North American 10-digit phone numbers should be in the format of ###-###-#### (separated by hyphens). Other conventions should use the common local standard. International numbers should be preceded by a plus symbol.', 'https://dd.reso.org/DD2.0/Teams/TeamVoiceMail/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamVoiceMailExt', 'en', 'Team Voice Mail Ext', 'The extension of the given phone number, if applicable.', 'https://dd.reso.org/DD2.0/Teams/TeamVoiceMailExt/', NULL, '2.0', 'reso_official_csv'),
  ('Teams.TeamsSocialMedia', 'en', 'Teams Social Media', 'A collection of the types of social media fields available for this team. The collection includes the type of system and other details pertinent about social media', 'https://dd.reso.org/DD2.0/Teams/TeamsSocialMedia/', NULL, '2.0', 'reso_official_csv'),
  ('TransactionManagement.ModificationTimestamp', 'en', 'Modification Timestamp', 'The date/time the TransactionManagement record was last modified.', 'https://dd.reso.org/DD2.0/TransactionManagement/ModificationTimestamp/', NULL, '2.0', 'reso_official_csv'),
  ('TransactionManagement.TransactionId', 'en', 'Transaction ID', 'The well-known identifier for the transaction record. The value may be identical to that of the TransactionKey, but the TransactionId is intended to be the value used by a human to retrieve the information about a specific transaction. In a multiple-originating or merged system, this value may not be unique and may require the use of the provider system to create a synthetic unique value.', 'https://dd.reso.org/DD2.0/TransactionManagement/TransactionId/', NULL, '2.0', 'reso_official_csv'),
  ('TransactionManagement.TransactionKey', 'en', 'Transaction Key', 'A unique identifier for this record from the immediate source. A string that can include a Uniform Resource Identifier (URI) or other forms. Alternatively, use the TransactionKeyNumeric for a numeric-only key field. The local key of the system. When records are received from other systems, a local key is commonly applied. If conveying the original keys from the source or originating systems, see SourceSystemKey and OriginatingSystemKey.', 'https://dd.reso.org/DD2.0/TransactionManagement/TransactionKey/', NULL, '2.0', 'reso_official_csv'),
  ('TransactionManagement.TransactionType', 'en', 'Transaction Type', 'A list of types of transactions (e.g., Listing for Sale, Listing for Lease, Other).', 'https://dd.reso.org/DD2.0/TransactionManagement/TransactionType/', 'https://dd.reso.org/DD2.0/lookups/TransactionType/', '2.0', 'reso_official_csv')
INSERT INTO public.reso_lookup_value_descriptions
  (lookup_name, standard_value, locale, display_value, definition, wiki_url, dd_version, source)
VALUES
  ('AccessibilityFeatures', 'Accessible Approach with Ramp', 'en', 'Accessible Approach with Ramp', 'A minimum of one entrance to the structure with a clear, evenly paved walkway from a parking or pedestrian arrival area. The path of travel does not include a running slope in excess of 1:12 (8.33%), a cross slope exceeding 1:50 (2%), nor level changes of more than 1/2". If slope is over 5%, handrails are required. Level landing; 32" clear width opening doors and adequate lighting on pathway and landing. This is required to be considered "visitable."', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Approach with Ramp/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Bedroom', 'en', 'Accessible Bedroom', 'Bedroom has adequate turnaround of 60" or other approved turnaround configuration. Closet doors have 32" clearance. Accessible environmental controls and multiple lighting fixtures. This is required to be considered Enhanced Accessible. Optional: Some lower-height storage in closet. Remote control of lighting and environmental controls.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Bedroom/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Central Living Area', 'en', 'Accessible Central Living Area', 'Hard surface flooring or low-pile carpet, securely attached along edges. Entrances to all rooms on all floors provide 36" clear passage. Multiple lighting fixtures installed to provide adaptable lighting for general purpose and tasks. This is required to be considered Enhanced Accessible.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Central Living Area/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Closets', 'en', 'Accessible Closets', 'Closet doors are 32” clearance throughout the central living area.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Closets/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Common Area', 'en', 'Accessible Common Area', 'Common area, used for entertaining guests, level, with 36" passage through and around the space. Required to be considered Visitable.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Common Area/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Doors', 'en', 'Accessible Doors', 'Minimum 32" clear passage; levered handle; threshold, if present, maximum 1/2" but beveled on both sides when over 1/4". Required to be considered Visitable or Enhanced Accessible.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Doors/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Electrical and Environmental Controls', 'en', 'Accessible Electrical and Environmental Controls', 'Thermostats and security system controls located on floor with central living area. Control devices for light switches and thermostats at 42-48" height off floor and side to side. Electrical plugs minimum of 18" above floor. This is required to be considered Enhanced Accessible. Optional: rocker-style light switches, lighted switches, automatic/remote control for environmental controls.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Electrical and Environmental Controls/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Elevator Installed', 'en', 'Accessible Elevator Installed', 'Elevator with minimum 32" door and minimum 36" x 48" turning radius.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Elevator Installed/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Entrance', 'en', 'Accessible Entrance', 'Entrance door is a minimum of 32" wide; threshold, when present, maximum 1/2" but when over 1/4" is beveled on both sides. The entry door has lever handle for egress. This is required to be considered Visitable. Optional: entryway is covered; bench near outside entry door; motion-detection outside lights; accessible peephole or other method for inside viewing of anyone outside the entry door; house number easily visible from street by emergency responders.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Entrance/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Full Bath', 'en', 'Accessible Full Bath', 'Bathroom has adequate turnaround: 60" or other approved turnaround configuration. Accessible bathing area: roll-in shower or space for shower chair or transfer bench in bathtub. Slip-resistant surface on bathroom floor and bathtub/shower. Roll-under or side-access to sink with padded trap. Lighting directly over shower/bathing areas, in addition to general bathroom lighting. This is required to be considered Enhanced Accessible. Optional: removable cabinet doors and base under sink; grab bars with shear force of 250 pounds installed around toilet and shower/tub with proper backing; handheld and/or height-adjustable shower head; automatic water temperature controlled (anti-scald) tub/shower; offset tub/shower controls toward front edge of tub/shower for easy access; raised toilet (17-19" minimum).', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Full Bath/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Hallway(s)', 'en', 'Accessible Hallway(s)', 'Hallway is a minimum of 36", preferred 42", wide (or adequate alternative based on individual configuration). At least one lighting fixture is present.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Hallway(s)/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Kitchen', 'en', 'Accessible Kitchen', '40" clear turn-around, or 36" clear with clear under-counter space for T-turn space in kitchen, unimpeded by fixtures. Roll-under/adaptable sink with padded trap or side-access to sink. Roll-out shelves in at least 50% of lower cabinets, Roll-under work area (36" clearance). Lighting fixtures directed over all task areas with adaptable control. This is required to be considered Enhanced Accessible. Optional: adaptable under-sink cabinet with removable doors and cabinet base; accessible features for upper kitchen cabinets; space for side-by-side refrigerator (minimum 36"); contrasting color counter edges for vision accessibility.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Kitchen/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Kitchen Appliances', 'en', 'Accessible Kitchen Appliances', 'Stove controls in front or side, at countertop height; oven with side-access door at counter level; microwave is at counter level. This is required to be considered Enhanced Accessible. Optional: raised dishwasher; microwave has clear work area below or to the right side.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Kitchen Appliances/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Stairway', 'en', 'Accessible Stairway', 'Handrails on both sides of stairs, extended when possible, with shear force of 250 pounds. Interior and exterior stairs have adequate number of light fixtures for full coverage. Non-slip stair treads. If stairs are carpeted, covering is non-moveable, low-pile carpet. This is required to be considered Enhanced Accessible. Optional: stair treads are in high contrast colors for increased visibility.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Stairway/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible Washer/Dryer', 'en', 'Accessible Washer/Dryer', 'Raised clothes washer and/or dryer, front controls, side opening, both open to center.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible Washer%2FDryer/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Accessible for Hearing-Impairment', 'en', 'Accessible for Hearing-Impairment', 'Home is wired for flashing lights and/or vibrating smoke alarm, door bell or other alerting features.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Accessible for Hearing-Impairment/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Adaptable Bathroom Walls', 'en', 'Adaptable Bathroom Walls', 'Reinforced main bathroom walls, including bath or shower, to permit installation of grab bars (with shear force of 250 pounds) and/or fixtures in the future. This is required to be considered Enhanced Accessible.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Adaptable Bathroom Walls/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Adaptable For Elevator', 'en', 'Adaptable For Elevator', 'Stacked closets in a multistory house for possible future conversion to an elevator.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Adaptable For Elevator/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Ceiling Track', 'en', 'Ceiling Track', 'Track installed in ceiling for lift chair (Hoyer lift).', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Ceiling Track/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Central Living Area', 'en', 'Central Living Area', 'Includes common area; hallway(s); full or three-quarters bathroom; kitchen; at least one bedroom; access to environmental controls; and access to floors above main floor, if necessary.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Central Living Area/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Common Area', 'en', 'Common Area', 'The portion of the home near accessible entrance, used for entertaining guests.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Common Area/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Customized Wheelchair Accessible', 'en', 'Customized Wheelchair Accessible', 'Customized accessibility for specific size or style of wheelchair or scooter.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Customized Wheelchair Accessible/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Electronic Environmental Controls', 'en', 'Electronic Environmental Controls', 'Programmable electronic controls for thermostat, lights, security system and automatic doors.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Electronic Environmental Controls/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Enhanced Accessible', 'en', 'Enhanced Accessible', 'The central living area is fully accessible for lifelong living by all residents, no matter their ability. A person in a wheelchair or with other disability is able to perform all personal and housekeeping tasks. Persons without disabilities are also able to perform basic tasks with greater ease. To be considered Enhanced Accessible, the home also includes all Visitable features.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Enhanced Accessible/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Exterior Wheelchair Lift', 'en', 'Exterior Wheelchair Lift', 'A mechanical wheelchair lift is installed outside the home to facilitate barrier-free approach.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Exterior Wheelchair Lift/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Grip-Accessible Features', 'en', 'Grip-Accessible Features', 'All doors, faucets and other mechanisms throughout the central living area are lever, hands-free or another style that can be controlled with a closed hand, clenched fist or weak hands. This is required to be considered Enhanced Accessible. Optional: wire pull (D-ring) handles or equivalent or easy touch latches on cabinets and drawers.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Grip-Accessible Features/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Reinforced Floors', 'en', 'Reinforced Floors', 'Reinforced floors for bariatric needs, power wheelchairs, therapeutic tub or heavy medical equipment.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Reinforced Floors/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Safe Emergency Egress from Home', 'en', 'Safe Emergency Egress from Home', 'A minimum of two, no-step, accessible egresses from central living area. Window locks are 19-54" from the floor and can be opened with a closed fist. Emergency egress windows in sleeping areas require minimal effort to open. This is required to be considered Enhanced Accessible.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Safe Emergency Egress from Home/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Smart Technology', 'en', 'Smart Technology', 'Smart Home (computer-controlled) and/or smart products (e.g., voice-activated controls, voice reminder, remote monitoring of individuals with dementia).', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Smart Technology/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Stair Lift', 'en', 'Stair Lift', 'A professionally installed motorized rail to climb an interior or exterior stairway.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Stair Lift/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Standby Generator', 'en', 'Standby Generator', 'Backup generator for refrigeration of medications, life-sustaining medical equipment or essential room temperature control.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Standby Generator/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Therapeutic Whirlpool', 'en', 'Therapeutic Whirlpool', 'Therapeutic whirlpool, properly installed.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Therapeutic Whirlpool/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Visitable', 'en', 'Visitable', 'A person in a wheelchair can easily enter the home and access the main common area. Home has a half-bathroom at minimum and a hall leading to that bathroom.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Visitable/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Visitor Bathroom', 'en', 'Visitor Bathroom', 'The bathroom that is closest to the common area, minimum half bath. Door has minimum 32" clear width opening and lever handles. Minimum 60" turnaround or other approved turnaround configuration (30" x 48" clear space if door opens out.). Grab bar installed in toilet area with proper blocking. This is required to be considered Visitable.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Visitor Bathroom/', '2.0', 'reso_official_csv'),
  ('AccessibilityFeatures', 'Walker-Accessible Stairs', 'en', 'Walker-Accessible Stairs', 'Treads are minimum 25" deep, with maximum 4" rise and minimum 36" wide. May be a custom feature in addition to approach with ramp.', 'https://dd.reso.org/DD2.0/lookups/AccessibilityFeatures/Walker-Accessible Stairs/', '2.0', 'reso_official_csv'),
  ('ActorType', 'Agent', 'en', 'Agent', 'The event was generated by what the source defines as a real estate professional.', 'https://dd.reso.org/DD2.0/lookups/ActorType/Agent/', '2.0', 'reso_official_csv'),
  ('ActorType', 'Bot', 'en', 'Bot', 'The event was generated by a bot or some type of scripting tool', 'https://dd.reso.org/DD2.0/lookups/ActorType/Bot/', '2.0', 'reso_official_csv'),
  ('ActorType', 'Client', 'en', 'Client', 'The event was generated by what the source defines as a registered client', 'https://dd.reso.org/DD2.0/lookups/ActorType/Client/', '2.0', 'reso_official_csv'),
  ('ActorType', 'Consumer', 'en', 'Consumer', 'The event was generated by what the source defines as a consumer', 'https://dd.reso.org/DD2.0/lookups/ActorType/Consumer/', '2.0', 'reso_official_csv'),
