  ('Appliances', 'Bar Fridge', 'en', 'Bar Fridge', 'A refrigerator that is sized and/or built to be part of a bar.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Bar Fridge/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Built-In Electric Oven', 'en', 'Built-In Electric Oven', 'A built-in electric oven.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Built-In Electric Oven/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Built-In Electric Range', 'en', 'Built-In Electric Range', 'A built-in electric range.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Built-In Electric Range/', '2.0', 'reso_official_csv'),
