  ('Appliances', 'Built-In Gas Oven', 'en', 'Built-In Gas Oven', 'A built-in gas oven', 'https://dd.reso.org/DD2.0/lookups/Appliances/Built-In Gas Oven/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Built-In Gas Range', 'en', 'Built-In Gas Range', 'A built-in gas range.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Built-In Gas Range/', '2.0', 'reso_official_csv'),
