  ('Appliances', 'Built-In Refrigerator', 'en', 'Built-In Refrigerator', 'A built-in refrigerator', 'https://dd.reso.org/DD2.0/lookups/Appliances/Built-In Refrigerator/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Convection Oven', 'en', 'Convection Oven', 'An oven that has fans to circulate air around food. Also known as a fan-assisted oven or simply a fan oven.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Convection Oven/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Cooktop', 'en', 'Cooktop', 'A kitchen stove or cooker; a kitchen appliance designed for the purpose of cooking food. Kitchen stoves rely on the application of direct heat for the cooking process.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Cooktop/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Dishwasher', 'en', 'Dishwasher', 'A dishwasher is a mechanical device for cleaning dishware and cutlery.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Dishwasher/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Disposal', 'en', 'Disposal', 'A garbage disposal unit (also known as a garbage disposal, waste disposal unit, garbage disposer or garburator (in Canada)) is a device, usually electrically powered, installed under a kitchen sink between the sink''s drain and the trap. The disposal unit shreds food waste into pieces small enough, generally less than 2 mm (0.079"), to pass through plumbing.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Disposal/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Double Oven', 'en', 'Double Oven', 'A built-in oven fixture that has either two ovens, or one oven and one microwave oven. It is usually built into the kitchen cabinet.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Double Oven/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Down Draft', 'en', 'Down Draft', 'A vent that is part of the surface of a cooktop that has a fan which sucks cooking fumes/smoke down. This is an alternative to a hooded cooktop/range.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Down Draft/', '2.0', 'reso_official_csv'),
