  ('Appliances', 'ENERGY STAR Qualified Appliances', 'en', 'ENERGY STAR Qualified Appliances', 'The property includes qualified ENERGY STAR appliances.', 'https://dd.reso.org/DD2.0/lookups/Appliances/ENERGY STAR Qualified Appliances/', '2.0', 'reso_official_csv'),
  ('Appliances', 'ENERGY STAR Qualified Dishwasher', 'en', 'ENERGY STAR Qualified Dishwasher', 'The property includes a qualified ENERGY STAR dishwasher.', 'https://dd.reso.org/DD2.0/lookups/Appliances/ENERGY STAR Qualified Dishwasher/', '2.0', 'reso_official_csv'),
  ('Appliances', 'ENERGY STAR Qualified Dryer', 'en', 'ENERGY STAR Qualified Dryer', 'The property includes a qualified ENERGY STAR clothes dryer.', 'https://dd.reso.org/DD2.0/lookups/Appliances/ENERGY STAR Qualified Dryer/', '2.0', 'reso_official_csv'),
  ('Appliances', 'ENERGY STAR Qualified Freezer', 'en', 'ENERGY STAR Qualified Freezer', 'The property includes a qualified ENERGY STAR freezer.', 'https://dd.reso.org/DD2.0/lookups/Appliances/ENERGY STAR Qualified Freezer/', '2.0', 'reso_official_csv'),
