  ('Appliances', 'Electric Cooktop', 'en', 'Electric Cooktop', 'A cooktop or stove that produces heat by way of electricity rather than gas. An induction cooktop is electric, but not all electric cooktops are induction.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Electric Cooktop/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Electric Oven', 'en', 'Electric Oven', 'An oven that is heated by electricity, typically by way of heating coils.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Electric Oven/', '2.0', 'reso_official_csv'),
  ('Appliances', 'Electric Range', 'en', 'Electric Range', 'An oven and cooktop that generates heat by way of electricity.', 'https://dd.reso.org/DD2.0/lookups/Appliances/Electric Range/', '2.0', 'reso_official_csv'),
