  ('ArchitecturalStyle', 'A-Frame', 'en', 'A-Frame', 'An architectural style that generally features four walls extending up from the foundation and a steeply pitched roof that reaches near the ground, creating an overall shape of the letter “A” or a triangle.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/A-Frame/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Art Deco', 'en', 'Art Deco', 'An architectural style that generally includes decorative windows, spires or other tower-like structures and facades with vertical lines and other ornamental geometric patterns. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Art Deco/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Barndominium', 'en', 'Barndominium', 'An architectural style that is typically a metal pole barn or other barn-like structure with a living area that encompasses a portion of or the entire building.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Barndominium/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Berm', 'en', 'Berm', 'An architectural style built partially or entirely below grade, with earthen material (i.e., dirt, grass) covering at least one or more walls.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Berm/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Bungalow', 'en', 'Bungalow', 'An architectural style (also known as cottage) that is generally small with a single story or partial second story that has an overhanging, sloped roof and covered porch. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Bungalow/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Cabin', 'en', 'Cabin', 'An architectural style that is generally small in size with a simple floor plan and built with mostly natural materials.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Cabin/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Cape Cod', 'en', 'Cape Cod', 'An architectural style that is generally framed rectangularly, includes one and a half or two stories of height, has a centered front door, and is built with a moderately steeply-pitched, gabled roof. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Cape Cod/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Colonial', 'en', 'Colonial', 'An architectural style that is generally framed rectangularly, includes two or three stories in height, and is built with a brick, stone or wood facade and steeply-pitched, gabled roof. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Colonial/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Contemporary', 'en', 'Contemporary', 'An architectural style that generally includes large windows, natural construction elements, geometric shapes and minimalistic elements. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Contemporary/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Craftsman', 'en', 'Craftsman', 'An architectural style (also known as arts and crafts) that generally is one or one and a half stories in height, has wood siding or shaker shingles, includes covered porches with exposed beams or columns, and is built with low-pitched, gabled roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Craftsman/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Creole', 'en', 'Creole', 'A prominent architectural style in the Southern United States, particularly the state of Louisiana, that is generally one to one and a half stories in height and includes full front porches and high, gabled roofs with a ridge parallel to the road it fronts. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Creole/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Dome', 'en', 'Dome', 'An architectural style (also known as geodesic) that generally takes the shape of a sphere or spherical ellipsoid and has a shell-type framework.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Dome/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Dutch Colonial', 'en', 'Dutch Colonial', 'An architectural style that generally has steep, broken-pitched, gambrel roofs that contain at least one dormer window. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Dutch Colonial/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Farmhouse', 'en', 'Farmhouse', 'An architectural style that is generally one and a half or two stories in height, asymmetrical in design, and built with central chimneys and large porches that sometimes cover multiple sides of the home. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Farmhouse/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Federal', 'en', 'Federal', 'An architectural style that is generally square or rectangular, emphasizing balance and symmetry, and has a brick exterior, typically without a porch. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Federal/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'French Provincial', 'en', 'French Provincial', 'An architectural style that is generally multi-story with a brick or stucco exterior, slate roof and tall, slender windows. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/French Provincial/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Georgian', 'en', 'Georgian', 'An architectural style that is generally symmetrical with two or three stories in height and a brick or stone exterior with regularly spaced windows. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Georgian/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Gothic Revival', 'en', 'Gothic Revival', 'An architectural style that generally emphasizes decorative elements, arch designs in windows and doorways, and steeply pitched, pointed and gabled roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Gothic Revival/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Greek Revival', 'en', 'Greek Revival', 'An architectural style that generally includes a plaster or stucco exterior with tall columns and framed, dormer windows. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Greek Revival/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Italianate', 'en', 'Italianate', 'An architectural style that is generally two to four stories in height with gently sloping, hipped roofs and tall, narrow or arched windows. Italianate homes further feature decorative elements such as towers, columns and brackets. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Italianate/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Mediterranean', 'en', 'Mediterranean', 'An architectural style that generally features a blend of Spanish Revival and Italian Renaissance architecture with stucco exterior, red clay or tile roofs, decorative archways, wrought ironwork in balconies and window grilles, and an incorporation of outdoor living spaces. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Mediterranean/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Mid-Century Modern', 'en', 'Mid-Century Modern', 'An architectural style that is generally asymmetrical and split-level or one story in height with large or floor-to-ceiling windows. Mid-century modern homes emphasize right angles and straight lines. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Mid-Century Modern/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Modern', 'en', 'Modern', 'An architectural style similar to mid-century modern that emphasizes function over form, straight lines and geometric shapes while keeping purely decorative aspects to a minimum. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Modern/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Monterey', 'en', 'Monterey', 'An architectural style that is generally two stories in height with large porches, full-length balconies, hipped roofs and tall, double-hung windows.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Monterey/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'National', 'en', 'National', 'An architectural style that is generally utilitarian, rectangular in shape and built with gabled or pyramidal roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/National/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Neoclassical', 'en', 'Neoclassical', 'An architectural style that generally emphasizes symmetry and often features large columns, decorative doorways and evenly spaced, divided pane windows. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Neoclassical/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Other', 'en', 'Other', 'The architectural style is something other than the options provided.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Other/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Prairie', 'en', 'Prairie', 'An architectural style that is generally asymmetrical and emphasizes horizontal lines, handmade woodwork, metalwork and art glass. Large, sometimes floor-to-ceiling windows are often prevalent along with flat or slightly pitched, overhanging roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Prairie/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Pueblo', 'en', 'Pueblo', 'An architectural style (also known as Southwestern or adobe) that is generally constructed of adobe, which may be covered by stucco, with an emphasis on natural, earth-tone materials. Pueblo homes typically have small windows, wooden posts or columns, and large, covered porches. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Pueblo/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Queen Anne', 'en', 'Queen Anne', 'An architectural style that is generally asymmetrical with round or polygonal towers or turrets, large wrap-around porches, and steeply pitched, gabled, slate roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Queen Anne/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Raised Ranch', 'en', 'Raised Ranch', 'An architectural style (also known as bi-level or split foyer) with designed living space below grade that generally have two full levels of living space with a short set of stairs leading up and down from inside the entrance to the home. Raised ranches also often feature large windows and low-pitched roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Raised Ranch/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Ranch', 'en', 'Ranch', 'An architectural style that is generally one story in height, low to the ground and built with low-pitched roofs and attached, front-facing garages. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Ranch/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Regency', 'en', 'Regency', 'An architectural style similar to Georgian that is generally two or three stories in height and symmetrical with a painted stucco façade and built with large columns supporting a covered entryway. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Regency/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Rustic', 'en', 'Rustic', 'An architectural style that is generally built mostly with wood, stone and other natural materials that create a naturally aged and rough look. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Rustic/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Saltbox', 'en', 'Saltbox', 'An architectural style originating in New England that is generally two stories in height in the front and one in the rear with a gable roof. Saltbox homes were originally timber framed and get their name from the visual similarity to a wood-lid box that salt was once kept in. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Saltbox/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'See Remarks', 'en', 'See Remarks', 'See remarks for information about the architectural style of the home.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/See Remarks/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Shingle', 'en', 'Shingle', 'An architectural style that is generally asymmetrical with shingle-covered exteriors, wide porches and steeply pitched roofs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Shingle/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Shotgun', 'en', 'Shotgun', 'An architectural style that is generally one story in height, rectangular, long and narrow with gabled roofs. Typically, an unaltered interior contains one room following another without typical hallways. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Shotgun/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Spanish', 'en', 'Spanish', 'An architectural style that is most common in the Southwestern United States and generally has a stucco exterior with liberal use of wood and tile. Spanish homes often have arched or rounded doorways and windows and some will include scalloped balconies with elaborate grillwork, decorative tiles around doorways and windows and even bell towers. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Spanish/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Split Level', 'en', 'Split Level', 'An architectural style (also known as tri level or quad level) that is generally asymmetrical and has facades with minimal decorative elements. The interiors have multiple levels accessed by short sets of stairs. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Split Level/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Stick', 'en', 'Stick', 'An architectural style related to Victorian that is generally asymmetrical with two to three stories of height and a highly decorative shingle or clapboard exterior that may include towers and an emphasis on geometric patterns. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Stick/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Traditional', 'en', 'Traditional', 'An architectural style that uses several different exterior materials, has simple triangular rooflines, includes regularly spaced and sized windows, and is complemented by large, covered porches. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Traditional/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Tudor', 'en', 'Tudor', 'An architectural style that is generally asymmetrical that has a brick or stone exterior with wood accents and is characterized by steeply pitched, gabled roofs, casement windows and arched doorways. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Tudor/', '2.0', 'reso_official_csv'),
  ('ArchitecturalStyle', 'Victorian', 'en', 'Victorian', 'An architectural style that is generally two to three stories in height with asymmetrical or complex shapes and highly decorative ornamentation such as brackets, spindles and patterned shingles. Roofs tend to be multi-faceted and steeply pitched and may have curved towers or turrets. Note that architectural style definitions may vary based on location.', 'https://dd.reso.org/DD2.0/lookups/ArchitecturalStyle/Victorian/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Appraiser', 'en', 'Appraiser', 'An appraiser provided the measurement of the area.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Appraiser/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Assessor', 'en', 'Assessor', 'The assessor provided the measurement of the area.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Assessor/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Builder', 'en', 'Builder', 'The builder provided the measurement of the area.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Builder/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Estimated', 'en', 'Estimated', 'The measurement of the area is an estimate.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Estimated/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Other', 'en', 'Other', 'The measurement of the area was provided by another party not listed.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Other/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Owner', 'en', 'Owner', 'The owner provided the measurement of the area.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Owner/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Plans', 'en', 'Plans', 'The measurement of the area was taken from building plans.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Plans/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'Public Records', 'en', 'Public Records', 'The measurement of the area was received from public records.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/Public Records/', '2.0', 'reso_official_csv'),
  ('AreaSource', 'See Remarks', 'en', 'See Remarks', 'See remarks for information about the source of the area measurement.', 'https://dd.reso.org/DD2.0/lookups/AreaSource/See Remarks/', '2.0', 'reso_official_csv'),
  ('AreaUnits', 'Square Feet', 'en', 'Square Feet', 'The value reported in the related Area field is in square feet.', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/Square Feet/', '2.0', 'reso_official_csv'),
  ('AreaUnits', 'Square Meters', 'en', 'Square Meters', 'The value reported in the related Area field is in square meters.', 'https://dd.reso.org/DD2.0/lookups/AreaUnits/Square Meters/', '2.0', 'reso_official_csv'),
  ('AssociationAmenities', 'Airport/Runway', 'en', 'Airport/Runway', 'The homeowner association includes access or some service related to an airport or runway.', 'https://dd.reso.org/DD2.0/lookups/AssociationAmenities/Airport%2FRunway/', '2.0', 'reso_official_csv'),
  ('AssociationAmenities', 'Barbecue', 'en', 'Barbecue', 'The homeowner association includes use of or access to a barbecue.', 'https://dd.reso.org/DD2.0/lookups/AssociationAmenities/Barbecue/', '2.0', 'reso_official_csv'),
