  ('AssociationAmenities', 'Billiard Room', 'en', 'Billiard Room', 'The homeowner association includes use of or access to a billiard room.', 'https://dd.reso.org/DD2.0/lookups/AssociationAmenities/Billiard Room/', '2.0', 'reso_official_csv'),
