  ('BuyerFinancing', 'Seller Financing', 'en', 'Seller Financing', 'The seller is providing financing to the buyer.', 'https://dd.reso.org/DD2.0/lookups/BuyerFinancing/Seller Financing/', '2.0', 'reso_official_csv'),
  ('BuyerFinancing', 'Trust Deed', 'en', 'Trust Deed', 'Financing where title of the property is placed with a trustee who secures payment of the loan for a beneficiary.', 'https://dd.reso.org/DD2.0/lookups/BuyerFinancing/Trust Deed/', '2.0', 'reso_official_csv'),
  ('BuyerFinancing', 'USDA', 'en', 'USDA', 'A loan from an approved provider that follows the guidelines of, and is insured by, the U.S. Department of Agriculture.', 'https://dd.reso.org/DD2.0/lookups/BuyerFinancing/USDA/', '2.0', 'reso_official_csv'),
