  ('ClassName', 'Farm', 'en', 'Farm', 'The class, sometimes known as property type, is a farm.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Farm/', '2.0', 'reso_official_csv'),
  ('ClassName', 'History Transactional', 'en', 'History Transactional', 'The class is the transactional history of another class.', 'https://dd.reso.org/DD2.0/lookups/ClassName/History Transactional/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Land', 'en', 'Land', 'The class, sometimes known as property type, is land for sale or lease.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Land/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Manufactured In Park', 'en', 'Manufactured In Park', 'The class, sometimes known as property type, is a manufactured or mobile home in a mobile park.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Manufactured In Park/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Media', 'en', 'Media', 'The class is one that contains records referencing media files.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Media/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Member', 'en', 'Member', 'The class containing member records.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Member/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Office', 'en', 'Office', 'The class containing office records.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Office/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Open House', 'en', 'Open House', 'The class containing open house records.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Open House/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Residential', 'en', 'Residential', 'The class, sometimes known as property type, is residential property for sale.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Residential/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Residential Income', 'en', 'Residential Income', 'The class, sometimes known as property type, is income or multifamily property for sale.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Residential Income/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Residential Lease', 'en', 'Residential Lease', 'The class, sometimes known as property type, is residential property for lease.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Residential Lease/', '2.0', 'reso_official_csv'),
  ('ClassName', 'Saved Search', 'en', 'Saved Search', 'The class containing saved search data.', 'https://dd.reso.org/DD2.0/lookups/ClassName/Saved Search/', '2.0', 'reso_official_csv'),
  ('ClosetType', 'Built-in Closet', 'en', 'Built-in Closet', 'The bedroom has a built-in closet.', 'https://dd.reso.org/DD2.0/lookups/ClosetType/Built-in Closet/', '2.0', 'reso_official_csv'),
  ('ClosetType', 'None', 'en', 'None', 'The room does not have a closet.', 'https://dd.reso.org/DD2.0/lookups/ClosetType/None/', '2.0', 'reso_official_csv'),
  ('ClosetType', 'Walk-in Closet', 'en', 'Walk-in Closet', 'The bedroom has a walk-in closet.', 'https://dd.reso.org/DD2.0/lookups/ClosetType/Walk-in Closet/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Accredited Buyer''s Representative / ABR', 'en', 'Accredited Buyer''s Representative / ABR', 'The Accredited Buyer’s Representative (ABR®) designation is designed for real estate buyer agents who focus on working directly with buyer-clients. http://www.rebac.net/abr', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Accredited Buyer''s Representative %2F ABR/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Accredited Land Consultant / ALC', 'en', 'Accredited Land Consultant / ALC', 'Accredited Land Consultants (ALCs) are the most trusted, knowledgeable, experienced and highest-producing experts in all segments of land. Conferred by the REALTORS® Land Institute, the designation requires successful completion of a rigorous education program for high-volume and experienced practitioners who adhere to an honorable Code of Conduct. https://www.nar.realtor/designations-and-certifications/alc', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Accredited Land Consultant %2F ALC/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'At Home With Diversity / AHWD', 'en', 'At Home With Diversity / AHWD', 'Learn to work effectively with and within today’s diverse real estate market. The At Home With Diversity certification teaches you how to conduct your business with sensitivity to all client profiles and how to build a business plan to successfully serve them. https://www.nar.realtor/designations-and-certifications/ahwd', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/At Home With Diversity %2F AHWD/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Commercial Investment Member / CCIM', 'en', 'Certified Commercial Investment Member / CCIM', 'The Certified Commercial Investment Member (CCIM) designation is commercial real estate’s global standard for professional achievement, earned through an extensive curriculum of 200 classroom hours and professional experiential requirements. https://www.nar.realtor/designations-and-certifications/ccim', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Commercial Investment Member %2F CCIM/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Distressed Property Expert / CDPE', 'en', 'Certified Distressed Property Expert / CDPE', 'A Certified Distressed Property Expert® (CDPE) has a thorough understanding of complex issues in today’s turbulent real estate industry and knowledge of foreclosure avoidance options available to homeowners. CDPEs can provide solutions, specifically short sales, for homeowners facing market hardships. http://www.cdpe.com/', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Distressed Property Expert %2F CDPE/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified International Property Specialist / CIPS', 'en', 'Certified International Property Specialist / CIPS', 'The CIPS designation is for REALTORS® from the United States and abroad, as well as association staff and volunteer leaders who wish to develop or grow their international real estate business. It will provide you with the knowledge, research, network and tools to globalize your business. https://www.nar.realtor/designations-and-certifications/cips-designation', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified International Property Specialist %2F CIPS/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Property Manager / CPM', 'en', 'Certified Property Manager / CPM', 'Certified Property Managers® (CPM®) are recognized as experts in real estate management, and they are at the top of the profession. Seventy percent of those who hold the CPM designation hold the highest management positions in their offices (owner/partner/officer/director). https://www.nar.realtor/designations-and-certifications/cpm', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Property Manager %2F CPM/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Real Estate Brokerage Manager / CRB', 'en', 'Certified Real Estate Brokerage Manager / CRB', 'The Certified Real Estate Brokerage Manager (CRB) Designation raises professional standards, strengthens individual and office performance, and indicates expertise in brokerage management. This designation represents the highest level of professional achievement in real estate brokerage management. You do not need a broker''s license to earn the CRB designation. https://www.nar.realtor/designations-and-certifications/crb', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Real Estate Brokerage Manager %2F CRB/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Real Estate Team Specialist / C-RETS', 'en', 'Certified Real Estate Team Specialist / C-RETS', 'The Certified Real Estate Team Specialist certification is designed to improve team development, individual leadership skills and financial performance. The courses provide the tools, strategies and knowledge required of today’s real estate professionals who are either considering or currently operating in a team environment. It is for team leaders, team members, those looking to start a team and those who simply want to sharpen their management skills. https://www.nar.realtor/designations-and-certifications/c-rets', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Real Estate Team Specialist %2F C-RETS/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Certified Residential Specialist / CRS', 'en', 'Certified Residential Specialist / CRS', 'Certified Residential Specialist (CRS) is the highest credential awarded to residential sales agents, managers and brokers. https://www.nar.realtor/designations-and-certifications/crs', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Certified Residential Specialist %2F CRS/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Counselor of Real Estate / CRE', 'en', 'Counselor of Real Estate / CRE', 'The Counselors of Real Estate® is an international group of recognized professionals who provide seasoned, expert, objective advice on real property and land-related matters. Only 1,100 practitioners throughout the world carry the CRE® designation. Membership is by invitation only. https://www.nar.realtor/designations-and-certifications/cre', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Counselor of Real Estate %2F CRE/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'General Accredited Appraiser / GAA', 'en', 'General Accredited Appraiser / GAA', 'For general appraisers, this designation is awarded to those whose education and experience exceed state appraisal certification requirements and is supported by the National Association of REALTORS®. https://www.nar.realtor/designations-and-certifications/gaa', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/General Accredited Appraiser %2F GAA/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Graduate, REALTOR Institute / GRI', 'en', 'Graduate, REALTOR Institute / GRI', 'REALTORS® with the GRI designation have in-depth training in legal and regulatory issues, technology, professional standards, and the sales process. Earning the designation is a way to stand out to prospective buyers and sellers as a professional with expertise in these areas. https://www.nar.realtor/designations-and-certifications/gri', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Graduate, REALTOR Institute %2F GRI/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Military Relocation Professional / MRP', 'en', 'Military Relocation Professional / MRP', 'The National Association of REALTORS® Military Relocation Professional certification focuses on educating real estate professionals about working with current and former military service members to find housing solutions that best suit their needs and take full advantage of military benefits and support. https://www.nar.realtor/designations-and-certifications/mrp', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Military Relocation Professional %2F MRP/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'NAR''s Green Designation / GREEN', 'en', 'NAR''s Green Designation / GREEN', 'Through the National Association of REALTORS® Green designation, the Green Resource Council provides ongoing education, resources and tools to help real estate practitioners find, understand and market properties with green features. https://www.nar.realtor/designations-and-certifications/green', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/NAR''s Green Designation %2F GREEN/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Performance Management Network / PMN', 'en', 'Performance Management Network / PMN', 'This designation is unique to the REALTOR® family of designations, emphasizing that in order to enhance your business, you must enhance yourself. It focuses on negotiating strategies and tactics, networking and referrals, business planning and systems, personal performance management, and leadership development. https://www.nar.realtor/designations-and-certifications/pmn', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Performance Management Network %2F PMN/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Pricing Strategy Advisor / PSA', 'en', 'Pricing Strategy Advisor / PSA', 'Enhance your skills in pricing properties, creating CMAs (comparative market analysis), working with appraisers and guiding clients through the anxieties and misperceptions they often have about home values with the National Association of REALTORS® PSA (Pricing Strategy Advisor) certification. https://www.nar.realtor/designations-and-certifications/psa', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Pricing Strategy Advisor %2F PSA/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'REALTOR Association Certified Executive / RCE', 'en', 'REALTOR Association Certified Executive / RCE', 'The REALTOR® Association Certified Executive (RCE) is the only professional designation designed specifically for REALTOR® association executives. RCE designees exemplify goal-oriented AEs with drive, experience and commitment to professional growth. https://www.nar.realtor/designations-and-certifications/rce', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/REALTOR Association Certified Executive %2F RCE/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Real Estate Negotiation Expert / RENE', 'en', 'Real Estate Negotiation Expert / RENE', 'This certification is for real estate professionals who want to sharpen their negotiation skills. The RENE certification program gives REALTORS® the tips and tools they need to be skillful advocates for their clients. https://www.nar.realtor/designations-and-certifications/rene', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Real Estate Negotiation Expert %2F RENE/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Residential Accredited Appraiser / RAA', 'en', 'Residential Accredited Appraiser / RAA', 'For residential appraisers, this designation is awarded to those whose education and experience exceed state appraisal certification requirements and is supported by the National Association of REALTORS®. https://www.nar.realtor/designations-and-certifications/raa', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Residential Accredited Appraiser %2F RAA/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Resort & Second-Home Property Specialist / RSPS', 'en', 'Resort & Second-Home Property Specialist / RSPS', 'This certification is designed for REALTORS® who facilitate the buying, selling or management of properties for investment, development, retirement or second homes in a resort, recreational and/or vacation destination. https://www.nar.realtor/designations-and-certifications/rsps', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Resort & Second-Home Property Specialist %2F RSPS/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Seller Representative Specialist / SRS', 'en', 'Seller Representative Specialist / SRS', 'The Seller Representative Specialist (SRS) designation is the premier credential in seller representation. It is designed to elevate professional standards and enhance personal performance. The designation is awarded by the Real Estate Business Institute (REBI) to real estate practitioners who meet specific educational and practical experience criteria. https://www.nar.realtor/designations-and-certifications/seller-representative-specialist-srs', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Seller Representative Specialist %2F SRS/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Seniors Real Estate Specialist / SRES', 'en', 'Seniors Real Estate Specialist / SRES', 'The Seniors Real Estate Specialist (SRES®) designation program educates REALTORS® on how to profitably and ethically serve the real estate needs of the fastest-growing market in real estate, clients age 50+. Those who earn the SRES® designation gain access to valuable member benefits, useful resources and networking opportunities across the U.S. and Canada in order to help their businesses thrive. https://www.nar.realtor/designations-and-certifications/sres', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Seniors Real Estate Specialist %2F SRES/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Short Sales & Foreclosure Resource / SFR', 'en', 'Short Sales & Foreclosure Resource / SFR', 'The Short Sales & Foreclosure Resource (SFR®) certification teaches real estate professionals to work with distressed sellers and the finance, tax and legal professionals who can help them. Learn how to qualify sellers for short sales, develop a short sale package, negotiate with lenders, safeguard your commission, limit risk, protect buyers and more. https://www.nar.realtor/designations-and-certifications/sfr', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Short Sales & Foreclosure Resource %2F SFR/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Society of Industrial and Office REALTORS / SIOR', 'en', 'Society of Industrial and Office REALTORS / SIOR', 'The Society of Industrial and Office REALTORS® (SIOR) designation is held by only the most knowledgeable, experienced and successful commercial real estate brokerage specialists. To earn it, designees must not only provide recommendations but must meet standards of experience, production, education and ethics. https://www.nar.realtor/designations-and-certifications/sior', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Society of Industrial and Office REALTORS %2F SIOR/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'Transnational Referral Certification / TRC', 'en', 'Transnational Referral Certification / TRC', 'Real estate professionals who have taken the Transnational Referral Certified (TRC) training, have completed special training on making and receiving client referrals from professionals in other countries. https://worldproperties.com/about-us/international-referrals-and-trc/', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/Transnational Referral Certification %2F TRC/', '2.0', 'reso_official_csv'),
  ('CoBuyerAgentDesignation', 'e-PRO', 'en', 'e-PRO', 'NAR''s e-PRO® certification teaches you to use cutting-edge technologies and digital initiatives to link up with today''s savvy real estate consumer. https://www.nar.realtor/designations-and-certifications/e-pro', 'https://dd.reso.org/DD2.0/lookups/CoBuyerAgentDesignation/e-PRO/', '2.0', 'reso_official_csv'),
  ('CoListAgentDesignation', 'Accredited Buyer''s Representative / ABR', 'en', 'Accredited Buyer''s Representative / ABR', 'The Accredited Buyer’s Representative (ABR®) designation is designed for real estate buyer agents who focus on working directly with buyer-clients. http://www.rebac.net/abr', 'https://dd.reso.org/DD2.0/lookups/CoListAgentDesignation/Accredited Buyer''s Representative %2F ABR/', '2.0', 'reso_official_csv'),
  ('CoListAgentDesignation', 'Accredited Land Consultant / ALC', 'en', 'Accredited Land Consultant / ALC', 'Accredited Land Consultants (ALCs) are the most trusted, knowledgeable, experienced and highest-producing experts in all segments of land. Conferred by the REALTORS® Land Institute, the designation requires successful completion of a rigorous education program for high-volume and experienced practitioners who adhere to an honorable Code of Conduct. https://www.nar.realtor/designations-and-certifications/alc', 'https://dd.reso.org/DD2.0/lookups/CoListAgentDesignation/Accredited Land Consultant %2F ALC/', '2.0', 'reso_official_csv'),
