  ('Heating', 'Kerosene', 'en', 'Kerosene', 'The heating system uses kerosene as its fuel to generate heat.', 'https://dd.reso.org/DD2.0/lookups/Heating/Kerosene/', '2.0', 'reso_official_csv'),
  ('Heating', 'Natural Gas', 'en', 'Natural Gas', 'The heating system uses natural gas as its fuel to generate heat.', 'https://dd.reso.org/DD2.0/lookups/Heating/Natural Gas/', '2.0', 'reso_official_csv'),
