  ('Heating', 'Oil', 'en', 'Oil', 'The heating system uses oil as its fuel to generate heat.', 'https://dd.reso.org/DD2.0/lookups/Heating/Oil/', '2.0', 'reso_official_csv'),
  ('Heating', 'Other', 'en', 'Other', 'The property has a heating system or features that are not included on this list.', 'https://dd.reso.org/DD2.0/lookups/Heating/Other/', '2.0', 'reso_official_csv'),
  ('Heating', 'Passive Solar', 'en', 'Passive Solar', 'Passive solar is a building design where the walls, windows, floors, etc., are made to collect heat and warm the dwelling.', 'https://dd.reso.org/DD2.0/lookups/Heating/Passive Solar/', '2.0', 'reso_official_csv'),
