  ('InteriorOrRoomFeatures', 'Bar', 'en', 'Bar', 'A built-in or movable fixture for the storage, preparation, serving and/or consumption of drinks.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Bar/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Beamed Ceilings', 'en', 'Beamed Ceilings', 'A property that has exposed beams across the ceiling of a room or rooms.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Beamed Ceilings/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Bidet', 'en', 'Bidet', 'A type of sink designed to wash the undercarriage of the human body.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Bidet/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Bookcases', 'en', 'Bookcases', 'Shelves for books or other objects that may or may not be built into the property.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Bookcases/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Breakfast Bar', 'en', 'Breakfast Bar', 'A surface designed for eating, which is typically smaller than a dining table and attached to another kitchen surface.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Breakfast Bar/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Built-in Features', 'en', 'Built-in Features', 'Some features are physically attached to the structure.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Built-in Features/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Cathedral Ceiling(s)', 'en', 'Cathedral Ceiling(s)', 'A type of vaulted ceiling that is typically higher than normal ceilings and has a slant or curve to reach its uppermost point, which tends to be equal distance from the two shorter walls in the room.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Cathedral Ceiling(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Cedar Closet(s)', 'en', 'Cedar Closet(s)', 'A closet that is partially or fully lined with cedarwood.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Cedar Closet(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Ceiling Fan(s)', 'en', 'Ceiling Fan(s)', 'A fan is mounted from the ceiling in a room or multiple rooms.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Ceiling Fan(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Central Vacuum', 'en', 'Central Vacuum', 'A built-in vacuum that typically consists of a power/collection unit that is typically installed in a garage or closet, tubing from the power unit to rooms throughout the house and including wall-mounted receptacles for the connection of a movable vacuum hose.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Central Vacuum/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Chandelier', 'en', 'Chandelier', 'A decorative lighting fixture that typically branches out with several lights (or candles) with other decorative components such as glass, crystal or other reflective or light-enhancing materials.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Chandelier/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Coffered Ceiling(s)', 'en', 'Coffered Ceiling(s)', 'A ceiling with multiple decorative indentations, trays or sunken panels.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Coffered Ceiling(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Crown Molding', 'en', 'Crown Molding', 'A decorative trim covering the seam between the ceiling and walls.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Crown Molding/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Double Vanity', 'en', 'Double Vanity', 'Bathroom cabinetry with two built-in sinks.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Double Vanity/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Dry Bar', 'en', 'Dry Bar', 'A built-in or movable fixture for the storage, preparation, serving and consumption of drinks that does not have a water supply or sink.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Dry Bar/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Dumbwaiter', 'en', 'Dumbwaiter', 'A small elevator, typically for carrying food between floors in a structure.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Dumbwaiter/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Eat-in Kitchen', 'en', 'Eat-in Kitchen', 'A kitchen that has been designed to accommodate dining.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Eat-in Kitchen/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Elevator', 'en', 'Elevator', 'A platform or compartment housed within a shaft for raising or lowering people or objects.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Elevator/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Entrance Foyer', 'en', 'Entrance Foyer', 'A room or hall at the entrance leading to other parts of the structure.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Entrance Foyer/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Granite Counters', 'en', 'Granite Counters', 'The counters are made of a type of granite stone.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Granite Counters/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'High Ceilings', 'en', 'High Ceilings', 'The ceiling height is greater than what might be considered a normal ceiling height.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/High Ceilings/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'High Speed Internet', 'en', 'High Speed Internet', 'The property has access to high-speed internet service but may or may not be wired and/or connected to that service.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/High Speed Internet/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'His and Hers Closets', 'en', 'His and Hers Closets', 'The room or rooms have two separate closets.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/His and Hers Closets/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'In-Law Floorplan', 'en', 'In-Law Floorplan', 'The structure has an area within that has the characteristics of an independent apartment, typically with a living area, kitchen, bedroom and bathroom. An in-law floor plan is not necessarily an Accessory Dwelling Unit (ADU).', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/In-Law Floorplan/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Kitchen Island', 'en', 'Kitchen Island', 'A separate counter surface in a kitchen that is not attached to other surfaces or to a wall. A kitchen island may or may not include a sink, stove or other fixtures.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Kitchen Island/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Laminate Counters', 'en', 'Laminate Counters', 'The counters are covered with a laminate.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Laminate Counters/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Low Flow Plumbing Fixtures', 'en', 'Low Flow Plumbing Fixtures', 'Some or all of the fixtures are designed to save water.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Low Flow Plumbing Fixtures/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Master Downstairs', 'en', 'Master Downstairs', 'There is a primary bedroom on the main level of the structure.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Master Downstairs/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Natural Woodwork', 'en', 'Natural Woodwork', 'The property or room has features made from real wood.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Natural Woodwork/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Open Floorplan', 'en', 'Open Floorplan', 'A generic design term for a floor plan that makes use of large open spaces and avoids the use of small enclosed spaces.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Open Floorplan/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Other', 'en', 'Other', 'The room or interior has features other than those included on this list.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Other/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Pantry', 'en', 'Pantry', 'A small room or closet where food, dishes and utensils are stored.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Pantry/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Recessed Lighting', 'en', 'Recessed Lighting', 'A light fixture installed into a hollow opening in the ceiling.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Recessed Lighting/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Sauna', 'en', 'Sauna', 'A small room or separate structure designed to produce heat to induce perspiration with wet steam (often poured over hot stones) or with dry heat.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Sauna/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'See Remarks', 'en', 'See Remarks', 'See the remarks fields for additional information about the room or interior.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/See Remarks/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Smart Camera(s)/Recording', 'en', 'Smart Camera(s)/Recording', 'A camera or recording control unit that has convenience and energy-saving aspects. A smart camera may also integrate with a larger smart home system and typically operates through a third-party service.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Smart Camera(s)%2FRecording/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Smart Home', 'en', 'Smart Home', 'A generic term for electronic automation of features such as lighting, heating/cooling, security and other amenities. The features are typically linked through an app or software via one or more third-party services. The features are also known for their convenience and energy efficiency.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Smart Home/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Smart Light(s)', 'en', 'Smart Light(s)', 'A lighting control unit that has convenience and energy-saving aspects. Smart lights may also integrate with a larger smart home system and typically operates through a third-party service.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Smart Light(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Smart Thermostat', 'en', 'Smart Thermostat', 'A heating/cooling control unit that has convenience and energy-saving aspects. A smart thermostat may also integrate with a larger smart home system and typically operates through a third-party service.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Smart Thermostat/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Soaking Tub', 'en', 'Soaking Tub', 'A bathtub that is typically deeper and may be shorter than traditional tubs.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Soaking Tub/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Solar Tube(s)', 'en', 'Solar Tube(s)', 'A reflective tube that extends from a light-gathering surface on the roof of the structure down into a room where the outside light is distributed.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Solar Tube(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Sound System', 'en', 'Sound System', 'The property includes a sound system that typically includes in-wall wiring and recessed/built-in speakers and a built-in location for the amplifier and other audio equipment.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Sound System/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Stone Counters', 'en', 'Stone Counters', 'The property or room has counters that are made of some type of stone.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Stone Counters/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Storage', 'en', 'Storage', 'The property or room has storage space.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Storage/', '2.0', 'reso_official_csv'),
