  ('InteriorOrRoomFeatures', 'Walk-In Closet(s)', 'en', 'Walk-In Closet(s)', 'A closet that is a small room with an entryway.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Walk-In Closet(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'WaterSense Fixture(s)', 'en', 'Water Sense Fixture(s)', 'Water fixtures that are backed by independent, third-party certification and meet Environmental Protection Agency (EPA) specifications for water efficiency and performance.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/WaterSense Fixture(s)/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Wet Bar', 'en', 'Wet Bar', 'Commonly a built-in fixture for the storage, preparation, serving and/or consumption of drinks that has a faucet and sink.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Wet Bar/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Wired for Data', 'en', 'Wired for Data', 'The property has been wired for data, typically Category 5 or 6 wiring for the support of Ethernet data communications.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Wired for Data/', '2.0', 'reso_official_csv'),
  ('InteriorOrRoomFeatures', 'Wired for Sound', 'en', 'Wired for Sound', 'The property has been wired for a built-in sound system. This typically includes in-wall wiring and recessed/built-in speakers and a location for audio equipment. The wiring is in place, but equipment may not be included.', 'https://dd.reso.org/DD2.0/lookups/InteriorOrRoomFeatures/Wired for Sound/', '2.0', 'reso_official_csv'),
