  ('LeaseRenewalCompensation', 'Call Listing Agent', 'en', 'Call Listing Agent', 'For details about additional selling office compensation for lease renewals, contact the listing agent.', 'https://dd.reso.org/DD2.0/lookups/LeaseRenewalCompensation/Call Listing Agent/', '2.0', 'reso_official_csv'),
  ('LeaseRenewalCompensation', 'Call Listing Office', 'en', 'Call Listing Office', 'For details about additional selling office compensation for lease renewals, contact the listing office.', 'https://dd.reso.org/DD2.0/lookups/LeaseRenewalCompensation/Call Listing Office/', '2.0', 'reso_official_csv'),
  ('LeaseRenewalCompensation', 'Commission Paid On Tenant Purchase', 'en', 'Commission Paid On Tenant Purchase', 'Additional commission is paid in the event the tenant purchases the property.', 'https://dd.reso.org/DD2.0/lookups/LeaseRenewalCompensation/Commission Paid On Tenant Purchase/', '2.0', 'reso_official_csv'),
  ('LeaseRenewalCompensation', 'No Renewal Commission', 'en', 'No Renewal Commission', 'There is no additional commission if the tenant renews or extends the lease.', 'https://dd.reso.org/DD2.0/lookups/LeaseRenewalCompensation/No Renewal Commission/', '2.0', 'reso_official_csv'),
  ('LeaseRenewalCompensation', 'Renewal Commission Paid', 'en', 'Renewal Commission Paid', 'There is additional commission paid if the tenant renews the lease.', 'https://dd.reso.org/DD2.0/lookups/LeaseRenewalCompensation/Renewal Commission Paid/', '2.0', 'reso_official_csv'),
