  ('LeaseTerm', '6 Months', 'en', '6 Months', 'The length of the lease is 6 months.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/6 Months/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Month To Month', 'en', 'Month To Month', 'The length of the lease is month to month.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Month To Month/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Negotiable', 'en', 'Negotiable', 'The length of the lease is negotiable.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Negotiable/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'None', 'en', 'None', 'There is no stated term to the lease.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/None/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Other', 'en', 'Other', 'The term of the lease is something other than is available on this list.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Other/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Renewal Option', 'en', 'Renewal Option', 'The lease has a renewal option.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Renewal Option/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Short Term Lease', 'en', 'Short Term Lease', 'The lease is short term.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Short Term Lease/', '2.0', 'reso_official_csv'),
  ('LeaseTerm', 'Weekly', 'en', 'Weekly', 'The length of the lease is weekly.', 'https://dd.reso.org/DD2.0/lookups/LeaseTerm/Weekly/', '2.0', 'reso_official_csv'),
  ('Levels', 'Bi-Level', 'en', 'Bi-Level', 'A bi-level home has two staggered levels. There are typically two short sets of stairs off of a landing area, one running upward and one running downward.', 'https://dd.reso.org/DD2.0/lookups/Levels/Bi-Level/', '2.0', 'reso_official_csv'),
  ('Levels', 'Multi/Split', 'en', 'Multi/Split', 'A split-level home (also called a tri-level home) is a style of house in which the floor levels are staggered so that the "main" level of the house (e.g., the level that usually contains the front entry) is partway between the upper and lower floors.', 'https://dd.reso.org/DD2.0/lookups/Levels/Multi%2FSplit/', '2.0', 'reso_official_csv'),
  ('Levels', 'One', 'en', 'One', 'The property being sold has one level. A discreet horizontal plane of interior living space (excluding basements).', 'https://dd.reso.org/DD2.0/lookups/Levels/One/', '2.0', 'reso_official_csv'),
  ('Levels', 'One and One Half', 'en', 'One and One Half', 'A 1.5-story house is where the height of any of the walls on the second floor are less than the height of the walls on the first floor. First floor walls that extend up to the second floor level are not included in the height comparison. Depending on your state, province or other local regulations, there may be a specific height difference required. For example, some areas require that second floor walls should be less than 70% the height of first floor walls in order to be called a 1.5-story structure. Other areas are 50%, and it is clear that this may vary substantially from region to region. Another common trait is angled ceilings that compensate for the short walls making all but the edges of the room high enough for normal use.', 'https://dd.reso.org/DD2.0/lookups/Levels/One and One Half/', '2.0', 'reso_official_csv'),
  ('Levels', 'Quad-Level', 'en', 'Quad-Level', 'A quad-level home has four staggered levels connected by two or more short sets of stairs. The levels consist of ground, underground, partial underground and upper.', 'https://dd.reso.org/DD2.0/lookups/Levels/Quad-Level/', '2.0', 'reso_official_csv'),
  ('Levels', 'Three Or More', 'en', 'Three Or More', 'The property being sold has three or more levels. A discreet horizontal plane of interior living space (excluding basements).', 'https://dd.reso.org/DD2.0/lookups/Levels/Three Or More/', '2.0', 'reso_official_csv'),
  ('Levels', 'Tri-Level', 'en', 'Tri-Level', 'A tri-level home has three staggered levels connected by two or more short sets of stairs. The levels consist of ground, partial underground and upper.', 'https://dd.reso.org/DD2.0/lookups/Levels/Tri-Level/', '2.0', 'reso_official_csv'),
  ('Levels', 'Two', 'en', 'Two', 'The property being sold has two levels. A discreet horizontal plane of interior living space (excluding basements).', 'https://dd.reso.org/DD2.0/lookups/Levels/Two/', '2.0', 'reso_official_csv'),
  ('LinearUnits', 'Feet', 'en', 'Feet', 'The elevation of the property is measured in feet.', 'https://dd.reso.org/DD2.0/lookups/LinearUnits/Feet/', '2.0', 'reso_official_csv'),
  ('LinearUnits', 'Meters', 'en', 'Meters', 'The elevation of the property is measured in meters.', 'https://dd.reso.org/DD2.0/lookups/LinearUnits/Meters/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Accredited Buyer''s Representative / ABR', 'en', 'Accredited Buyer''s Representative / ABR', 'The Accredited Buyer’s Representative (ABR®) designation is designed for real estate buyer agents who focus on working directly with buyer-clients. http://www.rebac.net/abr', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Accredited Buyer''s Representative %2F ABR/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Accredited Land Consultant / ALC', 'en', 'Accredited Land Consultant / ALC', 'Accredited Land Consultants (ALCs) are the most trusted, knowledgeable, experienced and highest-producing experts in all segments of land. Conferred by the REALTORS® Land Institute, the designation requires successful completion of a rigorous education program for high-volume and experienced practitioners who adhere to an honorable Code of Conduct. https://www.nar.realtor/designations-and-certifications/alc', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Accredited Land Consultant %2F ALC/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'At Home With Diversity / AHWD', 'en', 'At Home With Diversity / AHWD', 'Learn to work effectively with and within today’s diverse real estate market. The At Home with Diversity certification teaches you how to conduct your business with sensitivity to all client profiles and how to build a business plan to successfully serve them. https://www.nar.realtor/designations-and-certifications/ahwd', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/At Home With Diversity %2F AHWD/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Commercial Investment Member / CCIM', 'en', 'Certified Commercial Investment Member / CCIM', 'The Certified Commercial Investment Member (CCIM) designation is commercial real estate’s global standard for professional achievement, earned through an extensive curriculum of 200 classroom hours and professional experiential requirements. https://www.nar.realtor/designations-and-certifications/ccim', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Commercial Investment Member %2F CCIM/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Distressed Property Expert / CDPE', 'en', 'Certified Distressed Property Expert / CDPE', 'A Certified Distressed Property Expert® (CDPE) has a thorough understanding of complex issues in today’s turbulent real estate industry and knowledge of foreclosure avoidance options available to homeowners. CDPEs can provide solutions, specifically short sales, for homeowners facing market hardships. http://www.cdpe.com/', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Distressed Property Expert %2F CDPE/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified International Property Specialist / CIPS', 'en', 'Certified International Property Specialist / CIPS', 'The CIPS designation is for REALTORS® from the United States and abroad, as well as association staff and volunteer leaders who wish to develop or grow their international real estate business. It will provide you with the knowledge, research, network and tools to globalize your business. https://www.nar.realtor/designations-and-certifications/cips-designation', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified International Property Specialist %2F CIPS/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Property Manager / CPM', 'en', 'Certified Property Manager / CPM', 'Certified Property Managers® (CPM®) are recognized as experts in real estate management, and they are at the top of the profession. Seventy percent of those who hold the CPM designation hold the highest management positions in their offices (owner/partner/officer/director). https://www.nar.realtor/designations-and-certifications/cpm', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Property Manager %2F CPM/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Real Estate Brokerage Manager / CRB', 'en', 'Certified Real Estate Brokerage Manager / CRB', 'The Certified Real Estate Brokerage Manager (CRB) Designation raises professional standards, strengthens individual and office performance, and indicates expertise in brokerage management. This designation represents the highest level of professional achievement in real estate brokerage management. You do not need a broker''s license to earn the CRB designation. https://www.nar.realtor/designations-and-certifications/crb', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Real Estate Brokerage Manager %2F CRB/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Real Estate Team Specialist / C-RETS', 'en', 'Certified Real Estate Team Specialist / C-RETS', 'The Certified Real Estate Team Specialist certification is designed to improve team development, individual leadership skills and financial performance. The courses provide the tools, strategies and knowledge required of today’s real estate professionals who are either considering or currently operating in a team environment. It is for team leaders, team members, those looking to start a team and those who simply want to sharpen their management skills. https://www.nar.realtor/designations-and-certifications/c-rets', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Real Estate Team Specialist %2F C-RETS/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Certified Residential Specialist / CRS', 'en', 'Certified Residential Specialist / CRS', 'Certified Residential Specialist (CRS) is the highest credential awarded to residential sales agents, managers and brokers. https://www.nar.realtor/designations-and-certifications/crs', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Certified Residential Specialist %2F CRS/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Counselor of Real Estate / CRE', 'en', 'Counselor of Real Estate / CRE', 'The Counselors of Real Estate® (CRE®) is an international group of recognized professionals who provide seasoned, expert, objective advice on real property and land-related matters. Only 1,100 practitioners throughout the world carry the CRE® designation. Membership is by invitation only. https://www.nar.realtor/designations-and-certifications/cre', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Counselor of Real Estate %2F CRE/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'General Accredited Appraiser / GAA', 'en', 'General Accredited Appraiser / GAA', 'For general appraisers, this designation is awarded to those whose education and experience exceed state appraisal certification requirements and is supported by the National Association of REALTORS®. https://www.nar.realtor/designations-and-certifications/gaa', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/General Accredited Appraiser %2F GAA/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Graduate, REALTOR Institute / GRI', 'en', 'Graduate, REALTOR Institute / GRI', 'REALTORS® with the GRI designation have in-depth training in legal and regulatory issues, technology, professional standards, and the sales process. Earning the designation is a way to stand out to prospective buyers and sellers as a professional with expertise in these areas. https://www.nar.realtor/designations-and-certifications/gri', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Graduate, REALTOR Institute %2F GRI/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Military Relocation Professional / MRP', 'en', 'Military Relocation Professional / MRP', 'The National Association of REALTORS® Military Relocation Professional certification focuses on educating real estate professionals about working with current and former military service members to find housing solutions that best suit their needs and take full advantage of military benefits and support. https://www.nar.realtor/designations-and-certifications/mrp', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Military Relocation Professional %2F MRP/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'NAR''s Green Designation / GREEN', 'en', 'NAR''s Green Designation / GREEN', 'Through the National Association of REALTORS® Green designation, the Green Resource Council provides ongoing education, resources and tools to help real estate practitioners find, understand and market properties with green features. https://www.nar.realtor/designations-and-certifications/green', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/NAR''s Green Designation %2F GREEN/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Performance Management Network / PMN', 'en', 'Performance Management Network / PMN', 'This designation is unique to the REALTOR® family of designations, emphasizing that in order to enhance your business, you must enhance yourself. It focuses on negotiating strategies and tactics, networking and referrals, business planning and systems, personal performance management, and leadership development. https://www.nar.realtor/designations-and-certifications/pmn', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Performance Management Network %2F PMN/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Pricing Strategy Advisor / PSA', 'en', 'Pricing Strategy Advisor / PSA', 'Enhance your skills in pricing properties, creating CMAs (comparative market analysis), working with appraisers and guiding clients through the anxieties and misperceptions they often have about home values with the National Association of REALTORS® PSA (Pricing Strategy Advisor) certification. https://www.nar.realtor/designations-and-certifications/psa', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Pricing Strategy Advisor %2F PSA/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'REALTOR Association Certified Executive / RCE', 'en', 'REALTOR Association Certified Executive / RCE', 'The REALTOR® Association Certified Executive (RCE) is the only professional designation designed specifically for REALTOR® association executives. RCE designees exemplify goal-oriented AEs with drive, experience and commitment to professional growth. https://www.nar.realtor/designations-and-certifications/rce', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/REALTOR Association Certified Executive %2F RCE/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Real Estate Negotiation Expert / RENE', 'en', 'Real Estate Negotiation Expert / RENE', 'This certification is for real estate professionals who want to sharpen their negotiation skills. The RENE certification program gives REALTORS® the tips and tools they need to be skillful advocates for their clients. https://www.nar.realtor/designations-and-certifications/rene', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Real Estate Negotiation Expert %2F RENE/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Residential Accredited Appraiser / RAA', 'en', 'Residential Accredited Appraiser / RAA', 'For residential appraisers, this designation is awarded to those whose education and experience exceed state appraisal certification requirements and is supported by the National Association of REALTORS®. https://www.nar.realtor/designations-and-certifications/raa', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Residential Accredited Appraiser %2F RAA/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Resort & Second-Home Property Specialist / RSPS', 'en', 'Resort & Second-Home Property Specialist / RSPS', 'This certification is designed for REALTORS® who facilitate the buying, selling or management of properties for investment, development, retirement or second homes in a resort, recreational and/or vacation destination. https://www.nar.realtor/designations-and-certifications/rsps', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Resort & Second-Home Property Specialist %2F RSPS/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Seller Representative Specialist / SRS', 'en', 'Seller Representative Specialist / SRS', 'The Seller Representative Specialist (SRS) designation is the premier credential in seller representation. It is designed to elevate professional standards and enhance personal performance. The designation is awarded by the Real Estate Business Institute (REBI) to real estate practitioners who meet specific educational and practical experience criteria. https://www.nar.realtor/designations-and-certifications/seller-representative-specialist-srs', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Seller Representative Specialist %2F SRS/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Seniors Real Estate Specialist / SRES', 'en', 'Seniors Real Estate Specialist / SRES', 'The Seniors Real Estate Specialist (SRES®) designation program educates REALTORS® on how to profitably and ethically serve the real estate needs of the fastest-growing market in real estate, clients age 50+. Those who earn the SRES® designation gain access to valuable member benefits, useful resources and networking opportunities across the U.S. and Canada in order to help their businesses thrive. https://www.nar.realtor/designations-and-certifications/sres', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Seniors Real Estate Specialist %2F SRES/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Short Sales & Foreclosure Resource / SFR', 'en', 'Short Sales & Foreclosure Resource / SFR', 'The Short Sales & Foreclosure Resource (SFR®) certification teaches real estate professionals to work with distressed sellers and the finance, tax and legal professionals who can help them. Learn how to qualify sellers for short sales, develop a short sale package, negotiate with lenders, safeguard your commission, limit risk, protect buyers and more. https://www.nar.realtor/designations-and-certifications/sfr', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Short Sales & Foreclosure Resource %2F SFR/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Society of Industrial and Office REALTORS / SIOR', 'en', 'Society of Industrial and Office REALTORS / SIOR', 'The Society of Industrial and Office REALTORS® (SIOR) designation is held by only the most knowledgeable, experienced and successful commercial real estate brokerage specialists. To earn it, designees must not only provide recommendations but must meet standards of experience, production, education and ethics. https://www.nar.realtor/designations-and-certifications/sior', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Society of Industrial and Office REALTORS %2F SIOR/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'Transnational Referral Certification / TRC', 'en', 'Transnational Referral Certification / TRC', 'Real estate professionals who have taken the Transnational Referral Certified (TRC) training, have completed special training on making and receiving client referrals from professionals in other countries. https://worldproperties.com/about-us/international-referrals-and-trc/', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/Transnational Referral Certification %2F TRC/', '2.0', 'reso_official_csv'),
  ('ListAgentDesignation', 'e-PRO', 'en', 'e-PRO', 'The National Association of REALTORS® e-PRO® certification teaches you to use cutting-edge technologies and digital initiatives to link up with today''s savvy real estate consumer. https://www.nar.realtor/designations-and-certifications/e-pro', 'https://dd.reso.org/DD2.0/lookups/ListAgentDesignation/e-PRO/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Exclusive Agency', 'en', 'Exclusive Agency', 'A contract giving one brokerage firm, for a specified time, the right to sell/lease the property and also allowing the owner, acting alone, to sell/lease the property without paying commission.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Exclusive Agency/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Exclusive Right To Lease', 'en', 'Exclusive Right To Lease', 'A contract giving the broker the right to collect commission if the property is leased by anyone, including the owner, during the term of the agreement.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Exclusive Right To Lease/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Exclusive Right To Sell', 'en', 'Exclusive Right To Sell', 'A contract giving the broker the right to collect commission if the property is sold by anyone, including the owner, during the term of the agreement.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Exclusive Right To Sell/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Exclusive Right With Exception', 'en', 'Exclusive Right With Exception', 'A contract giving the broker the right to collect commission if the property is sold by anyone, including the owner, during the term of the agreement unless some specified exceptions to the agreement occur.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Exclusive Right With Exception/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Net', 'en', 'Net', 'A listing in which the broker''s commission is the excess of the sale price over an agreed-upon (net) price to the seller; illegal in some states because it can create a conflict of interest for the broker.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Net/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Open', 'en', 'Open', 'Often used for commercial property, a listing given to any number of brokers without liability to compensate any except the one who first secures a buyer who is ready, willing and able to meet the terms of the listing and secures the seller''s acceptance. The seller may, acting alone, sell the property without paying commission.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Open/', '2.0', 'reso_official_csv'),
  ('ListingAgreement', 'Probate', 'en', 'Probate', 'An Exclusive Right To Sell listing agreement that also resides under authority of the local probate code.', 'https://dd.reso.org/DD2.0/lookups/ListingAgreement/Probate/', '2.0', 'reso_official_csv'),
  ('ListingService', 'Entry Only', 'en', 'Entry Only', 'The only service provided by the brokerage is the input of the listing into the MLS system.', 'https://dd.reso.org/DD2.0/lookups/ListingService/Entry Only/', '2.0', 'reso_official_csv'),
  ('ListingService', 'Full Service', 'en', 'Full Service', 'A full set of services offered by a brokerage.', 'https://dd.reso.org/DD2.0/lookups/ListingService/Full Service/', '2.0', 'reso_official_csv'),
  ('ListingService', 'Limited Service', 'en', 'Limited Service', 'A limited set of services offered by a brokerage', 'https://dd.reso.org/DD2.0/lookups/ListingService/Limited Service/', '2.0', 'reso_official_csv'),
  ('ListingTerms', '1031 Exchange', 'en', '1031 Exchange', 'The seller may be interested in a 1031 exchange as part of the sale.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/1031 Exchange/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'All Inclusive Trust Deed', 'en', 'All Inclusive Trust Deed', 'The property is under an all-inclusive trust deed.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/All Inclusive Trust Deed/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Assumable', 'en', 'Assumable', 'The seller is interested in assumable financing.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Assumable/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Cash', 'en', 'Cash', 'The seller would like a cash sale.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Cash/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Contract', 'en', 'Contract', 'The seller may be interested in an agreement to perform services, provide product, share income or some other agreement as the method of payment for the property.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Contract/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Conventional', 'en', 'Conventional', 'The seller may accept a buyer using conventional financing to purchase the home.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Conventional/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Existing Bonds', 'en', 'Existing Bonds', 'The property for sale has existing bonds.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Existing Bonds/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'FHA', 'en', 'FHA', 'The seller may accept a buyer with a loan from an approved provider that follows the guidelines of, and is insured by, the Federal Housing Administration (FHA).', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/FHA/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Land Use Fee', 'en', 'Land Use Fee', 'The listed property has a land use fee.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Land Use Fee/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Lease Back', 'en', 'Lease Back', 'The seller may be interested in the simultaneous sale of a property with a lease back to the seller who then becomes the tenant.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Lease Back/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Lease Option', 'en', 'Lease Option', 'The seller may be interested in selling as a lease option to the buyer.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Lease Option/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Lease Purchase', 'en', 'Lease Purchase', 'The seller may be interested in selling as a lease purchase.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Lease Purchase/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Lien Release', 'en', 'Lien Release', 'The property for sale may require a lien release.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Lien Release/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Owner May Carry', 'en', 'Owner May Carry', 'The seller may be interested in carrying the mortgage note.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Owner May Carry/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Owner Pay Points', 'en', 'Owner Pay Points', 'The seller may carry points.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Owner Pay Points/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Owner Will Carry', 'en', 'Owner Will Carry', 'The seller will carry the mortgage note.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Owner Will Carry/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Private Financing Available', 'en', 'Private Financing Available', 'Financing is provided by a private party.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Private Financing Available/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Relocation Property', 'en', 'Relocation Property', 'The property for sale is a relocation property.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Relocation Property/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Seller Equity Share', 'en', 'Seller Equity Share', 'The seller may be interested in investing in an equity share.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Seller Equity Share/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Special Funding', 'en', 'Special Funding', 'The seller may be interested in a special funding arrangement.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Special Funding/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Submit', 'en', 'Submit', 'Contact the listing agent for the listing terms.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Submit/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Trade', 'en', 'Trade', 'The seller may be interested in a trade arrangement.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Trade/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Trust Conveyance', 'en', 'Trust Conveyance', 'A trust conveyance (to another trustee) may be involved in the sale of the property.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Trust Conveyance/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'Trust Deed', 'en', 'Trust Deed', 'The seller may accept financing where title of the property is placed with a trustee who secures payment of the loan for a beneficiary.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/Trust Deed/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'USDA Loan', 'en', 'USDA Loan', 'The seller may accept a loan from an approved provider that follows the guidelines of, and is insured by, the U.S. Department of Agriculture.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/USDA Loan/', '2.0', 'reso_official_csv'),
  ('ListingTerms', 'VA Loan', 'en', 'VA Loan', 'The seller may accept a loan from an approved provider that follows the guidelines of, and is insured by, the U.S. Department of Veterans Affairs.', 'https://dd.reso.org/DD2.0/lookups/ListingTerms/VA Loan/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Agent Website', 'en', 'Agent Website', 'A link that directs to the listing on an agent website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Agent Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Broker Website', 'en', 'Broker Website', 'A link that directs to the listing on a broker website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Broker Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Brokerage Website', 'en', 'Brokerage Website', 'A link that directs to the listing on a brokerage website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Brokerage Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Franchisor Website', 'en', 'Franchisor Website', 'A link that directs to the listing on a franchisor website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Franchisor Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'MLS Website', 'en', 'MLS Website', 'A link that directs to the listing on an MLS website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/MLS Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Other Website', 'en', 'Other Website', 'A link that directs to the listing on a general website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Other Website/', '2.0', 'reso_official_csv'),
  ('ListingURLDescription', 'Syndication Website', 'en', 'Syndication Website', 'A link that directs to the listing on a syndication website.', 'https://dd.reso.org/DD2.0/lookups/ListingURLDescription/Syndication Website/', '2.0', 'reso_official_csv'),
  ('LockBoxType', 'Call Listing Office', 'en', 'Call Listing Office', 'Call the listing office for information about accessing the property.', 'https://dd.reso.org/DD2.0/lookups/LockBoxType/Call Listing Office/', '2.0', 'reso_official_csv'),
  ('LockBoxType', 'Call Seller Direct', 'en', 'Call Seller Direct', 'Call the seller directly to arrange for access to the property.', 'https://dd.reso.org/DD2.0/lookups/LockBoxType/Call Seller Direct/', '2.0', 'reso_official_csv'),
