  ('MemberOtherPhoneType', 'Toll Free', 'en', 'Toll Free', 'The toll-free phone number of the member.', 'https://dd.reso.org/DD2.0/lookups/MemberOtherPhoneType/Toll Free/', '2.0', 'reso_official_csv'),
  ('MemberOtherPhoneType', 'Voicemail', 'en', 'Voicemail', 'The voicemail of the member.', 'https://dd.reso.org/DD2.0/lookups/MemberOtherPhoneType/Voicemail/', '2.0', 'reso_official_csv'),
  ('MemberStateLicenseType', 'Appraiser', 'en', 'Appraiser', 'The member state license type is appraiser.', 'https://dd.reso.org/DD2.0/lookups/MemberStateLicenseType/Appraiser/', '2.0', 'reso_official_csv'),
  ('MemberStateLicenseType', 'Broker', 'en', 'Broker', 'The member state license type is broker.', 'https://dd.reso.org/DD2.0/lookups/MemberStateLicenseType/Broker/', '2.0', 'reso_official_csv'),
  ('MemberStateLicenseType', 'Salesperson', 'en', 'Salesperson', 'The member state license type is salesperson.', 'https://dd.reso.org/DD2.0/lookups/MemberStateLicenseType/Salesperson/', '2.0', 'reso_official_csv'),
  ('MemberStatus', 'Active', 'en', 'Active', 'The member''s account is active.', 'https://dd.reso.org/DD2.0/lookups/MemberStatus/Active/', '2.0', 'reso_official_csv'),
  ('MemberStatus', 'Inactive', 'en', 'Inactive', 'the member''s account is not active.', 'https://dd.reso.org/DD2.0/lookups/MemberStatus/Inactive/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Affiliate', 'en', 'Affiliate', 'The member is affiliated with the real estate industry in some manner (e.g., home inspector, photographer, mortgage consultant) but is not necessarily a REALTOR®.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Affiliate/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Assistant', 'en', 'Assistant', 'The member is an assistant. The status of the assistant being licensed is not known or possibly not required.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Assistant/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Association Staff', 'en', 'Association Staff', 'The member is a member of an association''s staff.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Association Staff/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Designated REALTOR Appraiser', 'en', 'Designated REALTOR Appraiser', 'The member is a designated appraiser and a member of the National Association of REALTORS® (NAR).', 'https://dd.reso.org/DD2.0/lookups/MemberType/Designated REALTOR Appraiser/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Designated REALTOR Participant', 'en', 'Designated REALTOR Participant', 'The member is a designated broker and a member of the National Association of REALTORS® (NAR).', 'https://dd.reso.org/DD2.0/lookups/MemberType/Designated REALTOR Participant/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Leasing Agent', 'en', 'Leasing Agent', 'The member holds a leasing license.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Leasing Agent/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Licensed Assistant', 'en', 'Licensed Assistant', 'The member is a licensed assistant.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Licensed Assistant/', '2.0', 'reso_official_csv'),
  ('MemberType', 'MLS Only Appraiser', 'en', 'MLS Only Appraiser', 'The member is an appraiser and not a member of the National Association of REALTORS® (NAR), receiving MLS services only.', 'https://dd.reso.org/DD2.0/lookups/MemberType/MLS Only Appraiser/', '2.0', 'reso_official_csv'),
  ('MemberType', 'MLS Only Broker', 'en', 'MLS Only Broker', 'The member is a broker and not a member of the National Association of REALTORS® (NAR), receiving MLS services only.', 'https://dd.reso.org/DD2.0/lookups/MemberType/MLS Only Broker/', '2.0', 'reso_official_csv'),
  ('MemberType', 'MLS Only Broker Associate', 'en', 'MLS Only Broker Associate', 'The member is a broker and not a member of the National Association of REALTORS® (NAR), receiving MLS services only.', 'https://dd.reso.org/DD2.0/lookups/MemberType/MLS Only Broker Associate/', '2.0', 'reso_official_csv'),
  ('MemberType', 'MLS Only Salesperson', 'en', 'MLS Only Salesperson', 'The member is a salesperson and not a member of the National Association of REALTORS® (NAR), receiving MLS services only.', 'https://dd.reso.org/DD2.0/lookups/MemberType/MLS Only Salesperson/', '2.0', 'reso_official_csv'),
  ('MemberType', 'MLS Staff', 'en', 'MLS Staff', 'The individual is a member of MLS staff.', 'https://dd.reso.org/DD2.0/lookups/MemberType/MLS Staff/', '2.0', 'reso_official_csv'),
  ('MemberType', 'Non Member/Vendor', 'en', 'Non Member/Vendor', 'The individual is not a member or is a vendor.', 'https://dd.reso.org/DD2.0/lookups/MemberType/Non Member%2FVendor/', '2.0', 'reso_official_csv'),
