  ('RoomType', 'Kitchen', 'en', 'Kitchen', 'The room used for the preparation and storage of food; cookery.', 'https://dd.reso.org/DD2.0/lookups/RoomType/Kitchen/', '2.0', 'reso_official_csv'),
