  ('RoomType', 'Living Room', 'en', 'Living Room', 'A room in a private house used for general social and leisure activities.', 'https://dd.reso.org/DD2.0/lookups/RoomType/Living Room/', '2.0', 'reso_official_csv'),
  ('RoomType', 'Loft', 'en', 'Loft', 'A loft can be an upper story or attic in a building, directly under the roof. Alternatively, a loft apartment refers to a large adaptable open space, often converted for residential use (a converted loft) from some other use, frequently light industrial. Some converted lofts include upper open loft areas.', 'https://dd.reso.org/DD2.0/lookups/RoomType/Loft/', '2.0', 'reso_official_csv'),
  ('RoomType', 'Master Bathroom', 'en', 'Master Bathroom', 'Typically the largest of the bathrooms and attached to the primary bedroom.', 'https://dd.reso.org/DD2.0/lookups/RoomType/Master Bathroom/', '2.0', 'reso_official_csv'),
  ('RoomType', 'Master Bedroom', 'en', 'Master Bedroom', 'Typically the largest of the bedrooms with an attached bathroom.', 'https://dd.reso.org/DD2.0/lookups/RoomType/Master Bedroom/', '2.0', 'reso_official_csv'),
