  ('SpecialListingConditions', 'Real Estate Owned', 'en', 'Real Estate Owned', 'The listed property is currently owned by a bank/lender.', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/Real Estate Owned/', '2.0', 'reso_official_csv'),
  ('SpecialListingConditions', 'Short Sale', 'en', 'Short Sale', 'The listing is a short sale (short pay) and may require bank approval.', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/Short Sale/', '2.0', 'reso_official_csv'),
  ('SpecialListingConditions', 'Standard', 'en', 'Standard', 'The listing has none of the other conditions in the Special Listing Conditions field.', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/Standard/', '2.0', 'reso_official_csv'),
  ('SpecialListingConditions', 'Third Party Approval', 'en', 'Third Party Approval', 'A court or other third-party approval is required for the sale to finalize.', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/Third Party Approval/', '2.0', 'reso_official_csv'),
  ('SpecialListingConditions', 'Trust', 'en', 'Trust', 'A three-party fiduciary relationship in which the first party, the trustor or settlor, transfers a property upon the second party for the benefit of the third party, the beneficiary.', 'https://dd.reso.org/DD2.0/lookups/SpecialListingConditions/Trust/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Active', 'en', 'Active', 'The listing is on market and an offer has not been accepted.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Active/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Active Under Contract', 'en', 'Active Under Contract', 'An offer has been accepted but the listing is still on market.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Active Under Contract/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Canceled', 'en', 'Canceled', 'The listing contract has been terminated.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Canceled/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Closed', 'en', 'Closed', 'The purchase agreement has been fulfilled or the lease agreement has been executed.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Closed/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Coming Soon', 'en', 'Coming Soon', 'This is a listing that has not yet been on market but will be on market soon. A listing contract has been executed. Some systems may use Hold or Withdrawn for similar purposes. When all three are in use, Hold expresses a listing that may have been on market but is off market temporarily and is expected to return to market. Withdrawn may have been on market but, when used in conjunction with Hold, is not expected to return to market. Coming Soon is different from Hold and Withdrawn, as the property, under the current listing contract only, has not been previously on market.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Coming Soon/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Delete', 'en', 'Delete', 'The listing contract was never valid or there is another reason for the contract to be nullified.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Delete/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Expired', 'en', 'Expired', 'The listing contract has expired.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Expired/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Hold', 'en', 'Hold', 'A contract exists between the seller and the listing member. The listing may be completely off market, not allowing any showings and/or not taking any further offers. For systems that don''t use Hold, Withdrawn is a similar status that may be in use. When both Hold and Withdrawn are in use, Withdrawn may be used to indicate a greater certainty that the listing will not come back on market.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Hold/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Incomplete', 'en', 'Incomplete', 'The listing has not yet been completely entered and is not yet published in the MLS.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Incomplete/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Pending', 'en', 'Pending', 'An offer has been accepted and the listing is no longer on market.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Pending/', '2.0', 'reso_official_csv'),
  ('StandardStatus', 'Withdrawn', 'en', 'Withdrawn', 'The listing has been withdrawn from the market, but a contract still exists between the seller and the listing member. For those systems that use both Hold and Withdrawn, Withdrawn may represent an intention not to bring the listing back on the market. When Hold is not used by the system, Withdrawn does not represent any intention of returning to market or not.', 'https://dd.reso.org/DD2.0/lookups/StandardStatus/Withdrawn/', '2.0', 'reso_official_csv'),
